Your endpoint likely has a critical authorization vulnerability. Missing authorization checks allow any authenticated user to access resources belonging to other users - this is called Insecure Direct Object Reference (IDOR) combined with missing authorization.

**VULNERABLE CODE**:

```java
import javax.ws.rs.*;
import javax.ws.rs.core.MediaType;
import javax.ws.rs.core.Response;
import java.sql.*;

@Path("/api/documents")
public class DocumentController {

    private static final String DB_URL = "jdbc:postgresql://localhost/docdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @GET
    @Path("/{documentId}")
    @Produces(MediaType.APPLICATION_JSON)
    public Response getDocument(@PathParam("documentId") int documentId) {
        // VULNERABLE: No authorization check - any user can access any document
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "SELECT * FROM documents WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                Document doc = new Document();
                doc.setId(rs.getInt("id"));
                doc.setTitle(rs.getString("title"));
                doc.setContent(rs.getString("content"));
                doc.setOwnerId(rs.getInt("owner_id"));
                return Response.ok(doc).build();
            }
            return Response.status(Response.Status.NOT_FOUND).build();
        } catch (SQLException e) {
            return Response.serverError().build();
        }
    }

    @DELETE
    @Path("/{documentId}")
    public Response deleteDocument(@PathParam("documentId") int documentId) {
        // VULNERABLE: Any authenticated user can delete any document
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "DELETE FROM documents WHERE id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            stmt.executeUpdate();
            return Response.noContent().build();
        } catch (SQLException e) {
            return Response.serverError().build();
        }
    }
}
```

**Attack Payload**:
```bash
# Attacker (User ID: 999) accessing another user's document
curl -X GET "https://api.example.com/api/documents/1" \
  -H "Authorization: Bearer <attacker_token>"

# Attacker deleting another user's document
curl -X DELETE "https://api.example.com/api/documents/1" \
  -H "Authorization: Bearer <attacker_token>"

# Enumeration attack to find all documents
for i in {1..10000}; do
  curl -s "https://api.example.com/api/documents/$i" \
    -H "Authorization: Bearer <token>" >> harvested_docs.json
done
```

**Why This Is Dangerous**:
- Any authenticated user can read ANY document by guessing/incrementing document IDs
- No verification that the requesting user owns or has permission to access the resource
- DELETE endpoint allows mass deletion of other users' data
- Sequential IDs make enumeration attacks trivial
- Violates the principle of least privilege

**SECURE VERSION**:

```java
import javax.ws.rs.*;
import javax.ws.rs.core.*;
import javax.inject.Inject;
import java.sql.*;
import java.util.logging.Logger;

@Path("/api/documents")
public class SecureDocumentController {

    private static final Logger LOGGER = Logger.getLogger(SecureDocumentController.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/docdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @Inject
    private SecurityContext securityContext;

    @Inject
    private AuthorizationService authService;

    @GET
    @Path("/{documentId}")
    @Produces(MediaType.APPLICATION_JSON)
    public Response getDocument(@PathParam("documentId") int documentId) {
        // Get current authenticated user
        String currentUserId = securityContext.getUserPrincipal().getName();

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // SECURE: Query includes owner check OR permission check
            String sql = "SELECT d.* FROM documents d " +
                        "LEFT JOIN document_permissions dp ON d.id = dp.document_id " +
                        "WHERE d.id = ? AND (d.owner_id = ? OR dp.user_id = ?)";

            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            stmt.setInt(2, Integer.parseInt(currentUserId));
            stmt.setInt(3, Integer.parseInt(currentUserId));
            ResultSet rs = stmt.executeQuery();

            if (rs.next()) {
                Document doc = new Document();
                doc.setId(rs.getInt("id"));
                doc.setTitle(rs.getString("title"));
                doc.setContent(rs.getString("content"));

                LOGGER.info(String.format("User %s accessed document %d", currentUserId, documentId));
                return Response.ok(doc).build();
            }

            // Log potential unauthorized access attempt
            LOGGER.warning(String.format("User %s denied access to document %d", currentUserId, documentId));
            return Response.status(Response.Status.FORBIDDEN)
                          .entity("Access denied").build();

        } catch (SQLException e) {
            LOGGER.severe("Database error: " + e.getMessage());
            return Response.serverError().entity("Internal error").build();
        }
    }

    @DELETE
    @Path("/{documentId}")
    public Response deleteDocument(@PathParam("documentId") int documentId) {
        String currentUserId = securityContext.getUserPrincipal().getName();

        // SECURE: Only owner can delete
        if (!authService.isDocumentOwner(currentUserId, documentId)) {
            LOGGER.warning(String.format("Unauthorized delete attempt: User %s on document %d", 
                          currentUserId, documentId));
            return Response.status(Response.Status.FORBIDDEN)
                          .entity("Only document owner can delete").build();
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "DELETE FROM documents WHERE id = ? AND owner_id = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setInt(1, documentId);
            stmt.setInt(2, Integer.parseInt(currentUserId));

            int affected = stmt.executeUpdate();
            if (affected > 0) {
                LOGGER.info(String.format("User %s deleted document %d", currentUserId, documentId));
                return Response.noContent().build();
            }
            return Response.status(Response.Status.NOT_FOUND).build();
        } catch (SQLException e) {
            LOGGER.severe("Database error: " + e.getMessage());
            return Response.serverError().build();
        }
    }
}
```

**Key Security Controls**:
- **Resource-level authorization**: Every request verifies the user has permission to access the specific resource
- **Defense in depth SQL**: Query includes owner/permission check even if service-layer check is bypassed
- **Audit logging**: All access attempts (successful and denied) are logged for security monitoring
- **Fail secure**: Returns 403 Forbidden with generic message, not revealing if resource exists

Complex authorization requires a dedicated authorization service with role-based access control (RBAC), attribute-based access control (ABAC), or a combination. Here's a production-ready pattern implementing hierarchical permissions.

**PRODUCTION PATTERN**:

```java
import javax.ws.rs.*;
import javax.ws.rs.core.*;
import javax.inject.Inject;
import javax.annotation.security.RolesAllowed;
import java.sql.*;
import java.util.*;
import java.util.logging.Logger;
import java.time.Instant;

// Authorization Service - Central permission logic
public class AuthorizationService {

    private static final Logger AUDIT_LOG = Logger.getLogger("SECURITY_AUDIT");

    public enum Permission {
        READ, WRITE, DELETE, SHARE, ADMIN
    }

    public enum Role {
        ADMIN(100),           // Can do anything
        TEAM_LEAD(50),        // Can manage team resources
        MEMBER(10),           // Can access own and shared resources
        VIEWER(1);            // Read-only access

        private final int level;
        Role(int level) { this.level = level; }
        public int getLevel() { return level; }
    }

    @Inject
    private PermissionRepository permissionRepo;

    @Inject
    private TeamRepository teamRepo;

    public AuthorizationResult authorize(AuthorizationRequest request) {
        String userId = request.getUserId();
        String resourceId = request.getResourceId();
        String resourceType = request.getResourceType();
        Permission requiredPermission = request.getRequiredPermission();

        // Layer 1: Check if user is system admin
        if (isSystemAdmin(userId)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_ADMIN");
            return AuthorizationResult.granted("System admin access");
        }

        // Layer 2: Check direct ownership
        if (isResourceOwner(userId, resourceId, resourceType)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_OWNER");
            return AuthorizationResult.granted("Resource owner");
        }

        // Layer 3: Check explicit user permissions
        Optional<Permission> directPermission = getDirectPermission(userId, resourceId, resourceType);
        if (directPermission.isPresent() && hasRequiredAccess(directPermission.get(), requiredPermission)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_DIRECT");
            return AuthorizationResult.granted("Direct permission");
        }

        // Layer 4: Check team-based permissions
        List<String> userTeams = teamRepo.getTeamsForUser(userId);
        for (String teamId : userTeams) {
            Optional<Permission> teamPermission = getTeamPermission(teamId, resourceId, resourceType);
            if (teamPermission.isPresent() && hasRequiredAccess(teamPermission.get(), requiredPermission)) {
                logAccess(userId, resourceId, requiredPermission, "GRANTED_TEAM:" + teamId);
                return AuthorizationResult.granted("Team permission via " + teamId);
            }
        }

        // Layer 5: Check hierarchical access (team lead can access team member resources)
        if (isTeamLeadWithAccessToMember(userId, resourceId, resourceType)) {
            logAccess(userId, resourceId, requiredPermission, "GRANTED_HIERARCHY");
            return AuthorizationResult.granted("Team lead hierarchical access");
        }

        // Default deny
        logAccess(userId, resourceId, requiredPermission, "DENIED");
        return AuthorizationResult.denied("Insufficient permissions");
    }

    private boolean hasRequiredAccess(Permission granted, Permission required) {
        Map<Permission, Integer> levels = Map.of(
            Permission.READ, 1,
            Permission.WRITE, 2,
            Permission.DELETE, 3,
            Permission.SHARE, 4,
            Permission.ADMIN, 5
        );
        return levels.get(granted) >= levels.get(required);
    }

    private void logAccess(String userId, String resourceId, Permission permission, String result) {
        AUDIT_LOG.info(String.format(
            "AUTH|%s|user=%s|resource=%s|permission=%s|result=%s|ip=%s",
            Instant.now().toString(), userId, resourceId, permission, result,
            RequestContext.getCurrentRemoteAddr()
        ));
    }

    private boolean isSystemAdmin(String userId) {
        return permissionRepo.getUserRole(userId)
                            .map(role -> role == Role.ADMIN)
                            .orElse(false);
    }

    private boolean isResourceOwner(String userId, String resourceId, String resourceType) {
        return permissionRepo.getResourceOwner(resourceId, resourceType)
                            .map(ownerId -> ownerId.equals(userId))
                            .orElse(false);
    }

    private Optional<Permission> getDirectPermission(String userId, String resourceId, String resourceType) {
        return permissionRepo.getDirectPermission(userId, resourceId, resourceType);
    }

    private Optional<Permission> getTeamPermission(String teamId, String resourceId, String resourceType) {
        return permissionRepo.getTeamPermission(teamId, resourceId, resourceType);
    }

    private boolean isTeamLeadWithAccessToMember(String userId, String resourceId, String resourceType) {
        Optional<String> resourceOwner = permissionRepo.getResourceOwner(resourceId, resourceType);
        if (resourceOwner.isEmpty()) return false;

        List<String> userTeams = teamRepo.getTeamsWhereUserIsLead(userId);
        for (String teamId : userTeams) {
            if (teamRepo.isUserInTeam(resourceOwner.get(), teamId)) {
                return true;
            }
        }
        return false;
    }
}

// Authorization Result - Immutable result object
public class AuthorizationResult {
    private final boolean authorized;
    private final String reason;
    private final Instant timestamp;

    private AuthorizationResult(boolean authorized, String reason) {
        this.authorized = authorized;
        this.reason = reason;
        this.timestamp = Instant.now();
    }

    public static AuthorizationResult granted(String reason) {
        return new AuthorizationResult(true, reason);
    }

    public static AuthorizationResult denied(String reason) {
        return new AuthorizationResult(false, reason);
    }

    public boolean isAuthorized() { return authorized; }
    public String getReason() { return reason; }
}

// Secure Controller with comprehensive authorization
@Path("/api/documents")
@Produces(MediaType.APPLICATION_JSON)
public class ProductionDocumentController {

    private static final Logger LOGGER = Logger.getLogger(ProductionDocumentController.class.getName());

    @Inject
    private AuthorizationService authService;

    @Inject
    private DocumentRepository documentRepo;

    @Inject
    private SecurityContext securityContext;

    @Inject
    private RateLimiter rateLimiter;

    @GET
    @Path("/{documentId}")
    public Response getDocument(@PathParam("documentId") String documentId,
                                @Context HttpHeaders headers) {

        String userId = getCurrentUserId();

        // Rate limiting check
        if (!rateLimiter.tryAcquire(userId, "document_read")) {
            LOGGER.warning(String.format("Rate limit exceeded: user=%s", userId));
            return Response.status(429)
                          .header("Retry-After", "60")
                          .entity("Rate limit exceeded").build();
        }

        // Input validation
        if (!isValidUUID(documentId)) {
            return Response.status(Response.Status.BAD_REQUEST)
                          .entity("Invalid document ID format").build();
        }

        // Authorization check
        AuthorizationRequest authRequest = AuthorizationRequest.builder()
            .userId(userId)
            .resourceId(documentId)
            .resourceType("document")
            .requiredPermission(AuthorizationService.Permission.READ)
            .build();

        AuthorizationResult authResult = authService.authorize(authRequest);

        if (!authResult.isAuthorized()) {
            // Return 404 instead of 403 to prevent resource enumeration
            return Response.status(Response.Status.NOT_FOUND)
                          .entity("Document not found").build();
        }

        // Fetch and return document
        try {
            Optional<Document> doc = documentRepo.findById(documentId);
            if (doc.isPresent()) {
                return Response.ok(doc.get())
                              .header("X-Content-Type-Options", "nosniff")
                              .header("Cache-Control", "private, no-store")
                              .build();
            }
            return Response.status(Response.Status.NOT_FOUND).build();
        } catch (Exception e) {
            LOGGER.severe("Error fetching document: " + e.getMessage());
            return Response.serverError().entity("Internal error").build();
        }
    }

    @DELETE
    @Path("/{documentId}")
    @RolesAllowed({"ADMIN", "TEAM_LEAD", "MEMBER"})
    public Response deleteDocument(@PathParam("documentId") String documentId) {

        String userId = getCurrentUserId();

        if (!isValidUUID(documentId)) {
            return Response.status(Response.Status.BAD_REQUEST).build();
        }

        AuthorizationRequest authRequest = AuthorizationRequest.builder()
            .userId(userId)
            .resourceId(documentId)
            .resourceType("document")
            .requiredPermission(AuthorizationService.Permission.DELETE)
            .build();

        AuthorizationResult authResult = authService.authorize(authRequest);

        if (!authResult.isAuthorized()) {
            return Response.status(Response.Status.FORBIDDEN)
                          .entity("Delete permission required").build();
        }

        try {
            // Soft delete with audit trail
            documentRepo.softDelete(documentId, userId);
            LOGGER.info(String.format("Document deleted: id=%s, by=%s, reason=%s", 
                       documentId, userId, authResult.getReason()));
            return Response.noContent().build();
        } catch (Exception e) {
            LOGGER.severe("Error deleting document: " + e.getMessage());
            return Response.serverError().build();
        }
    }

    private String getCurrentUserId() {
        return securityContext.getUserPrincipal().getName();
    }

    private boolean isValidUUID(String id) {
        try {
            java.util.UUID.fromString(id);
            return true;
        } catch (IllegalArgumentException e) {
            return false;
        }
    }
}
```

**Defense in Depth Layers**:

1. **Authentication Gate** (handled by container/framework):
```java
@RolesAllowed({"ADMIN", "TEAM_LEAD", "MEMBER"})
public Response deleteDocument(...) {
    // Method only accessible to authenticated users with specific roles
}
```

2. **Resource-Level Authorization** (custom authorization service):
```java
AuthorizationResult authResult = authService.authorize(authRequest);
if (!authResult.isAuthorized()) {
    return Response.status(Response.Status.FORBIDDEN).build();
}
```

3. **Database-Level Enforcement** (defense if app logic bypassed):
```java
// Repository implementation includes user context
public Optional<Document> findByIdForUser(String docId, String userId) {
    String sql = "SELECT d.* FROM documents d " +
                "WHERE d.id = ? AND d.deleted_at IS NULL " +
                "AND EXISTS (SELECT 1 FROM permissions p " +
                "           WHERE p.resource_id = d.id AND p.user_id = ?)";
    // Even if authorization service is bypassed, DB enforces access
}
```

**Additional Protections**:

- **Rate limiting**: Prevents enumeration attacks and DoS
- **UUID resource IDs**: Non-sequential IDs prevent guessing
- **404 vs 403 strategy**: Return 404 for unauthorized reads to prevent resource discovery
- **Soft delete with audit**: Maintain audit trail, enable recovery
- **Security headers**: Prevent caching of sensitive data
- **Centralized authorization**: Single point of truth for permission logic
- **Comprehensive audit logging**: All access decisions logged with context for SIEM integration
- **Fail-closed design**: Default deny if any authorization component fails

**No, DES and Triple-DES (3DES) are NOT safe for encrypting payment data or any sensitive information.** DES was broken decades ago, and 3DES has been deprecated by NIST since 2017 due to the Sweet32 birthday attack (CVE-2016-2183). Using these algorithms puts you at risk of PCI-DSS non-compliance and potential data breaches.

**VULNERABLE CODE**:

```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.SecretKeySpec;
import java.util.Base64;

public class InsecurePaymentEncryption {

    // DANGEROUS: Using deprecated DES algorithm
    private static final String ALGORITHM = "DES";

    public String encryptPaymentData(String creditCardNumber, byte[] keyBytes) throws Exception {
        // VULNERABLE: DES has only 56-bit key strength
        SecretKeySpec key = new SecretKeySpec(keyBytes, ALGORITHM);

        // VULNERABLE: ECB mode leaks patterns in ciphertext
        Cipher cipher = Cipher.getInstance("DES/ECB/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, key);

        byte[] encrypted = cipher.doFinal(creditCardNumber.getBytes("UTF-8"));
        return Base64.getEncoder().encodeToString(encrypted);
    }

    // Also vulnerable: Triple-DES with 64-bit block size
    public String encrypt3DES(String data, byte[] keyBytes) throws Exception {
        SecretKeySpec key = new SecretKeySpec(keyBytes, "DESede");
        // VULNERABLE: 64-bit blocks enable Sweet32 birthday attacks
        Cipher cipher = Cipher.getInstance("DESede/CBC/PKCS5Padding");
        cipher.init(Cipher.ENCRYPT_MODE, key);

        byte[] encrypted = cipher.doFinal(data.getBytes("UTF-8"));
        return Base64.getEncoder().encodeToString(encrypted);
    }
}
```

**Attack Scenario**:
```text
Sweet32 Attack on 3DES:
1. Attacker captures encrypted HTTPS traffic using 3DES
2. After ~32GB of data (2^32 blocks), birthday collision occurs
3. XOR of two colliding ciphertext blocks reveals XOR of plaintexts
4. Combined with known plaintext (HTTP headers), secrets are recovered

DES Brute Force:
1. 56-bit key space = 2^56 possible keys
2. Modern GPUs test 10^12 keys/second
3. Full key search in ~20 hours with specialized hardware
4. Cloud-based cracking services available for <$100
```

**Why This Is Dangerous**:
- **DES 56-bit keys**: Brute-forceable in hours with modern hardware ($100 in cloud compute)
- **64-bit block size**: Birthday attacks recover plaintext after ~32GB encrypted under same key
- **ECB mode**: Identical plaintext blocks produce identical ciphertext, leaking data patterns
- **No authentication**: Ciphertext can be modified without detection
- **PCI-DSS Violation**: DES/3DES explicitly prohibited for new implementations

**SECURE VERSION**:

```java
import javax.crypto.Cipher;
import javax.crypto.KeyGenerator;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.util.Arrays;
import java.util.Base64;

public class SecurePaymentEncryption {

    // SECURE: AES-256 with authenticated encryption
    private static final String ALGORITHM = "AES";
    private static final String TRANSFORMATION = "AES/GCM/NoPadding";
    private static final int GCM_IV_LENGTH = 12;  // 96 bits recommended for GCM
    private static final int GCM_TAG_LENGTH = 128; // Authentication tag bits
    private static final int AES_KEY_SIZE = 256;   // 256-bit key strength

    private final SecureRandom secureRandom = new SecureRandom();

    public SecretKey generateKey() throws Exception {
        KeyGenerator keyGen = KeyGenerator.getInstance(ALGORITHM);
        keyGen.init(AES_KEY_SIZE, secureRandom);
        return keyGen.generateKey();
    }

    public String encryptPaymentData(String creditCardNumber, SecretKey key) throws Exception {
        // Generate unique IV for each encryption
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);

        // SECURE: AES-GCM provides confidentiality AND authenticity
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, key, gcmSpec);

        byte[] encrypted = cipher.doFinal(creditCardNumber.getBytes("UTF-8"));

        // Prepend IV to ciphertext for decryption
        byte[] combined = new byte[iv.length + encrypted.length];
        System.arraycopy(iv, 0, combined, 0, iv.length);
        System.arraycopy(encrypted, 0, combined, iv.length, encrypted.length);

        return Base64.getEncoder().encodeToString(combined);
    }

    public String decryptPaymentData(String encryptedData, SecretKey key) throws Exception {
        byte[] combined = Base64.getDecoder().decode(encryptedData);

        // Extract IV and ciphertext
        byte[] iv = Arrays.copyOfRange(combined, 0, GCM_IV_LENGTH);
        byte[] ciphertext = Arrays.copyOfRange(combined, GCM_IV_LENGTH, combined.length);

        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.DECRYPT_MODE, key, gcmSpec);

        // GCM automatically verifies authenticity
        byte[] decrypted = cipher.doFinal(ciphertext);
        return new String(decrypted, "UTF-8");
    }
}
```

**Key Security Controls**:
- **AES-256**: 256-bit keys are computationally infeasible to brute force (2^256 operations)
- **GCM Mode**: Provides authenticated encryption - detects any tampering with ciphertext
- **128-bit blocks**: Immune to Sweet32 birthday attacks (would require 2^64 blocks)
- **Unique IVs**: Fresh random IV per encryption prevents pattern analysis
- **Integrated authentication**: GCM tag ensures data integrity without separate HMAC

Excellent questions! Key management and streaming encryption are critical for production systems. Poor key handling undermines even the strongest encryption, and memory-efficient streaming is essential for large datasets.

**PRODUCTION PATTERN**:

```java
import javax.crypto.*;
import javax.crypto.spec.*;
import java.io.*;
import java.nio.ByteBuffer;
import java.nio.channels.FileChannel;
import java.security.*;
import java.util.Arrays;
import java.util.Base64;
import java.util.logging.Logger;

public class ProductionCryptoService {

    private static final Logger AUDIT_LOG = Logger.getLogger("security.audit.crypto");
    private static final String TRANSFORMATION = "AES/GCM/NoPadding";
    private static final int GCM_IV_LENGTH = 12;
    private static final int GCM_TAG_LENGTH = 128;
    private static final int BUFFER_SIZE = 8192; // 8KB chunks for streaming

    private final SecureRandom secureRandom;
    private final KeyManagementService keyManager;

    public ProductionCryptoService(KeyManagementService keyManager) {
        this.keyManager = keyManager;
        this.secureRandom = new SecureRandom();
    }

    /**
     * Encrypt sensitive data with envelope encryption pattern.
     * Data Encryption Key (DEK) is encrypted by Key Encryption Key (KEK).
     */
    public EncryptedPayload encryptWithEnvelope(byte[] plaintext, String keyId) 
            throws GeneralSecurityException {

        // Generate ephemeral DEK for this data
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        keyGen.init(256, secureRandom);
        SecretKey dataKey = keyGen.generateKey();

        // Encrypt the data with DEK
        byte[] iv = generateIV();
        byte[] ciphertext = encryptAESGCM(plaintext, dataKey, iv);

        // Wrap DEK with KEK from key management system
        SecretKey masterKey = keyManager.getKey(keyId);
        byte[] wrappedKey = wrapKey(dataKey, masterKey);

        // Clear DEK from memory immediately
        clearKey(dataKey);

        AUDIT_LOG.info(String.format(
            "Encrypted %d bytes with key_id=%s, iv_prefix=%s",
            plaintext.length, keyId, Base64.getEncoder().encodeToString(Arrays.copyOf(iv, 4))
        ));

        return new EncryptedPayload(wrappedKey, iv, ciphertext, keyId);
    }

    /**
     * Stream encryption for large files - memory efficient.
     * Uses AES-GCM with chunked processing.
     */
    public void encryptFileStream(File inputFile, File outputFile, String keyId) 
            throws IOException, GeneralSecurityException {

        long startTime = System.currentTimeMillis();

        // Generate DEK and IV
        KeyGenerator keyGen = KeyGenerator.getInstance("AES");
        keyGen.init(256, secureRandom);
        SecretKey dataKey = keyGen.generateKey();
        byte[] iv = generateIV();

        // Wrap DEK with master key
        SecretKey masterKey = keyManager.getKey(keyId);
        byte[] wrappedKey = wrapKey(dataKey, masterKey);

        try (FileInputStream fis = new FileInputStream(inputFile);
             FileOutputStream fos = new FileOutputStream(outputFile)) {

            // Write header: key_id_length(4) + key_id + wrapped_key_length(4) + wrapped_key + iv
            writeHeader(fos, keyId, wrappedKey, iv);

            // Initialize cipher for streaming
            Cipher cipher = Cipher.getInstance(TRANSFORMATION);
            GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
            cipher.init(Cipher.ENCRYPT_MODE, dataKey, gcmSpec);

            // Process file in chunks
            byte[] buffer = new byte[BUFFER_SIZE];
            int bytesRead;
            long totalBytesProcessed = 0;

            while ((bytesRead = fis.read(buffer)) != -1) {
                byte[] output = cipher.update(buffer, 0, bytesRead);
                if (output != null) {
                    fos.write(output);
                }
                totalBytesProcessed += bytesRead;
            }

            // Write final block with GCM tag
            byte[] finalBlock = cipher.doFinal();
            fos.write(finalBlock);

            // Audit log success
            long duration = System.currentTimeMillis() - startTime;
            AUDIT_LOG.info(String.format(
                "File encrypted: input=%s, output=%s, bytes=%d, duration_ms=%d, key_id=%s",
                inputFile.getName(), outputFile.getName(), totalBytesProcessed, duration, keyId
            ));

        } finally {
            clearKey(dataKey);
        }
    }

    /**
     * Decrypt streaming file with authentication verification.
     */
    public void decryptFileStream(File inputFile, File outputFile) 
            throws IOException, GeneralSecurityException {

        try (FileInputStream fis = new FileInputStream(inputFile);
             FileOutputStream fos = new FileOutputStream(outputFile)) {

            // Read header
            EncryptedFileHeader header = readHeader(fis);

            // Unwrap DEK using master key
            SecretKey masterKey = keyManager.getKey(header.keyId);
            SecretKey dataKey = unwrapKey(header.wrappedKey, masterKey);

            try {
                // Initialize cipher
                Cipher cipher = Cipher.getInstance(TRANSFORMATION);
                GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, header.iv);
                cipher.init(Cipher.DECRYPT_MODE, dataKey, gcmSpec);

                // Decrypt in chunks
                byte[] buffer = new byte[BUFFER_SIZE];
                int bytesRead;

                while ((bytesRead = fis.read(buffer)) != -1) {
                    byte[] output = cipher.update(buffer, 0, bytesRead);
                    if (output != null) {
                        fos.write(output);
                    }
                }

                // Verify GCM tag and write final block
                // Throws AEADBadTagException if tampered
                byte[] finalBlock = cipher.doFinal();
                fos.write(finalBlock);

                AUDIT_LOG.info(String.format(
                    "File decrypted successfully: file=%s, key_id=%s",
                    inputFile.getName(), header.keyId
                ));

            } catch (AEADBadTagException e) {
                AUDIT_LOG.severe(String.format(
                    "SECURITY ALERT: Authentication failed for file=%s - possible tampering!",
                    inputFile.getName()
                ));
                // Delete partial output to prevent use of corrupted data
                outputFile.delete();
                throw new SecurityException("Data integrity verification failed", e);
            } finally {
                clearKey(dataKey);
            }
        }
    }

    private byte[] generateIV() {
        byte[] iv = new byte[GCM_IV_LENGTH];
        secureRandom.nextBytes(iv);
        return iv;
    }

    private byte[] encryptAESGCM(byte[] plaintext, SecretKey key, byte[] iv) 
            throws GeneralSecurityException {
        Cipher cipher = Cipher.getInstance(TRANSFORMATION);
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.ENCRYPT_MODE, key, gcmSpec);
        return cipher.doFinal(plaintext);
    }

    private byte[] wrapKey(SecretKey keyToWrap, SecretKey wrappingKey) 
            throws GeneralSecurityException {
        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        byte[] iv = generateIV();
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.WRAP_MODE, wrappingKey, gcmSpec);
        byte[] wrapped = cipher.wrap(keyToWrap);

        // Combine IV + wrapped key
        byte[] result = new byte[iv.length + wrapped.length];
        System.arraycopy(iv, 0, result, 0, iv.length);
        System.arraycopy(wrapped, 0, result, iv.length, wrapped.length);
        return result;
    }

    private SecretKey unwrapKey(byte[] wrappedKeyData, SecretKey wrappingKey) 
            throws GeneralSecurityException {
        byte[] iv = Arrays.copyOfRange(wrappedKeyData, 0, GCM_IV_LENGTH);
        byte[] wrapped = Arrays.copyOfRange(wrappedKeyData, GCM_IV_LENGTH, wrappedKeyData.length);

        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        GCMParameterSpec gcmSpec = new GCMParameterSpec(GCM_TAG_LENGTH, iv);
        cipher.init(Cipher.UNWRAP_MODE, wrappingKey, gcmSpec);
        return (SecretKey) cipher.unwrap(wrapped, "AES", Cipher.SECRET_KEY);
    }

    private void clearKey(SecretKey key) {
        try {
            // Attempt to clear key material from memory
            if (key instanceof Destroyable) {
                ((Destroyable) key).destroy();
            }
        } catch (DestroyFailedException e) {
            // Log but continue - not all key implementations support destroy
            AUDIT_LOG.warning("Could not destroy key material: " + e.getMessage());
        }
    }

    private void writeHeader(OutputStream os, String keyId, byte[] wrappedKey, byte[] iv) 
            throws IOException {
        DataOutputStream dos = new DataOutputStream(os);
        byte[] keyIdBytes = keyId.getBytes("UTF-8");
        dos.writeInt(keyIdBytes.length);
        dos.write(keyIdBytes);
        dos.writeInt(wrappedKey.length);
        dos.write(wrappedKey);
        dos.write(iv);
    }

    private EncryptedFileHeader readHeader(InputStream is) throws IOException {
        DataInputStream dis = new DataInputStream(is);
        int keyIdLength = dis.readInt();
        byte[] keyIdBytes = new byte[keyIdLength];
        dis.readFully(keyIdBytes);
        String keyId = new String(keyIdBytes, "UTF-8");

        int wrappedKeyLength = dis.readInt();
        byte[] wrappedKey = new byte[wrappedKeyLength];
        dis.readFully(wrappedKey);

        byte[] iv = new byte[GCM_IV_LENGTH];
        dis.readFully(iv);

        return new EncryptedFileHeader(keyId, wrappedKey, iv);
    }

    // Data classes
    public static class EncryptedPayload {
        public final byte[] wrappedKey;
        public final byte[] iv;
        public final byte[] ciphertext;
        public final String keyId;

        public EncryptedPayload(byte[] wrappedKey, byte[] iv, byte[] ciphertext, String keyId) {
            this.wrappedKey = wrappedKey;
            this.iv = iv;
            this.ciphertext = ciphertext;
            this.keyId = keyId;
        }
    }

    private static class EncryptedFileHeader {
        final String keyId;
        final byte[] wrappedKey;
        final byte[] iv;

        EncryptedFileHeader(String keyId, byte[] wrappedKey, byte[] iv) {
            this.keyId = keyId;
            this.wrappedKey = wrappedKey;
            this.iv = iv;
        }
    }
}

/**
 * Key Management Service interface - implement with HSM, AWS KMS, or HashiCorp Vault
 */
interface KeyManagementService {
    SecretKey getKey(String keyId) throws GeneralSecurityException;
    String createKey(String alias) throws GeneralSecurityException;
    void rotateKey(String keyId) throws GeneralSecurityException;
}
```

**Defense in Depth Layers**:

1. **Envelope Encryption**: Data Encryption Keys (DEK) are unique per operation, wrapped by Key Encryption Keys (KEK) stored in HSM/KMS
```java
// Each encryption generates fresh DEK
SecretKey dataKey = keyGen.generateKey();
// DEK is wrapped (encrypted) by master key from KMS
byte[] wrappedKey = wrapKey(dataKey, masterKey);
// Only wrapped DEK is stored with ciphertext
```

2. **Key Hygiene**: Immediate clearing of sensitive key material after use
```java
finally {
    clearKey(dataKey);  // Destroy DEK from memory
}
```

3. **Authentication Verification**: GCM mode detects tampering before any decrypted data is used
```java
catch (AEADBadTagException e) {
    outputFile.delete();  // Don't use potentially corrupted data
    throw new SecurityException("Data integrity verification failed", e);
}
```

**Additional Protections**:

- **AWS KMS Integration Example**:
```java
import com.amazonaws.services.kms.AWSKMS;
import com.amazonaws.services.kms.model.*;

public class AWSKeyManagementService implements KeyManagementService {
    private final AWSKMS kmsClient;

    @Override
    public SecretKey getKey(String keyId) throws GeneralSecurityException {
        GenerateDataKeyRequest request = new GenerateDataKeyRequest()
            .withKeyId(keyId)
            .withKeySpec(DataKeySpec.AES_256);
        GenerateDataKeyResult result = kmsClient.generateDataKey(request);
        byte[] plainKey = result.getPlaintext().array();
        return new SecretKeySpec(plainKey, "AES");
    }
}
```

- **Key Rotation Support**: Store key version with ciphertext to support seamless rotation
- **Audit Logging**: All crypto operations logged with key IDs (never key material)
- **Memory Protection**: Use byte[] for sensitive data (can be cleared), avoid String (immutable)
- **Algorithm Agility**: Transformation stored in header allows future algorithm upgrades

**Monitoring Alerts to Configure**:
```text
- Decryption failures (AEADBadTagException) > 0: Potential tampering
- Same IV reused: Critical cryptographic failure
- Key access from unusual IP/location: Potential compromise
- Bulk decryption operations: Data exfiltration attempt
```

Hardcoding authentication keys or secrets in your Rust code is dangerous: they end up in your Git history, builds, logs, and often can't be rotated easily.

**VULNERABLE CODE**:

```rust
use std::net::TcpListener;
use std::io::{Read, Write};

// DANGEROUS: Hardcoded global API secret
// This will live in the binary and source control forever.
const API_SECRET: &str = "sk_live_1234567890_SUPER_SECRET";

fn authenticate_client(provided_key: &str) -> bool {
    // Simple string comparison using hardcoded secret
    provided_key == API_SECRET
}

fn handle_client(mut stream: std::net::TcpStream) {
    let mut buffer = [0u8; 512];
    if let Ok(bytes_read) = stream.read(&mut buffer) {
        let request = String::from_utf8_lossy(&buffer[..bytes_read]);
        let parts: Vec<&str> = request.trim().split("|").collect();

        if parts.len() != 2 {
            let _ = stream.write_all(b"ERR:BAD_REQUEST\n");
            return;
        }

        let api_key = parts[0];
        if authenticate_client(api_key) {
            let _ = stream.write_all(b"OK:AUTHENTICATED\n");
        } else {
            // DANGEROUS: leaks expected format
            let _ = stream.write_all(b"ERR:INVALID_API_KEY sk_live_********\n");
        }
    }
}

fn main() {
    let listener = TcpListener::bind("127.0.0.1:4000").expect("bind failed");

    for stream in listener.incoming() {
        if let Ok(stream) = stream {
            std::thread::spawn(|| handle_client(stream));
        }
    }
}
```

**Attack Payload** (example brute-force attempt over raw TCP):
```text
sk_live_0000000000_GUESS1|ping
sk_live_0000000000_GUESS2|ping
sk_live_0000000000_GUESS3|ping
```

This kind of brute force can be automated; once the binary is obtained, reverse engineering the hardcoded `API_SECRET` is trivial.

**Why This Is Dangerous**:
- Secrets are hardcoded and end up in source control, build artifacts, and backups, making them easy to leak or reverse engineer.
- No environment separation: the same key might be reused across dev, staging, and production.
- No rotation or revocation strategy: changing the key requires code changes and redeploys, increasing downtime and risk.

**SECURE VERSION**:

```rust
use std::env;
use std::io::{Read, Write};
use std::net::{TcpListener, TcpStream};
use subtle::ConstantTimeEq; // for constant-time comparison
use log::{error, info, warn};

fn load_api_secret() -> Result<String, String> {
    // PRIMARY DEFENSE: load secret from environment / secret manager
    match env::var("API_SECRET") {
        Ok(val) if !val.is_empty() => Ok(val),
        Ok(_) => Err("API_SECRET is empty".to_string()),
        Err(e) => Err(format!("API_SECRET missing: {}", e)),
    }
}

fn constant_time_equal(a: &str, b: &str) -> bool {
    // DEFENSE: avoid timing attacks on secret comparisons
    a.as_bytes().ct_eq(b.as_bytes()).into()
}

fn authenticate_client(provided_key: &str, expected_key: &str) -> bool {
    constant_time_equal(provided_key, expected_key)
}

fn handle_client(mut stream: TcpStream, api_secret: String) {
    let peer = stream
        .peer_addr()
        .map(|a| a.to_string())
        .unwrap_or_else(|_| "unknown".to_string());

    let mut buffer = [0u8; 512];
    if let Ok(bytes_read) = stream.read(&mut buffer) {
        let request = String::from_utf8_lossy(&buffer[..bytes_read]);
        let parts: Vec<&str> = request.trim().split("|").collect();

        if parts.len() != 2 {
            let _ = stream.write_all(b"ERR:BAD_REQUEST\n");
            warn!("Bad request from {}", peer);
            return;
        }

        let api_key = parts[0];

        // DEFENSE IN DEPTH: basic format validation (length + prefix)
        if api_key.len() < 10 || !api_key.starts_with("sk_") {
            let _ = stream.write_all(b"ERR:UNAUTHORIZED\n");
            warn!("Suspicious key format from {}", peer);
            return;
        }

        if authenticate_client(api_key, &api_secret) {
            let _ = stream.write_all(b"OK:AUTHENTICATED\n");
            info!("Successful auth from {}", peer);
        } else {
            // FAIL SECURELY: generic error, no hints about secret
            let _ = stream.write_all(b"ERR:UNAUTHORIZED\n");
            warn!("Failed auth from {}", peer);
        }
    } else {
        error!("Failed to read from client {}", peer);
    }
}

fn main() {
    env_logger::init();

    let api_secret = match load_api_secret() {
        Ok(secret) => secret,
        Err(e) => {
            eprintln!("Configuration error: {}", e);
            std::process::exit(1); // Fail fast if secret missing
        }
    };

    // Listener address can also be environment-specific
    let bind_addr = env::var("BIND_ADDR").unwrap_or_else(|_| "127.0.0.1:4000".to_string());

    let listener = TcpListener::bind(&bind_addr).expect("bind failed");
    info!("Server listening on {}", bind_addr);

    for stream in listener.incoming() {
        match stream {
            Ok(stream) => {
                let api_secret_clone = api_secret.clone();
                std::thread::spawn(|| handle_client(stream, api_secret_clone));
            }
            Err(e) => error!("Incoming connection failed: {}", e),
        }
    }
}
```

**Key Security Controls**:
- Secrets loaded from environment (`API_SECRET`) instead of hardcoding, making rotation and environment separation straightforward.
- Constant-time comparison (`subtle::ConstantTimeEq`) to reduce the risk of timing attacks on secret verification.
- Secure failure and logging: exits if the secret is misconfigured, avoids leaking secret patterns, and logs authentication attempts for monitoring and incident response.

In production, you should never rely solely on environment variables or hardcoded values. Use a secrets manager, isolate per-environment keys, rotate them periodically, and add strong auditing and rate limiting around authentication.

**PRODUCTION PATTERN**:

