APP_ENV=production
```

```bash
# Run security audit before deployment
composer audit

# Install without dev dependencies in production
composer install --no-dev --optimize-autoloader --no-interaction
```

**Key Security Controls**:
- **Pinned versions**: Use semantic versioning constraints (`^10.48.0`) to control updates
- **Security advisories package**: `roave/security-advisories` blocks installation of known vulnerable packages
- **No dev dependencies in production**: Use `--no-dev` flag during production deployment
- **Composer audit**: Built-in vulnerability scanning against PHP Security Advisories database

Automated vulnerability scanning and zero-day response are essential for production security. Here's a comprehensive approach used by enterprise PHP applications.

**PRODUCTION PATTERN**:

```php
<?php
// app/Services/DependencySecurityService.php
namespace App\Services;

use Illuminate\Support\Facades\Log;
use Illuminate\Support\Facades\Cache;
use Illuminate\Support\Facades\Http;
use App\Events\SecurityVulnerabilityDetected;

class DependencySecurityService
{
    private const CACHE_KEY = 'composer_audit_results';
    private const CACHE_TTL = 3600; // 1 hour
    private const PACKAGIST_API = 'https://packagist.org/api/security-advisories';

    private array $criticalPackages = [
        'laravel/framework',
        'guzzlehttp/guzzle',
        'symfony/http-kernel',
    ];

    public function runSecurityAudit(): array
    {
        $lockFile = base_path('composer.lock');

        if (!file_exists($lockFile)) {
            Log::error('DependencySecurity: composer.lock not found');
            return ['error' => 'Lock file missing'];
        }

        $lockContent = json_decode(file_get_contents($lockFile), true);
        $packages = $this->extractPackages($lockContent);

        $vulnerabilities = $this->checkVulnerabilities($packages);

        if (!empty($vulnerabilities['critical'])) {
            $this->handleCriticalVulnerability($vulnerabilities['critical']);
        }

        Cache::put(self::CACHE_KEY, $vulnerabilities, self::CACHE_TTL);

        return $vulnerabilities;
    }

    private function extractPackages(array $lockContent): array
    {
        $packages = [];

        foreach ($lockContent['packages'] ?? [] as $package) {
            $packages[$package['name']] = [
                'version' => $package['version'],
                'time' => $package['time'] ?? null,
                'source' => $package['source']['url'] ?? null,
            ];
        }

        return $packages;
    }

    private function checkVulnerabilities(array $packages): array
    {
        $response = Http::timeout(30)
            ->retry(3, 1000)
            ->post(self::PACKAGIST_API, [
                'packages' => array_keys($packages),
            ]);

        if (!$response->successful()) {
            Log::warning('DependencySecurity: API request failed', [
                'status' => $response->status(),
            ]);
            return ['error' => 'API unavailable'];
        }

        $advisories = $response->json('advisories', []);
        $results = ['critical' => [], 'high' => [], 'medium' => [], 'low' => []];

        foreach ($advisories as $packageName => $packageAdvisories) {
            $currentVersion = $packages[$packageName]['version'] ?? null;

            foreach ($packageAdvisories as $advisory) {
                if ($this->isAffected($currentVersion, $advisory['affectedVersions'])) {
                    $severity = $this->normalizeSeverity($advisory['severity'] ?? 'unknown');

                    $results[$severity][] = [
                        'package' => $packageName,
                        'installed_version' => $currentVersion,
                        'cve' => $advisory['cve'] ?? 'N/A',
                        'title' => $advisory['title'],
                        'link' => $advisory['link'] ?? null,
                        'fixed_versions' => $advisory['fixedVersions'] ?? [],
                    ];

                    Log::warning('DependencySecurity: Vulnerability detected', [
                        'package' => $packageName,
                        'severity' => $severity,
                        'cve' => $advisory['cve'] ?? 'N/A',
                    ]);
                }
            }
        }

        return $results;
    }

    private function handleCriticalVulnerability(array $vulnerabilities): void
    {
        event(new SecurityVulnerabilityDetected($vulnerabilities));

        Log::critical('DependencySecurity: CRITICAL vulnerability detected', [
            'count' => count($vulnerabilities),
            'packages' => array_column($vulnerabilities, 'package'),
        ]);

        // Check if critical package requires immediate action
        foreach ($vulnerabilities as $vuln) {
            if (in_array($vuln['package'], $this->criticalPackages)) {
                $this->triggerEmergencyProtocol($vuln);
            }
        }
    }

    private function triggerEmergencyProtocol(array $vulnerability): void
    {
        // Notify security team immediately
        Log::emergency('DependencySecurity: EMERGENCY - Core package vulnerability', [
            'package' => $vulnerability['package'],
            'cve' => $vulnerability['cve'],
        ]);

        // Enable additional security measures
        if (config('security.auto_waf_rules')) {
            $this->deployEmergencyWAFRules($vulnerability);
        }
    }

    private function deployEmergencyWAFRules(array $vulnerability): void
    {
        // Example: Block known exploit patterns
        Log::info('DependencySecurity: Deploying emergency WAF rules', [
            'cve' => $vulnerability['cve'],
        ]);
    }

    private function isAffected(string $installedVersion, string $affectedRange): bool
    {
        // Parse semver constraint and check if installed version matches
        return \Composer\Semver\Semver::satisfies(
            ltrim($installedVersion, 'v'),
            $affectedRange
        );
    }

    private function normalizeSeverity(?string $severity): string
    {
        return match(strtolower($severity ?? '')) {
            'critical' => 'critical',
            'high' => 'high',
            'medium', 'moderate' => 'medium',
            default => 'low',
        };
    }
}
