```php
<?php
// app/Console/Commands/SecurityAuditCommand.php
namespace App\Console\Commands;

use Illuminate\Console\Command;
use App\Services\DependencySecurityService;

class SecurityAuditCommand extends Command
{
    protected $signature = 'security:audit 
                            {--severity=medium : Minimum severity to report}
                            {--fail-on=critical : Fail if vulnerabilities at this level exist}';

    protected $description = 'Run security audit on composer dependencies';

    public function handle(DependencySecurityService $service): int
    {
        $this->info('Running dependency security audit...');

        $results = $service->runSecurityAudit();

        if (isset($results['error'])) {
            $this->error('Audit failed: ' . $results['error']);
            return Command::FAILURE;
        }

        $this->displayResults($results);

        $failLevel = $this->option('fail-on');
        if ($this->hasVulnerabilitiesAtLevel($results, $failLevel)) {
            $this->error("Found {$failLevel} or higher vulnerabilities!");
            return Command::FAILURE;
        }

        $this->info('Security audit completed successfully.');
        return Command::SUCCESS;
    }

    private function displayResults(array $results): void
    {
        foreach (['critical', 'high', 'medium', 'low'] as $severity) {
            $count = count($results[$severity] ?? []);
            if ($count > 0) {
                $this->warn("Found {$count} {$severity} vulnerabilities:");
                foreach ($results[$severity] as $vuln) {
                    $this->line("  - {$vuln['package']} ({$vuln['cve']}): {$vuln['title']}");
                }
            }
        }
    }

    private function hasVulnerabilitiesAtLevel(array $results, string $level): bool
    {
        $levels = ['critical', 'high', 'medium', 'low'];
        $threshold = array_search($level, $levels);

        for ($i = 0; $i <= $threshold; $i++) {
            if (!empty($results[$levels[$i]])) {
                return true;
            }
        }

        return false;
    }
}
