**Key Security Controls**:
- **Protocol Whitelisting**: Only TLS 1.2 and TLS 1.3 are enabled, completely blocking SSLv3, TLS 1.0, and TLS 1.1
- **Strong Cipher Suites**: Only AEAD ciphers (GCM, ChaCha20-Poly1305) with forward secrecy (ECDHE) are allowed
- **Certificate Validation**: Default trust managers verify server certificates against trusted CA store
- **Hostname Verification**: Ensures certificate matches the requested hostname to prevent MITM attacks

Server-side TLS configuration is critical because attackers will probe for weak protocol support. Even if your client is secure, a misconfigured server can be exploited via downgrade attacks. Here's a production-ready Spring Boot configuration with multiple defense layers.

**PRODUCTION PATTERN**:

```java
// application.yml - Primary TLS Configuration
/*
server:
  port: 8443
  ssl:
    enabled: true
    key-store: classpath:keystore.p12
    key-store-password: ${SSL_KEYSTORE_PASSWORD}
    key-store-type: PKCS12
    key-alias: tomcat
    # CRITICAL: Protocol configuration
    enabled-protocols: TLSv1.3,TLSv1.2
    # Strong cipher suites only
    ciphers:
      - TLS_AES_256_GCM_SHA384
      - TLS_AES_128_GCM_SHA256
      - TLS_CHACHA20_POLY1305_SHA256
      - TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384
      - TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384
    # Client certificate authentication (optional, for mTLS)
    client-auth: want
*/

package com.example.secure.config;

import org.apache.catalina.connector.Connector;
import org.apache.coyote.http11.Http11NioProtocol;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.web.embedded.tomcat.TomcatServletWebServerFactory;
import org.springframework.boot.web.server.WebServerFactoryCustomizer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.HstsHeaderWriter;

import javax.net.ssl.*;
import java.security.KeyStore;
import java.time.Duration;
import java.util.Arrays;
import java.util.logging.Logger;

@Configuration
@EnableWebSecurity
public class SecureTlsConfiguration {

    private static final Logger logger = Logger.getLogger(SecureTlsConfiguration.class.getName());

    // Secure protocols - TLS 1.2 minimum, TLS 1.3 preferred
    private static final String[] ALLOWED_PROTOCOLS = {"TLSv1.3", "TLSv1.2"};

    // Blocked protocols - explicitly disabled
    private static final String[] BLOCKED_PROTOCOLS = {"SSLv2", "SSLv3", "TLSv1", "TLSv1.1"};

    // Strong cipher suites with forward secrecy and AEAD
    private static final String[] SECURE_CIPHERS = {
        // TLS 1.3 cipher suites
        "TLS_AES_256_GCM_SHA384",
        "TLS_AES_128_GCM_SHA256",
        "TLS_CHACHA20_POLY1305_SHA256",
        // TLS 1.2 cipher suites with ECDHE and GCM
        "TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384",
        "TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256",
        "TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256",
        "TLS_ECDHE_ECDSA_WITH_CHACHA20_POLY1305_SHA256",
        "TLS_ECDHE_RSA_WITH_CHACHA20_POLY1305_SHA256"
    };

    @Value("${ssl.keystore.path}")
    private String keystorePath;

    @Value("${ssl.keystore.password}")
    private String keystorePassword;

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            // Force HTTPS for all requests
            .requiresChannel(channel -> channel
                .anyRequest().requiresSecure()
            )
            // HSTS header - force browsers to use HTTPS
            .headers(headers -> headers
                .httpStrictTransportSecurity(hsts -> hsts
                    .includeSubDomains(true)
                    .maxAgeInSeconds(31536000) // 1 year
                    .preload(true)
                )
            )
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/health").permitAll()
                .anyRequest().authenticated()
            );

        return http.build();
    }

    @Bean
    public WebServerFactoryCustomizer<TomcatServletWebServerFactory> tlsCustomizer() {
        return factory -> {
            factory.addConnectorCustomizers(connector -> {
                Http11NioProtocol protocol = (Http11NioProtocol) connector.getProtocolHandler();

                // SECURE: Explicitly set allowed protocols
                protocol.setSSLEnabledProtocols(String.join(",", ALLOWED_PROTOCOLS));

                // SECURE: Set strong cipher suites
                protocol.setCiphers(String.join(",", SECURE_CIPHERS));

                // SECURE: Use server's cipher preference order
                protocol.setUseServerCipherSuitesOrder(true);

                // Enable session tickets for TLS 1.3 performance
                protocol.setSessionTimeout(3600);

                logger.info("TLS configured with protocols: " + Arrays.toString(ALLOWED_PROTOCOLS));
                logger.info("TLS cipher suites: " + protocol.getCiphers());
            });
        };
    }

    @Bean
    public SSLContext serverSSLContext() throws Exception {
        // Load keystore
        KeyStore keyStore = KeyStore.getInstance("PKCS12");
        try (var is = getClass().getResourceAsStream(keystorePath)) {
            keyStore.load(is, keystorePassword.toCharArray());
        }

        // Initialize key manager
        KeyManagerFactory kmf = KeyManagerFactory.getInstance(
            KeyManagerFactory.getDefaultAlgorithm());
        kmf.init(keyStore, keystorePassword.toCharArray());

        // Initialize trust manager for client certificates (mTLS)
        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init(keyStore);

        // Create SSL context with TLS 1.3
        SSLContext sslContext = SSLContext.getInstance("TLSv1.3");
        sslContext.init(kmf.getKeyManagers(), tmf.getTrustManagers(), null);

        // Verify configuration
        SSLParameters params = sslContext.getDefaultSSLParameters();
        params.setProtocols(ALLOWED_PROTOCOLS);
        params.setCipherSuites(SECURE_CIPHERS);
        params.setUseCipherSuitesOrder(true);

        logger.info("SSLContext initialized with protocols: " + 
            Arrays.toString(params.getProtocols()));

        return sslContext;
    }
}
