// AES-GCM provides:
// - Confidentiality (encryption)
// - Integrity (authentication tag detects tampering)
// - Optional associated data authentication
aesGcm.Encrypt(nonce, plainBytes, cipherText, tag, associatedData);

// Tampering attempt throws AuthenticationTagMismatchException
try {
    aesGcm.Decrypt(nonce, modifiedCipherText, tag, plainBytes, aad);
} catch (AuthenticationTagMismatchException) {
