**Why This Is Dangerous**:
- `java.util.Random` is not cryptographically secure and can be predicted
- 6-digit tokens have only 1 million possibilities - brute forceable in minutes
- No token expiration allows indefinite attack window
- No rate limiting enables automated enumeration
- HTTP transmission exposes tokens to network sniffing
- Response confirms valid email addresses (user enumeration)

**SECURE VERSION**:

```java
import java.security.SecureRandom;
import java.sql.*;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePasswordResetController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecurePasswordResetController.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "app_user";
    private static final String DB_PASS = "app_password";
    private static final int TOKEN_LENGTH = 32;
    private static final int TOKEN_EXPIRY_MINUTES = 15;

    // SECURE: Cryptographically secure random number generator
    private static final SecureRandom secureRandom = new SecureRandom();

    protected void doPost(HttpServletRequest request, HttpServletResponse response) {
        String email = request.getParameter("email");

        // SECURE: Input validation
        if (email == null || !isValidEmail(email)) {
            logger.warn("Invalid email format in reset request from IP: {}", 
                       request.getRemoteAddr());
            sendGenericResponse(response);
            return;
        }

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // SECURE: Generate cryptographically strong token
            byte[] tokenBytes = new byte[TOKEN_LENGTH];
            secureRandom.nextBytes(tokenBytes);
            String resetToken = Base64.getUrlEncoder().withoutPadding()
                                      .encodeToString(tokenBytes);

            // SECURE: Hash the token before storage
            String tokenHash = hashToken(resetToken);

            // SECURE: Set expiration time
            Timestamp expiresAt = Timestamp.from(
                Instant.now().plus(TOKEN_EXPIRY_MINUTES, ChronoUnit.MINUTES));

            // SECURE: Invalidate any existing tokens first
            invalidateExistingTokens(conn, email);

            String sql = "UPDATE users SET reset_token_hash = ?, " +
                        "reset_token_expires = ?, reset_attempts = 0 " +
                        "WHERE email = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, tokenHash);
            stmt.setTimestamp(2, expiresAt);
            stmt.setString(3, email);
            int updated = stmt.executeUpdate();

            if (updated > 0) {
                // SECURE: HTTPS only link
                String resetLink = "https://example.com/reset?token=" + resetToken;
                sendEmail(email, "Password Reset", buildSecureEmailBody(resetLink));
                logger.info("Password reset requested for user (email hash: {})", 
                           hashForLogging(email));
            }

            // SECURE: Always return same response (prevents user enumeration)
            sendGenericResponse(response);

        } catch (Exception e) {
            logger.error("Password reset error", e);
            sendGenericResponse(response);
        }
    }

    private void sendGenericResponse(HttpServletResponse response) {
        response.setContentType("application/json");
        response.getWriter().write(
            "{\"message\":\"If an account exists, a reset link will be sent.\"}");
    }

    private boolean isValidEmail(String email) {
        return email != null && email.matches("^[A-Za-z0-9+_.-]+@[A-Za-z0-9.-]+$") 
               && email.length() <= 254;
    }

    private String hashToken(String token) {
        // Use SHA-256 for token hashing
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(token.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(hash);
    }
}
```

**Key Security Controls**:
- **SecureRandom**: Uses cryptographically secure PRNG instead of predictable Random
- **256-bit tokens**: Base64-encoded 32 bytes = ~43 characters, computationally infeasible to brute force
- **Token hashing**: Store only hashed tokens in database, preventing token theft from DB compromise
- **Short expiration**: 15-minute window limits attack opportunity
- **Generic responses**: Same response for valid/invalid emails prevents user enumeration

Excellent question! The token validation endpoint is equally critical. You need to implement multiple layers of defense including token verification, rate limiting, and secure password update procedures.

**PRODUCTION PATTERN**:

```java
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.sql.*;
import java.time.Instant;
import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.mindrot.jbcrypt.BCrypt;

public class SecurePasswordResetService {
    private static final Logger logger = LoggerFactory.getLogger(SecurePasswordResetService.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private static final int MAX_RESET_ATTEMPTS = 3;
    private static final int RATE_LIMIT_WINDOW_SECONDS = 300;
    private static final int MAX_REQUESTS_PER_IP = 5;
    private static final int MIN_PASSWORD_LENGTH = 12;
    private static final int BCRYPT_ROUNDS = 12;

    // Rate limiting storage (use Redis in production)
    private final ConcurrentHashMap<String, RateLimitEntry> rateLimits = new ConcurrentHashMap<>();

    private final DataSource dataSource;
    private final PasswordPolicyValidator passwordValidator;
    private final NotificationService notificationService;

    public SecurePasswordResetService(DataSource dataSource) {
        this.dataSource = dataSource;
        this.passwordValidator = new PasswordPolicyValidator();
        this.notificationService = new NotificationService();
    }

    public ResetResult validateAndResetPassword(HttpServletRequest request,
                                                  String token,
                                                  String newPassword,
                                                  String confirmPassword) {
        String clientIp = getClientIp(request);
        String requestId = generateRequestId();

        // LAYER 1: Rate limiting by IP
        if (isRateLimited(clientIp)) {
            auditLogger.warn("[{}] Rate limit exceeded for IP: {}", requestId, clientIp);
            return ResetResult.rateLimited();
        }

        // LAYER 2: Input validation
        if (token == null || token.length() < 40 || token.length() > 50) {
            logger.warn("[{}] Invalid token format from IP: {}", requestId, clientIp);
            return ResetResult.invalidToken();
        }

        if (!newPassword.equals(confirmPassword)) {
            return ResetResult.passwordMismatch();
        }

        // LAYER 3: Password policy validation
        PasswordValidationResult policyResult = passwordValidator.validate(newPassword);
        if (!policyResult.isValid()) {
            return ResetResult.weakPassword(policyResult.getErrors());
        }

        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            try {
                // LAYER 4: Token verification with timing-safe comparison
                String tokenHash = hashToken(token);

                String sql = "SELECT id, email, reset_token_hash, reset_token_expires, " +
                            "reset_attempts, password_hash FROM users " +
                            "WHERE reset_token_hash IS NOT NULL FOR UPDATE";

                PreparedStatement stmt = conn.prepareStatement(sql);
                ResultSet rs = stmt.executeQuery();

                UserResetData userData = null;
                while (rs.next()) {
                    String storedHash = rs.getString("reset_token_hash");
                    // SECURE: Timing-safe comparison prevents timing attacks
                    if (MessageDigest.isEqual(
                            tokenHash.getBytes(StandardCharsets.UTF_8),
                            storedHash.getBytes(StandardCharsets.UTF_8))) {
                        userData = extractUserData(rs);
                        break;
                    }
                }

                if (userData == null) {
                    logger.warn("[{}] Invalid reset token from IP: {}", requestId, clientIp);
                    incrementRateLimit(clientIp);
                    return ResetResult.invalidToken();
                }

                // LAYER 5: Token expiration check
                if (Instant.now().isAfter(userData.tokenExpires)) {
                    auditLogger.info("[{}] Expired reset token for user: {}", 
                                    requestId, userData.userId);
                    invalidateToken(conn, userData.userId);
                    conn.commit();
                    return ResetResult.tokenExpired();
                }

                // LAYER 6: Attempt limiting per token
                if (userData.resetAttempts >= MAX_RESET_ATTEMPTS) {
                    auditLogger.warn("[{}] Max reset attempts exceeded for user: {}", 
                                    requestId, userData.userId);
                    invalidateToken(conn, userData.userId);
                    conn.commit();
                    return ResetResult.maxAttemptsExceeded();
                }

                // LAYER 7: Check password isn't same as current
                if (BCrypt.checkpw(newPassword, userData.currentPasswordHash)) {
                    return ResetResult.sameAsCurrent();
                }

                // LAYER 8: Check password history (prevent reuse)
                if (isPasswordInHistory(conn, userData.userId, newPassword)) {
                    return ResetResult.passwordReused();
                }

                // LAYER 9: Update password with strong hashing
                String newPasswordHash = BCrypt.hashpw(newPassword, 
                                                       BCrypt.gensalt(BCRYPT_ROUNDS));

                updatePasswordAndInvalidateToken(conn, userData.userId, newPasswordHash);
                addToPasswordHistory(conn, userData.userId, newPasswordHash);

                // LAYER 10: Invalidate all existing sessions
                invalidateAllSessions(conn, userData.userId);

                conn.commit();

                // LAYER 11: Notify user of password change
                notificationService.sendPasswordChangeNotification(
                    userData.email, clientIp, request.getHeader("User-Agent"));

                auditLogger.info("[{}] Password successfully reset for user: {} from IP: {}",
                               requestId, userData.userId, clientIp);

                return ResetResult.success();

            } catch (Exception e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            logger.error("[{}] Database error during password reset", requestId, e);
            return ResetResult.systemError();
        }
    }

    private void updatePasswordAndInvalidateToken(Connection conn, long userId, 
                                                   String passwordHash) throws SQLException {
        String sql = "UPDATE users SET password_hash = ?, reset_token_hash = NULL, " +
                    "reset_token_expires = NULL, reset_attempts = 0, " +
                    "password_changed_at = CURRENT_TIMESTAMP, " +
                    "failed_login_attempts = 0 WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, passwordHash);
        stmt.setLong(2, userId);
        stmt.executeUpdate();
    }

    private void invalidateAllSessions(Connection conn, long userId) throws SQLException {
        String sql = "DELETE FROM user_sessions WHERE user_id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        int invalidated = stmt.executeUpdate();
        logger.info("Invalidated {} sessions for user {}", invalidated, userId);
    }

    private boolean isPasswordInHistory(Connection conn, long userId, 
                                        String newPassword) throws SQLException {
        String sql = "SELECT password_hash FROM password_history " +
                    "WHERE user_id = ? ORDER BY created_at DESC LIMIT 10";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, userId);
        ResultSet rs = stmt.executeQuery();

        while (rs.next()) {
            if (BCrypt.checkpw(newPassword, rs.getString("password_hash"))) {
                return true;
            }
        }
        return false;
    }

    private String hashToken(String token) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(token.getBytes(StandardCharsets.UTF_8));
        return Base64.getEncoder().encodeToString(hash);
    }

    private String getClientIp(HttpServletRequest request) {
        String xff = request.getHeader("X-Forwarded-For");
        if (xff != null && !xff.isEmpty()) {
            return xff.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String generateRequestId() {
        byte[] bytes = new byte[8];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    private static class RateLimitEntry {
        AtomicInteger count = new AtomicInteger(0);
        long windowStart = System.currentTimeMillis();
    }
}

public class PasswordPolicyValidator {
    private static final int MIN_LENGTH = 12;
    private static final int MAX_LENGTH = 128;

    public PasswordValidationResult validate(String password) {
        List<String> errors = new ArrayList<>();

        if (password == null || password.length() < MIN_LENGTH) {
            errors.add("Password must be at least " + MIN_LENGTH + " characters");
        }
        if (password != null && password.length() > MAX_LENGTH) {
            errors.add("Password must not exceed " + MAX_LENGTH + " characters");
        }
        if (!password.matches(".*[A-Z].*")) {
            errors.add("Password must contain at least one uppercase letter");
        }
        if (!password.matches(".*[a-z].*")) {
            errors.add("Password must contain at least one lowercase letter");
        }
        if (!password.matches(".*[0-9].*")) {
            errors.add("Password must contain at least one digit");
        }
        if (!password.matches(".*[!@#$%^&*()_+\\-=\\[\\]{}|;':,.<>?/].*")) {
            errors.add("Password must contain at least one special character");
        }
        // Check for common passwords
        if (isCommonPassword(password)) {
            errors.add("Password is too common. Please choose a stronger password");
        }

        return new PasswordValidationResult(errors.isEmpty(), errors);
    }

    private boolean isCommonPassword(String password) {
        // Check against top 10000 common passwords (load from file in production)
        Set<String> commonPasswords = loadCommonPasswords();
        return commonPasswords.contains(password.toLowerCase());
    }
}
```

**Defense in Depth Layers**:

1. **Rate Limiting**: Prevents brute force attacks by limiting requests per IP address
```java
private boolean isRateLimited(String clientIp) {
    RateLimitEntry entry = rateLimits.computeIfAbsent(clientIp, k -> new RateLimitEntry());
    long now = System.currentTimeMillis();
    if (now - entry.windowStart > RATE_LIMIT_WINDOW_SECONDS * 1000) {
        entry.windowStart = now;
        entry.count.set(0);
    }
    return entry.count.incrementAndGet() > MAX_REQUESTS_PER_IP;
}
```

2. **Timing-Safe Token Comparison**: Prevents timing attacks that could leak valid tokens
```java
// VULNERABLE: Variable-time comparison
if (tokenHash.equals(storedHash)) { ... }  // DON'T DO THIS

// SECURE: Constant-time comparison
if (MessageDigest.isEqual(tokenHash.getBytes(), storedHash.getBytes())) { ... }
```

3. **Session Invalidation**: Forces re-authentication after password change
```java
private void invalidateAllSessions(Connection conn, long userId) throws SQLException {
    String sql = "DELETE FROM user_sessions WHERE user_id = ?";
    // Also invalidate refresh tokens, API keys, remember-me tokens
}
```

**Additional Protections**:
- **Password history**: Prevents reuse of last 10 passwords
- **Bcrypt with high work factor**: 2^12 iterations makes offline attacks expensive
- **Transactional integrity**: All operations atomic - no partial state
- **User notification**: Email alert on successful password change with IP/User-Agent
- **Audit logging**: Separate audit log for compliance and forensics
- **Token single-use**: Token invalidated immediately after successful use
- **Account lockout integration**: Failed reset attempts contribute to lockout counter

Multi-tenant data isolation is one of the most critical security controls in SaaS applications. A single flaw can expose ALL your customers' data to unauthorized access. This vulnerability caused massive breaches in 2023, including the Salesforce Community Sites incident affecting hundreds of organizations.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const { Pool } = require('pg');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// VULNERABLE: Trusts user-provided tenant ID without validation
app.get('/api/customers', async (req, res) => {
  const tenantId = req.query.tenant_id; // User can change this!

  try {
    const result = await pool.query(
      'SELECT * FROM customers WHERE tenant_id = $1',
      [tenantId]
    );
    res.json(result.rows);
  } catch (error) {
    res.status(500).json({ error: 'Database error' });
  }
});

// VULNERABLE: No tenant isolation on document retrieval
app.get('/api/documents/:documentId', async (req, res) => {
  const { documentId } = req.params;

  try {
    // Missing tenant check - any user can access any document!
    const result = await pool.query(
      'SELECT * FROM documents WHERE id = $1',
      [documentId]
    );

    if (result.rows.length === 0) {
      return res.status(404).json({ error: 'Document not found' });
    }

    res.json(result.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'Database error' });
  }
});
```

**Attack Payload**:
```bash
# Attacker authenticated as Tenant A user, accessing Tenant B's data
curl -H "Authorization: Bearer valid_token_for_tenant_a" \
  "https://api.example.com/api/customers?tenant_id=tenant_b_uuid"

# Direct object reference - enumerate document IDs to find other tenants' files
for i in {1..10000}; do
  curl -H "Authorization: Bearer valid_token" \
    "https://api.example.com/api/documents/$i"
done
```

**Why This Is Dangerous**:
- User-controllable tenant_id parameter allows horizontal privilege escalation
- Document retrieval has no tenant context validation at all
- Attackers can enumerate resources across all tenants
- A single compromised user account exposes every customer's data
- Violates data protection regulations (GDPR, HIPAA, SOC 2)

**SECURE VERSION**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const jwt = require('jsonwebtoken');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Middleware: Extract and validate tenant from authenticated token
const tenantIsolation = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.replace('Bearer ', '');
    if (!token) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // CRITICAL: Tenant ID comes from verified token, NOT user input
    req.tenantId = decoded.tenant_id;
    req.userId = decoded.user_id;

    if (!req.tenantId) {
      return res.status(403).json({ error: 'Invalid tenant context' });
    }

    next();
  } catch (error) {
    return res.status(401).json({ error: 'Invalid authentication' });
  }
};

app.use('/api', tenantIsolation);

// SECURE: Tenant ID enforced from authenticated session
app.get('/api/customers', async (req, res) => {
  try {
    // Tenant ID from verified JWT, not query parameter
    const result = await pool.query(
      'SELECT id, name, email, created_at FROM customers WHERE tenant_id = $1',
      [req.tenantId]
    );
    res.json(result.rows);
  } catch (error) {
    console.error(`Tenant ${req.tenantId} customer query failed:`, error.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// SECURE: Document access validated against tenant context
app.get('/api/documents/:documentId', async (req, res) => {
  const { documentId } = req.params;

  // Input validation
  if (!documentId || !/^[0-9a-f-]{36}$/i.test(documentId)) {
    return res.status(400).json({ error: 'Invalid document ID format' });
  }

  try {
    // CRITICAL: Always include tenant_id in WHERE clause
    const result = await pool.query(
      'SELECT id, name, content_type, created_at FROM documents WHERE id = $1 AND tenant_id = $2',
      [documentId, req.tenantId]
    );

    if (result.rows.length === 0) {
      // Don't reveal if document exists for other tenant
      return res.status(404).json({ error: 'Document not found' });
    }

    res.json(result.rows[0]);
  } catch (error) {
    console.error(`Document ${documentId} access failed for tenant ${req.tenantId}:`, error.message);
    res.status(500).json({ error: 'Internal server error' });
  }
});
```

**Key Security Controls**:
- **Server-side tenant enforcement**: Tenant ID extracted from cryptographically signed JWT, never from user input
- **Mandatory tenant filtering**: Every database query includes tenant_id in WHERE clause
- **Consistent error responses**: 404 returned regardless of whether resource exists in another tenant (prevents enumeration)
- **Input validation**: Document IDs validated against expected format before database query

Excellent question. Cross-tenant access and shared resources are common requirements that introduce significant complexity. The key is implementing a robust authorization layer that handles these cases explicitly while maintaining strong isolation by default.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const { Pool } = require('pg');
const jwt = require('jsonwebtoken');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

// Structured audit logging
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'tenant-access' },
  transports: [
    new winston.transports.File({ filename: 'audit.log' }),
    new winston.transports.Console()
  ]
});

// Rate limiting for cross-tenant operations
const crossTenantLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many cross-tenant requests' }
});

// Tenant access types
const AccessType = {
  SAME_TENANT: 'same_tenant',
  SHARED_RESOURCE: 'shared_resource',
  ADMIN_CROSS_TENANT: 'admin_cross_tenant',
  DENIED: 'denied'
};

// Authorization service with explicit cross-tenant handling
class TenantAuthorizationService {
  constructor(pool, logger) {
    this.pool = pool;
    this.logger = logger;
  }

  async checkResourceAccess(userId, userTenantId, userRole, resourceType, resourceId, targetTenantId = null) {
    const accessContext = {
      userId,
      userTenantId,
      userRole,
      resourceType,
      resourceId,
      targetTenantId,
      timestamp: new Date().toISOString()
    };

    try {
      // Case 1: Same tenant access (default path)
      if (!targetTenantId || targetTenantId === userTenantId) {
        const hasAccess = await this.verifySameTenantAccess(
          userId, userTenantId, resourceType, resourceId
        );

        if (hasAccess) {
          this.logger.info('Same tenant access granted', accessContext);
          return { allowed: true, type: AccessType.SAME_TENANT };
        }
      }

      // Case 2: Check for explicit shared resource access
      const sharedAccess = await this.checkSharedResourceAccess(
        userTenantId, resourceType, resourceId
      );

      if (sharedAccess.allowed) {
        this.logger.info('Shared resource access granted', {
          ...accessContext,
          sharingAgreementId: sharedAccess.agreementId
        });
        return { allowed: true, type: AccessType.SHARED_RESOURCE, agreementId: sharedAccess.agreementId };
      }

      // Case 3: Platform admin cross-tenant access (highly restricted)
      if (userRole === 'platform_admin' && targetTenantId) {
        const adminAccess = await this.validateAdminCrossTenantAccess(
          userId, targetTenantId, resourceType
        );

        if (adminAccess.allowed) {
          // Enhanced audit for admin cross-tenant access
          this.logger.warn('ADMIN CROSS-TENANT ACCESS', {
            ...accessContext,
            justification: adminAccess.justification,
            expiresAt: adminAccess.expiresAt,
            approvedBy: adminAccess.approvedBy
          });
          return { allowed: true, type: AccessType.ADMIN_CROSS_TENANT };
        }
      }

      // Default deny - log the denial
      this.logger.warn('Access denied', accessContext);
      return { allowed: false, type: AccessType.DENIED };

    } catch (error) {
      this.logger.error('Authorization check failed', { ...accessContext, error: error.message });
      return { allowed: false, type: AccessType.DENIED, error: 'Authorization check failed' };
    }
  }

  async verifySameTenantAccess(userId, tenantId, resourceType, resourceId) {
    const query = `
      SELECT 1 FROM ${this.sanitizeTableName(resourceType)}
      WHERE id = $1 AND tenant_id = $2
      LIMIT 1
    `;
    const result = await this.pool.query(query, [resourceId, tenantId]);
    return result.rows.length > 0;
  }

  async checkSharedResourceAccess(requestingTenantId, resourceType, resourceId) {
    // Check explicit sharing agreements
    const query = `
      SELECT sa.id as agreement_id, sa.permissions, sa.expires_at
      FROM sharing_agreements sa
      JOIN ${this.sanitizeTableName(resourceType)} r ON r.id = sa.resource_id
      WHERE sa.resource_id = $1
        AND sa.resource_type = $2
        AND sa.shared_with_tenant_id = $3
        AND sa.status = 'active'
        AND (sa.expires_at IS NULL OR sa.expires_at > NOW())
      LIMIT 1
    `;
    const result = await this.pool.query(query, [resourceId, resourceType, requestingTenantId]);

    if (result.rows.length > 0) {
      return { allowed: true, agreementId: result.rows[0].agreement_id };
    }
    return { allowed: false };
  }

  async validateAdminCrossTenantAccess(adminUserId, targetTenantId, resourceType) {
    // Require explicit, time-limited, approved access tickets
    const query = `
      SELECT at.id, at.justification, at.expires_at, at.approved_by
      FROM admin_access_tickets at
      WHERE at.admin_user_id = $1
        AND at.target_tenant_id = $2
        AND at.resource_type = $3
        AND at.status = 'approved'
        AND at.expires_at > NOW()
      LIMIT 1
    `;
    const result = await this.pool.query(query, [adminUserId, targetTenantId, resourceType]);

    if (result.rows.length > 0) {
      const ticket = result.rows[0];
      return {
        allowed: true,
        justification: ticket.justification,
        expiresAt: ticket.expires_at,
        approvedBy: ticket.approved_by
      };
    }
    return { allowed: false };
  }

  sanitizeTableName(resourceType) {
    const allowedTables = ['documents', 'customers', 'projects', 'reports'];
    if (!allowedTables.includes(resourceType)) {
      throw new Error('Invalid resource type');
    }
    return resourceType;
  }
}

const authService = new TenantAuthorizationService(pool, auditLogger);

// Enhanced middleware with tenant context
const tenantAuthMiddleware = async (req, res, next) => {
  try {
    const token = req.headers.authorization?.replace('Bearer ', '');
    if (!token) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    req.auth = {
      userId: decoded.user_id,
      tenantId: decoded.tenant_id,
      role: decoded.role,
      permissions: decoded.permissions || []
    };

    // Add tenant context to all responses for debugging
    res.set('X-Tenant-Context', req.auth.tenantId);

    next();
  } catch (error) {
    auditLogger.warn('Authentication failed', { error: error.message, ip: req.ip });
    return res.status(401).json({ error: 'Invalid authentication' });
  }
};

app.use('/api', tenantAuthMiddleware);

// Standard same-tenant document access
app.get('/api/documents/:documentId', async (req, res) => {
  const { documentId } = req.params;

  if (!/^[0-9a-f-]{36}$/i.test(documentId)) {
    return res.status(400).json({ error: 'Invalid document ID' });
  }

  const accessResult = await authService.checkResourceAccess(
    req.auth.userId,
    req.auth.tenantId,
    req.auth.role,
    'documents',
    documentId
  );

  if (!accessResult.allowed) {
    return res.status(404).json({ error: 'Document not found' });
  }

  try {
    const result = await pool.query(
      'SELECT id, name, content_type, size, created_at FROM documents WHERE id = $1',
      [documentId]
    );

    res.json({
      ...result.rows[0],
      accessType: accessResult.type
    });
  } catch (error) {
    auditLogger.error('Document retrieval failed', { documentId, error: error.message });
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Cross-tenant admin access (rate limited, heavily audited)
app.get('/api/admin/tenants/:tenantId/documents',
  crossTenantLimiter,
  async (req, res) => {
    const { tenantId: targetTenantId } = req.params;

    if (req.auth.role !== 'platform_admin') {
      auditLogger.warn('Non-admin attempted cross-tenant access', {
        userId: req.auth.userId,
        userTenantId: req.auth.tenantId,
        targetTenantId
      });
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    const accessResult = await authService.checkResourceAccess(
      req.auth.userId,
      req.auth.tenantId,
      req.auth.role,
      'documents',
      null,
      targetTenantId
    );

    if (!accessResult.allowed) {
      return res.status(403).json({ 
        error: 'Cross-tenant access not authorized',
        hint: 'Submit an access ticket for approval'
      });
    }

    try {
      const result = await pool.query(
        'SELECT id, name, content_type, created_at FROM documents WHERE tenant_id = $1',
        [targetTenantId]
      );

      res.json({
        documents: result.rows,
        accessContext: {
          type: accessResult.type,
          grantedVia: 'admin_access_ticket'
        }
      });
    } catch (error) {
      res.status(500).json({ error: 'Internal server error' });
    }
  }
);

// Health check for monitoring
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', timestamp: new Date().toISOString() });
});

module.exports = app;
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT validation with tenant context embedded in signed token
```javascript
// Tenant ID is cryptographically bound to the session
const decoded = jwt.verify(token, process.env.JWT_SECRET);
req.auth.tenantId = decoded.tenant_id; // Cannot be forged
```

2. **Authorization Layer**: Explicit access checks with multiple access paths
```javascript
// Every resource access goes through central authorization
const accessResult = await authService.checkResourceAccess(
  userId, tenantId, role, resourceType, resourceId, targetTenantId
);
```

3. **Database Layer**: Tenant ID always in query predicate
```javascript
// Even after authorization passes, queries are tenant-scoped
WHERE id = $1 AND tenant_id = $2
```

4. **Audit Layer**: All access decisions logged with full context
```javascript
auditLogger.info('Access granted', { userId, tenantId, resourceId, accessType });
```

**Additional Protections**:

- **Time-limited admin access**: Cross-tenant admin access requires pre-approved tickets that expire
- **Dual authorization for sharing**: Resource sharing requires explicit agreement records with defined permissions
- **Rate limiting on sensitive endpoints**: Cross-tenant operations have stricter rate limits
- **Information hiding**: 404 returned for unauthorized resources regardless of existence
- **Response headers**: Tenant context in headers aids debugging and incident response
- **Allowlist for resource types**: Prevents SQL injection via resource type parameter
- **Separation of logging**: Security audit logs separate from application logs for SIEM integration

Using JWTs in Rust web frameworks like Axum can be dangerous if the tokens are not verified correctly. A few common mistakes are: trusting the algorithm from the token header, not checking issuer/audience, or using weak/secrets embedded in code.

**VULNERABLE CODE**:

```rust
use axum::{
    extract::FromRequestParts,
    http::{request::Parts, StatusCode},
    response::Response,
    routing::get,
    Router,
};
use jsonwebtoken::{decode, Algorithm, DecodingKey, Validation};
use serde::Deserialize;

#[derive(Debug, Deserialize)]
struct Claims {
    sub: String,
    role: String,
    exp: usize,
    iss: String,
    aud: String,
}

struct AuthUser {
    user_id: String,
    role: String,
}

#[axum::async_trait]
impl<S> FromRequestParts<S> for AuthUser
where
    S: Send + Sync,
{
    type Rejection = Response;

    async fn from_request_parts(
        parts: &mut Parts,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        let auth_header = parts
            .headers
            .get("Authorization")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("");

        // 1) No check for "Bearer " prefix; takes entire header as token
        let token = auth_header;

        // 2) Hard-coded, weak secret, checked into source
        let secret = "secret";

        // 3) Uses default Validation::default(), accepts alg from header
        let validation = Validation::default();

        let token_data = match decode::<Claims>(
            token,
            &DecodingKey::from_secret(secret.as_bytes()),
            &validation,
        ) {
            Ok(data) => data,
            Err(_) => {
                return Err((StatusCode::UNAUTHORIZED, "invalid token").into_response());
            }
        };

        // 4) No issuer or audience checking, blindly trusts claims
        Ok(AuthUser {
            user_id: token_data.claims.sub,
            role: token_data.claims.role,
        })
    }
}

async fn admin_only(user: AuthUser) -> String {
    // 5) Role check is missing entirely
    format!("Hello, {}! You are in admin area.", user.user_id)
}

#[tokio::main]
async fn main() {
    let app = Router::new().route("/admin", get(admin_only));

    axum::Server::bind(&"0.0.0.0:3000".parse().unwrap())
        .serve(app.into_make_service())
        .await
        .unwrap();
}
```

**Attack Payload** (forged JWT with `none` algorithm):
```text
Authorization: eyJhbGciOiJub25lIiwidHlwIjoiSldUIn0.ewogICJzdWIiOiAiYWRtaW4iLAogICJyb2xlIjogImFkbWluIiwKICAiaXNzIjogImh0dHBzOi8vYXR0YWNrZXIuZXhhbXBsZSIsCiAgImF1ZCI6ICJhcGkiLAogICJleHAiOiAxOTk5OTk5OTk5Cn0.
```

This payload is a base64-encoded JWT header and body with `alg: none` and role `admin`. In libraries that improperly accept `none` or trust the `alg` from the header when misconfigured, an attacker can craft tokens that appear valid without any signature.

**Why This Is Dangerous**:
- Trusts the `alg` from the JWT header and uses almost default validation, which can lead to algorithm confusion or acceptance of insecure algorithms if options change.
- Uses a hard-coded, trivial secret key (`"secret"`), which can be guessed or leaked from source control, enabling attackers to sign their own tokens.
- Skips critical checks (issuer, audience, role/authorization logic), so any valid-looking token is treated as fully trusted, enabling privilege escalation.

**SECURE VERSION**:

```rust
use axum::{
    async_trait,
    extract::FromRequestParts,
    http::{request::Parts, StatusCode},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use jsonwebtoken::{decode, Algorithm, DecodingKey, Validation};
use serde::Deserialize;
use std::env;
use tracing::{error, info};
use tracing_subscriber::EnvFilter;

#[derive(Debug, Deserialize)]
struct Claims {
    sub: String,
    role: String,
    exp: usize,
    iss: String,
    aud: String,
}

#[derive(Debug, Clone)]
struct AuthUser {
    user_id: String,
    role: String,
}

#[derive(Debug)]
struct AuthError(StatusCode, &'static str);

impl IntoResponse for AuthError {
    fn into_response(self) -> Response {
        (self.0, self.1).into_response()
    }
}

fn jwt_validation() -> (DecodingKey, Validation) {
    let secret = env::var("JWT_SECRET")
        .expect("JWT_SECRET must be set in environment (do NOT hard-code secrets)");

    // PRIMARY DEFENSE: Pin the algorithm and validate iss/aud
    let mut validation = Validation::new(Algorithm::HS256);
    validation.set_audience(&["my-api"]);
    validation.set_issuer(&["https://auth.mycompany.com"]);

    (DecodingKey::from_secret(secret.as_bytes()), validation)
}

#[async_trait]
impl<S> FromRequestParts<S> for AuthUser
where
    S: Send + Sync,
{
    type Rejection = Response;

    async fn from_request_parts(
        parts: &mut Parts,
        _state: &S,
    ) -> Result<Self, Self::Rejection> {
        let auth_header = parts
            .headers
            .get("Authorization")
            .and_then(|v| v.to_str().ok())
            .unwrap_or("");

        // DEFENSE: Require "Bearer <token>" format
        if !auth_header.starts_with("Bearer ") {
            return Err(AuthError(StatusCode::UNAUTHORIZED, "missing bearer token").into_response());
        }

        let token = &auth_header[7..];
        let (decoding_key, validation) = jwt_validation();

        match decode::<Claims>(token, &decoding_key, &validation) {
            Ok(token_data) => {
                info!("authenticated user {} with role {}", token_data.claims.sub, token_data.claims.role);

                Ok(AuthUser {
                    user_id: token_data.claims.sub,
                    role: token_data.claims.role,
                })
            }
            Err(e) => {
                error!("JWT validation failed: {}", e);
                Err(AuthError(StatusCode::UNAUTHORIZED, "invalid token").into_response())
            }
        }
    }
}

async fn admin_only(user: AuthUser) -> Result<String, Response> {
    // DEFENSE: Enforce authorization, not just authentication
    if user.role != "admin" {
        return Err(AuthError(StatusCode::FORBIDDEN, "insufficient role").into_response());
    }

    Ok(format!("Hello, {}! You are in admin area.", user.user_id))
}

#[tokio::main]
async fn main() {
    // Structured logging, configurable per environment
    tracing_subscriber::fmt()
        .with_env_filter(EnvFilter::from_default_env())
        .init();

    let app = Router::new().route("/admin", get(admin_only));

    axum::Server::bind(&"0.0.0.0:3000".parse().unwrap())
        .serve(app.into_make_service())
        .await
        .unwrap();
}
```

**Key Security Controls**:
- **Pinned algorithm and claim validation**: Uses `Validation::new(Algorithm::HS256)` and explicitly sets `iss` and `aud`, preventing algorithm confusion and token reuse from other services.
- **Secure secret management**: Reads `JWT_SECRET` from the environment instead of hard-coding it, making rotation and secure storage (e.g., via a secrets manager) feasible.
- **Authorization checks and safe failure**: Enforces role-based authorization (`admin` role), returns generic error messages, and logs failures for monitoring without leaking sensitive details to clients.

In production, JWT handling in Axum for microservices should be centralized around a well-defined token service, strict validation rules, and robust observability. Separate access and refresh tokens, use short-lived access tokens, and implement key rotation with a JWKS-like approach.

**PRODUCTION PATTERN**:

```rust
use axum::{
    async_trait,
    extract::FromRequestParts,
    http::{request::Parts, HeaderMap, StatusCode},
    response::{IntoResponse, Response},
    routing::{get, post},
    Json, Router,
};
use chrono::{Duration, Utc};
use jsonwebtoken::{decode, encode, Algorithm, DecodingKey, EncodingKey, Header, Validation};
use serde::{Deserialize, Serialize};
use std::{collections::HashMap, env, net::SocketAddr, sync::Arc};
use tokio::sync::RwLock;
use tower::limit::RateLimitLayer;
use tower_http::trace::TraceLayer;
use tracing::{error, info};
use tracing_subscriber::EnvFilter;

#[derive(Debug, Serialize, Deserialize, Clone)]
struct Claims {
    sub: String,
    role: String,
    exp: i64,
    iss: String,
    aud: String,
    kid: String, // key id for rotation
}

#[derive(Clone)]
struct KeyStore {
    active_kid: String,
    enc_keys: HashMap<String, EncodingKey>,
    dec_keys: HashMap<String, DecodingKey>,
}

impl KeyStore {
    fn from_env() -> Self {
        // In real deployments, load from JWKS / KMS; here from env for simplicity
        let active_kid = env::var("JWT_ACTIVE_KID").expect("JWT_ACTIVE_KID not set");
        let secret = env::var("JWT_SECRET_ACTIVE").expect("JWT_SECRET_ACTIVE not set");

        let mut enc_keys = HashMap::new();
        let mut dec_keys = HashMap::new();
        enc_keys.insert(active_kid.clone(), EncodingKey::from_secret(secret.as_bytes()));
        dec_keys.insert(active_kid.clone(), DecodingKey::from_secret(secret.as_bytes()));

        KeyStore {
            active_kid,
            enc_keys,
            dec_keys,
        }
    }

    fn encode_access(&self, sub: &str, role: &str) -> jsonwebtoken::errors::Result<String> {
        let now = Utc::now();
        let claims = Claims {
            sub: sub.to_string(),
            role: role.to_string(),
            iss: "https://auth.mycompany.com".into(),
            aud: "my-api".into(),
            exp: (now + Duration::minutes(5)).timestamp(), // short-lived access token
            kid: self.active_kid.clone(),
        };

        let mut header = Header::new(Algorithm::HS256);
        header.kid = Some(self.active_kid.clone());
        encode(&header, &claims, self.enc_keys.get(&self.active_kid).unwrap())
    }

    fn decode(&self, token: &str) -> jsonwebtoken::errors::Result<Claims> {
        let header = jsonwebtoken::decode_header(token)?;
        let kid = header
            .kid
            .ok_or_else(|| jsonwebtoken::errors::ErrorKind::InvalidToken)?;

        let key = self
            .dec_keys
            .get(&kid)
            .ok_or_else(|| jsonwebtoken::errors::ErrorKind::InvalidToken)?;

        let mut validation = Validation::new(Algorithm::HS256);
        validation.set_issuer(&["https://auth.mycompany.com"]);
        validation.set_audience(&["my-api"]);

        let token_data = decode::<Claims>(token, key, &validation)?;
        Ok(token_data.claims)
    }
}

#[derive(Clone)]
struct AppState {
    keys: Arc<RwLock<KeyStore>>,
    env: String,
}

#[derive(Debug)]
struct AuthError(StatusCode, &'static str);

impl IntoResponse for AuthError {
    fn into_response(self) -> Response {
        (self.0, self.1).into_response()
    }
}

#[derive(Debug, Clone)]
struct AuthUser {
    user_id: String,
    role: String,
}

#[async_trait]
impl FromRequestParts<AppState> for AuthUser {
    type Rejection = Response;

    async fn from_request_parts(
        parts: &mut Parts,
        state: &AppState,
    ) -> Result<Self, Self::Rejection> {
        let token = extract_bearer(&parts.headers)?;
        let keystore = state.keys.read().await;

        match keystore.decode(&token) {
            Ok(claims) => {
                info!("auth ok: sub={} role={}", claims.sub, claims.role);
                Ok(AuthUser {
                    user_id: claims.sub,
                    role: claims.role,
                })
            }
            Err(e) => {
                error!("JWT validation failed: {}", e);
                Err(AuthError(StatusCode::UNAUTHORIZED, "invalid token").into_response())
            }
        }
    }
}

fn extract_bearer(headers: &HeaderMap) -> Result<String, Response> {
    let auth = headers
        .get("Authorization")
        .and_then(|v| v.to_str().ok())
        .unwrap_or("");

    if !auth.starts_with("Bearer ") {
        return Err(AuthError(StatusCode::UNAUTHORIZED, "missing bearer token").into_response());
    }

    Ok(auth[7..].to_string())
}

#[derive(Deserialize)]
struct LoginRequest {
    username: String,
    password: String,
}

#[derive(Serialize)]
struct TokenResponse {
    access_token: String,
    token_type: String,
    expires_in: i64,
}

async fn login_handler(
    state: axum::extract::State<AppState>,
    Json(body): Json<LoginRequest>,
) -> Result<Json<TokenResponse>, Response> {
    // Example: authenticate against your user store
    if body.username != "admin" || body.password != "correct-horse-battery-staple" {
        return Err(AuthError(StatusCode::UNAUTHORIZED, "invalid credentials").into_response());
    }

    let keys = state.keys.read().await;
    let access = keys
        .encode_access(&body.username, "admin")
        .map_err(|_| AuthError(StatusCode::INTERNAL_SERVER_ERROR, "token issue").into_response())?;

    Ok(Json(TokenResponse {
        access_token: access,
        token_type: "Bearer".into(),
        expires_in: 300,
    }))
}

async fn admin_endpoint(user: AuthUser) -> Result<String, Response> {
    if user.role != "admin" {
        return Err(AuthError(StatusCode::FORBIDDEN, "insufficient role").into_response());
    }

    Ok(format!("Admin data for {}", user.user_id))
}

#[tokio::main]
async fn main() {
    // Environment-specific behavior
    let env_mode = env::var("APP_ENV").unwrap_or_else(|_| "dev".into());

    tracing_subscriber::fmt()
        .with_env_filter(EnvFilter::from_default_env())
        .init();

    let state = AppState {
        keys: Arc::new(RwLock::new(KeyStore.from_env())),
        env: env_mode.clone(),
    };

    let mut app = Router::new()
        .route("/login", post(login_handler))
        .route("/admin", get(admin_endpoint))
        .with_state(state.clone())
        .layer(TraceLayer::new_for_http());

    // Rate limiting for auth endpoints (defense in depth)
    app = app.layer(RateLimitLayer::new(100, std::time::Duration::from_secs(60)));

    let addr: SocketAddr = "0.0.0.0:3000".parse().unwrap();
    info!("starting server on {} in {} mode", addr, env_mode);

    axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
        .unwrap();
}
```

**Defense in Depth Layers**:
1. **Strict JWT validation and key rotation**:
   - `KeyStore::decode` pins `Algorithm::HS256`, validates `iss` and `aud`, and uses `kid` to select the correct key. This supports key rotation by loading multiple keys (e.g., from JWKS) while refusing unknown `kid` values.
   - Example:
   ```rust
   let mut validation = Validation::new(Algorithm::HS256);
   validation.set_issuer(&["https://auth.mycompany.com"]);
   validation.set_audience(&["my-api"]);
   ```

2. **Rate limiting and credential abuse protection**:
   - `RateLimitLayer::new(100, Duration::from_secs(60))` reduces brute-force attempts and token abuse, especially on `/login` and other sensitive routes.
   - This can be combined with account lockouts and IP-based rules in a real deployment.

3. **Observability, audit logging, and environment-specific hardening**:
   - Uses `TraceLayer` and `tracing` to log authentication successes and failures without leaking tokens.
   - `APP_ENV` can control stricter security headers, secure cookies on the gateway, and additional checks in production (e.g., require TLS offload and `X-Forwarded-Proto=https`).

**Additional Protections**:
- **Short-lived access tokens & dedicated refresh flows**: Access tokens expire in minutes and are not reused for long-lived sessions; refresh tokens should be stored server-side or in httpOnly cookies and validated at a dedicated auth service.
- **Centralized token issuance & validation**: Only a single auth service should issue tokens; other microservices only validate them with pinned settings and a synchronized `KeyStore` (JWKS or KMS-backed).
- **Secure transport and headers**: Enforce HTTPS everywhere (via ingress), add `Strict-Transport-Security`, and for browser clients, ensure `SameSite`, `Secure`, and `HttpOnly` on any JWT-carrying cookies, plus robust CORS restrictions at the API gateway.

GraphQL authorization is tricky because the flexible query structure allows attackers to access data through nested relationships that bypass top-level authorization checks. This is exactly what happened in CVE-2024-4835 where GitLab's GraphQL API allowed unauthorized access to private resources.

**VULNERABLE CODE**:

```go
package graph

import (
	"context"
	"database/sql"
	"errors"

	"github.com/99designs/gqlgen/graphql"
	"myapp/graph/model"
)

type Resolver struct {
	DB *sql.DB
}

// Query resolver - checks auth at top level only
func (r *queryResolver) User(ctx context.Context, id string) (*model.User, error) {
	// Get current user from context
	currentUser := ctx.Value("user").(*model.User)

	// Only check if user is authenticated, not authorized
	if currentUser == nil {
		return nil, errors.New("not authenticated")
	}

	// VULNERABLE: No check if currentUser can access requested user's data
	var user model.User
	err := r.DB.QueryRow(
		"SELECT id, name, email FROM users WHERE id = $1",
		id,
	).Scan(&user.ID, &user.Name, &user.Email)

	return &user, err
}

// VULNERABLE: Nested resolver with no authorization
func (r *userResolver) PrivateDocuments(ctx context.Context, obj *model.User) ([]*model.Document, error) {
	// No authorization check - assumes parent resolver validated access
	rows, err := r.DB.Query(
		"SELECT id, title, content, classification FROM documents WHERE owner_id = $1",
		obj.ID,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var docs []*model.Document
	for rows.Next() {
		var doc model.Document
		rows.Scan(&doc.ID, &doc.Title, &doc.Content, &doc.Classification)
		docs = append(docs, &doc)
	}
	return docs, nil
}
```

**Attack Payload**:
```graphql
# Attacker queries another user's private documents
query {
  user(id: "victim-user-id-123") {
    id
    name
    email
    privateDocuments {
      id
      title
      content
      classification
    }
  }
}
```

**Why This Is Dangerous**:
- Authorization only checks authentication, not whether the requesting user can access the target user's data
- Nested resolvers trust that parent resolvers performed authorization, creating an authorization gap
- Attackers can enumerate user IDs and access any user's private documents
- No field-level authorization on sensitive fields like `classification`

**SECURE VERSION**:

```go
package graph

import (
	"context"
	"database/sql"
	"errors"
	"log"

	"github.com/99designs/gqlgen/graphql"
	"myapp/graph/model"
)

var (
	ErrNotAuthenticated = errors.New("not authenticated")
	ErrNotAuthorized    = errors.New("not authorized to access this resource")
)

type Resolver struct {
	DB     *sql.DB
	Logger *log.Logger
}

// Authorization helper - checks resource access
func (r *Resolver) canAccessUser(ctx context.Context, targetUserID string) error {
	currentUser, ok := ctx.Value("user").(*model.User)
	if !ok || currentUser == nil {
		return ErrNotAuthenticated
	}

	// Users can only access their own data, unless admin
	if currentUser.ID != targetUserID && !currentUser.IsAdmin {
		r.Logger.Printf("AUTHZ_DENIED: user=%s attempted access to user=%s", 
			currentUser.ID, targetUserID)
		return ErrNotAuthorized
	}

	return nil
}

// Query resolver with proper authorization
func (r *queryResolver) User(ctx context.Context, id string) (*model.User, error) {
	// Check authorization BEFORE fetching data
	if err := r.canAccessUser(ctx, id); err != nil {
		return nil, err
	}

	var user model.User
	err := r.DB.QueryRow(
		"SELECT id, name, email FROM users WHERE id = $1",
		id,
	).Scan(&user.ID, &user.Name, &user.Email)

	if err == sql.ErrNoRows {
		return nil, errors.New("user not found")
	}
	return &user, err
}

// SECURE: Nested resolver with independent authorization check
func (r *userResolver) PrivateDocuments(ctx context.Context, obj *model.User) ([]*model.Document, error) {
	// CRITICAL: Re-check authorization at every resolver level
	if err := r.canAccessUser(ctx, obj.ID); err != nil {
		return nil, err
	}

	rows, err := r.DB.Query(
		"SELECT id, title, content, classification FROM documents WHERE owner_id = $1",
		obj.ID,
	)
	if err != nil {
		return nil, errors.New("failed to fetch documents")
	}
	defer rows.Close()

	var docs []*model.Document
	for rows.Next() {
		var doc model.Document
		if err := rows.Scan(&doc.ID, &doc.Title, &doc.Content, &doc.Classification); err != nil {
			continue
		}
		docs = append(docs, &doc)
	}
	return docs, nil
}
```

**Key Security Controls**:
- **Independent authorization at each resolver**: Every resolver performs its own authorization check, never trusting parent resolvers
- **Centralized authorization logic**: `canAccessUser()` helper ensures consistent policy enforcement
- **Audit logging**: Failed authorization attempts are logged with user context for security monitoring
- **Error message sanitization**: Generic errors returned to prevent information disclosure

Excellent questions! Production GraphQL APIs need multiple layers of defense: role-based access control (RBAC), field-level permissions, query complexity limits, and introspection controls. Here's a comprehensive production pattern.

**PRODUCTION PATTERN**:

```go
package graph

import (
	"context"
	"database/sql"
	"errors"
	"fmt"
	"log"
	"time"

	"github.com/99designs/gqlgen/graphql"
	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/extension"
	"github.com/vektah/gqlparser/v2/ast"
	"myapp/graph/model"
)

// Role definitions
type Role string

const (
	RoleUser    Role = "user"
	RoleManager Role = "manager"
	RoleAdmin   Role = "admin"
)

// Permission defines field-level access
type Permission struct {
	AllowedRoles []Role
	Condition    func(ctx context.Context, obj interface{}) bool
}

// FieldPermissions maps type.field to permissions
var FieldPermissions = map[string]Permission{
	"User.email": {
		AllowedRoles: []Role{RoleUser, RoleManager, RoleAdmin},
		Condition: func(ctx context.Context, obj interface{}) bool {
			// Users can see their own email, managers/admins can see all
			user := obj.(*model.User)
			current := GetCurrentUser(ctx)
			return current.ID == user.ID || hasRole(current, RoleManager, RoleAdmin)
		},
	},
	"User.ssn": {
		AllowedRoles: []Role{RoleAdmin},
		Condition:    nil, // Admin only, no additional condition
	},
	"Document.classification": {
		AllowedRoles: []Role{RoleManager, RoleAdmin},
		Condition:    nil,
	},
	"AuditLog.ipAddress": {
		AllowedRoles: []Role{RoleAdmin},
		Condition:    nil,
	},
}

// AuthorizationMiddleware implements field-level RBAC
type AuthorizationMiddleware struct {
	Logger *log.Logger
}

func (a *AuthorizationMiddleware) ExtensionName() string {
	return "AuthorizationMiddleware"
}

func (a *AuthorizationMiddleware) Validate(schema graphql.ExecutableSchema) error {
	return nil
}

func (a *AuthorizationMiddleware) InterceptField(ctx context.Context, next graphql.Resolver) (interface{}, error) {
	fc := graphql.GetFieldContext(ctx)
	fieldKey := fmt.Sprintf("%s.%s", fc.Object, fc.Field.Name)

	// Check field-level permissions
	perm, exists := FieldPermissions[fieldKey]
	if exists {
		currentUser := GetCurrentUser(ctx)
		if currentUser == nil {
			a.Logger.Printf("AUTHZ_FIELD_DENIED: anonymous access to %s", fieldKey)
			return nil, nil // Return null for unauthorized fields
		}

		// Check role-based access
		if !hasRole(currentUser, perm.AllowedRoles...) {
			a.Logger.Printf("AUTHZ_FIELD_DENIED: user=%s role=%s field=%s",
				currentUser.ID, currentUser.Role, fieldKey)
			return nil, nil // Return null instead of error to prevent enumeration
		}
	}

	// Execute resolver
	result, err := next(ctx)

	// Post-resolution condition check (for object-level conditions)
	if exists && perm.Condition != nil && result != nil {
		if !perm.Condition(ctx, result) {
			return nil, nil
		}
	}

	return result, err
}

// ComplexityLimitMiddleware prevents query depth/complexity attacks
type ComplexityLimitMiddleware struct {
	MaxComplexity int
	MaxDepth      int
	Logger        *log.Logger
}

func (c *ComplexityLimitMiddleware) ExtensionName() string {
	return "ComplexityLimit"
}

func (c *ComplexityLimitMiddleware) Validate(schema graphql.ExecutableSchema) error {
	return nil
}

func (c *ComplexityLimitMiddleware) MutateOperationContext(ctx context.Context, rc *graphql.OperationContext) *graphql.ResponseError {
	// Check query depth
	depth := calculateDepth(rc.Operation.SelectionSet, 0)
	if depth > c.MaxDepth {
		c.Logger.Printf("QUERY_DEPTH_EXCEEDED: depth=%d max=%d", depth, c.MaxDepth)
		return &graphql.ResponseError{
			Message: fmt.Sprintf("query depth %d exceeds maximum %d", depth, c.MaxDepth),
		}
	}
	return nil
}

func calculateDepth(selectionSet ast.SelectionSet, currentDepth int) int {
	maxDepth := currentDepth
	for _, selection := range selectionSet {
		if field, ok := selection.(*ast.Field); ok {
			if field.SelectionSet != nil {
				d := calculateDepth(field.SelectionSet, currentDepth+1)
				if d > maxDepth {
					maxDepth = d
				}
			}
		}
	}
	return maxDepth
}

// Secure resolver with comprehensive authorization
func (r *queryResolver) Users(ctx context.Context, filter *model.UserFilter) ([]*model.User, error) {
	currentUser := GetCurrentUser(ctx)
	if currentUser == nil {
		return nil, ErrNotAuthenticated
	}

	// Role-based query scope
	var query string
	var args []interface{}

	switch currentUser.Role {
	case string(RoleAdmin):
		// Admins can see all users
		query = "SELECT id, name, email, role, department FROM users WHERE 1=1"
	case string(RoleManager):
		// Managers can only see users in their department
		query = "SELECT id, name, email, role, department FROM users WHERE department = $1"
		args = append(args, currentUser.Department)
	default:
		// Regular users can only see themselves
		query = "SELECT id, name, email, role, department FROM users WHERE id = $1"
		args = append(args, currentUser.ID)
	}

	// Audit log the query
	r.Logger.Printf("AUTHZ_QUERY: user=%s role=%s action=list_users scope=%s",
		currentUser.ID, currentUser.Role, getQueryScope(currentUser))

	rows, err := r.DB.QueryContext(ctx, query, args...)
	if err != nil {
		return nil, errors.New("failed to fetch users")
	}
	defer rows.Close()

	var users []*model.User
	for rows.Next() {
		var user model.User
		if err := rows.Scan(&user.ID, &user.Name, &user.Email, &user.Role, &user.Department); err != nil {
			continue
		}
		users = append(users, &user)
	}
	return users, nil
}

// Helper functions
func GetCurrentUser(ctx context.Context) *model.User {
	user, ok := ctx.Value("user").(*model.User)
	if !ok {
		return nil
	}
	return user
}

func hasRole(user *model.User, roles ...Role) bool {
	for _, role := range roles {
		if Role(user.Role) == role {
			return true
		}
	}
	return false
}

func getQueryScope(user *model.User) string {
	switch Role(user.Role) {
	case RoleAdmin:
		return "global"
	case RoleManager:
		return "department:" + user.Department
	default:
		return "self"
	}
}

// Server setup with all protections
func NewGraphQLHandler(db *sql.DB, logger *log.Logger) *handler.Server {
	srv := handler.NewDefaultServer(NewExecutableSchema(Config{
		Resolvers: &Resolver{DB: db, Logger: logger},
	}))

	// Add authorization middleware
	srv.Use(&AuthorizationMiddleware{Logger: logger})

	// Add complexity limits
	srv.Use(&ComplexityLimitMiddleware{
		MaxComplexity: 200,
		MaxDepth:      10,
		Logger:        logger,
	})

	// Disable introspection in production
	if !isDevEnvironment() {
		srv.Use(extension.Introspection{})
	}

	// Add automatic persisted queries for production
	srv.Use(extension.AutomaticPersistedQuery{
		Cache: NewLRUCache(1000),
	})

	return srv
}

func isDevEnvironment() bool {
	// Check environment variable
	return false // Default to production-safe
}
```

**Defense in Depth Layers**:

1. **Query Complexity Limiting**:
```go
// Prevent resource exhaustion via deeply nested queries
func (c *ComplexityLimitMiddleware) MutateOperationContext(ctx context.Context, rc *graphql.OperationContext) *graphql.ResponseError {
    depth := calculateDepth(rc.Operation.SelectionSet, 0)
    if depth > c.MaxDepth {
        return &graphql.ResponseError{Message: "query too complex"}
    }
    return nil
}
```

2. **Field-Level Authorization**:
```go
// Null out sensitive fields for unauthorized users
if !hasRole(currentUser, perm.AllowedRoles...) {
    return nil, nil // Return null, not error (prevents enumeration)
}
```

3. **Query Scope Restriction**:
```go
// Automatically scope queries based on user role
switch currentUser.Role {
case "admin":
    query = "SELECT * FROM users" // Full access
case "manager":
    query = "SELECT * FROM users WHERE department = $1" // Department only
default:
    query = "SELECT * FROM users WHERE id = $1" // Self only
}
```

**Additional Protections**:
- **Introspection disabled in production**: Prevents attackers from discovering schema structure
- **Persisted queries**: Only allow pre-approved queries in production, blocking arbitrary query construction
- **Rate limiting per user/IP**: Prevent brute-force enumeration attacks
- **Audit logging**: Every authorization decision is logged with user context, action, and scope for SIEM integration
- **Null response for denied fields**: Returns null instead of errors to prevent field enumeration attacks
- **Context deadline enforcement**: Prevents long-running queries from exhausting server resources

Basic Authentication over HTTP is one of the most dangerous authentication patterns because credentials are transmitted in plaintext (Base64 is encoding, not encryption). This is trivially intercepted by anyone on the network path.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// DANGEROUS: Basic auth over HTTP
function basicAuth(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Basic ')) {
    res.setHeader('WWW-Authenticate', 'Basic realm="API"');
    return res.status(401).send('Authentication required');
  }

  // Base64 decode - this is NOT encryption!
  const base64Credentials = authHeader.split(' ')[1];
  const credentials = Buffer.from(base64Credentials, 'base64').toString('utf8');
  const [username, password] = credentials.split(':');

  // Direct string comparison - timing attack vulnerable
  if (username === 'admin' && password === 'secretpassword') {
    req.user = { username };
    return next();
  }

  res.status(401).send('Invalid credentials');
}

// HTTP server - credentials sent in cleartext!
app.get('/api/data', basicAuth, (req, res) => {
  res.json({ secret: 'sensitive data', user: req.user });
});

app.listen(3000, () => {
  console.log('Server running on http://localhost:3000');
});
```

**Attack Payload**:
```bash
# Intercept on same network with tcpdump
sudo tcpdump -i eth0 -A port 3000 | grep -i authorization

# Output shows cleartext credentials:
# Authorization: Basic YWRtaW46c2VjcmV0cGFzc3dvcmQ=
# Decode: echo 'YWRtaW46c2VjcmV0cGFzc3dvcmQ=' | base64 -d
# Result: admin:secretpassword
```

**Why This Is Dangerous**:
- Base64 is reversible encoding, not encryption - anyone can decode it instantly
- HTTP transmits data in plaintext across every network hop (WiFi, ISP, CDN)
- Hardcoded credentials in source code get leaked via git repos
- String comparison with `===` is vulnerable to timing attacks
- No rate limiting allows unlimited brute force attempts

**SECURE VERSION**:

```javascript
const express = require('express');
const https = require('https');
const fs = require('fs');
const crypto = require('crypto');
const bcrypt = require('bcrypt');

const app = express();

// Secure user store (in production, use a database)
const users = new Map();

async function initUsers() {
  // Store hashed passwords, never plaintext
  const hashedPassword = await bcrypt.hash(process.env.ADMIN_PASSWORD, 12);
  users.set('admin', { passwordHash: hashedPassword, role: 'admin' });
}

// Timing-safe string comparison
function safeCompare(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  const bufA = Buffer.from(a);
  const bufB = Buffer.from(b);
  if (bufA.length !== bufB.length) {
    crypto.timingSafeEqual(bufA, bufA); // Constant time even on length mismatch
    return false;
  }
  return crypto.timingSafeEqual(bufA, bufB);
}

async function secureBasicAuth(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Basic ')) {
    res.setHeader('WWW-Authenticate', 'Basic realm="Secure API"');
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const base64Credentials = authHeader.split(' ')[1];
    const credentials = Buffer.from(base64Credentials, 'base64').toString('utf8');
    const colonIndex = credentials.indexOf(':');

    if (colonIndex === -1) {
      return res.status(401).json({ error: 'Invalid credentials format' });
    }

    const username = credentials.substring(0, colonIndex);
    const password = credentials.substring(colonIndex + 1);

    const user = users.get(username);
    if (!user) {
      // Prevent username enumeration - still do bcrypt compare
      await bcrypt.compare(password, '$2b$12$invalidhashtopreventtiming');
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Secure password comparison
    const validPassword = await bcrypt.compare(password, user.passwordHash);
    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    req.user = { username, role: user.role };
    next();
  } catch (error) {
    console.error('Auth error:', error.message);
    res.status(500).json({ error: 'Authentication failed' });
  }
}

app.get('/api/data', secureBasicAuth, (req, res) => {
  res.json({ data: 'sensitive information', user: req.user.username });
});

// HTTPS server - credentials encrypted in transit
const httpsOptions = {
  key: fs.readFileSync(process.env.SSL_KEY_PATH),
  cert: fs.readFileSync(process.env.SSL_CERT_PATH)
};

initUsers().then(() => {
  https.createServer(httpsOptions, app).listen(443, () => {
    console.log('Secure server running on https://localhost:443');
  });
});
```

**Key Security Controls**:
- **HTTPS encryption**: All traffic including credentials encrypted with TLS, preventing MITM attacks
- **bcrypt password hashing**: Passwords stored securely with salt, computationally expensive to crack
- **Timing-safe comparison**: Prevents attackers from inferring valid usernames via response time differences
- **Environment variables**: Credentials never hardcoded in source code

Production authentication requires multiple defense layers: rate limiting, account lockout, comprehensive logging, and support for modern authentication standards like API keys and JWT tokens.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const https = require('https');
const fs = require('fs');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');
const jwt = require('jsonwebtoken');

const app = express();

// Security headers
app.use(helmet({
  strictTransportSecurity: { maxAge: 31536000, includeSubDomains: true, preload: true },
  contentSecurityPolicy: { directives: { defaultSrc: ["'self'"] } }
}));

// Structured logging for security events
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: '/var/log/app/security.log' }),
    new winston.transports.Console()
  ]
});

// Rate limiting - defense against brute force
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many authentication attempts, try again later' },
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    securityLogger.warn({
      event: 'rate_limit_exceeded',
      ip: req.ip,
      path: req.path,
      userAgent: req.get('User-Agent')
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});

// Account lockout tracking
const failedAttempts = new Map();
const LOCKOUT_THRESHOLD = 5;
const LOCKOUT_DURATION = 30 * 60 * 1000; // 30 minutes

function isAccountLocked(username) {
  const attempts = failedAttempts.get(username);
  if (!attempts) return false;
  if (attempts.count >= LOCKOUT_THRESHOLD) {
    if (Date.now() - attempts.lastAttempt < LOCKOUT_DURATION) {
      return true;
    }
    failedAttempts.delete(username); // Reset after lockout period
  }
  return false;
}

function recordFailedAttempt(username, ip) {
  const attempts = failedAttempts.get(username) || { count: 0, lastAttempt: 0 };
  attempts.count++;
  attempts.lastAttempt = Date.now();
  failedAttempts.set(username, attempts);

  securityLogger.warn({
    event: 'failed_login',
    username,
    ip,
    attemptCount: attempts.count,
    locked: attempts.count >= LOCKOUT_THRESHOLD
  });
}

function clearFailedAttempts(username) {
  failedAttempts.delete(username);
}

// Multi-method authentication middleware
class AuthenticationManager {
  constructor() {
    this.users = new Map();
    this.apiKeys = new Map();
    this.jwtSecret = process.env.JWT_SECRET;
  }

  async initialize() {
    // Load users from secure storage
    const adminHash = await bcrypt.hash(process.env.ADMIN_PASSWORD, 12);
    this.users.set('admin', { passwordHash: adminHash, role: 'admin' });

    // API keys for service accounts
    const apiKeyHash = crypto.createHash('sha256')
      .update(process.env.SERVICE_API_KEY)
      .digest('hex');
    this.apiKeys.set(apiKeyHash, { service: 'internal-service', role: 'service' });
  }

  middleware() {
    return async (req, res, next) => {
      const startTime = Date.now();

      try {
        // Check for JWT Bearer token first
        const authHeader = req.headers.authorization;

        if (authHeader?.startsWith('Bearer ')) {
          return this.authenticateJWT(req, res, next, authHeader);
        }

        // Check for API key
        const apiKey = req.headers['x-api-key'];
        if (apiKey) {
          return this.authenticateApiKey(req, res, next, apiKey);
        }

        // Fall back to Basic Auth
        if (authHeader?.startsWith('Basic ')) {
          return this.authenticateBasic(req, res, next, authHeader);
        }

        res.setHeader('WWW-Authenticate', 'Basic realm="API", Bearer');
        return res.status(401).json({ error: 'Authentication required' });

      } catch (error) {
        securityLogger.error({
          event: 'auth_error',
          error: error.message,
          ip: req.ip,
          duration: Date.now() - startTime
        });
        return res.status(500).json({ error: 'Authentication failed' });
      }
    };
  }

  async authenticateBasic(req, res, next, authHeader) {
    const base64Credentials = authHeader.split(' ')[1];
    const credentials = Buffer.from(base64Credentials, 'base64').toString('utf8');
    const colonIndex = credentials.indexOf(':');

    if (colonIndex === -1) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const username = credentials.substring(0, colonIndex);
    const password = credentials.substring(colonIndex + 1);

    // Check account lockout
    if (isAccountLocked(username)) {
      securityLogger.warn({ event: 'locked_account_attempt', username, ip: req.ip });
      return res.status(423).json({ error: 'Account temporarily locked' });
    }

    const user = this.users.get(username);
    if (!user) {
      await bcrypt.compare(password, '$2b$12$invalidhashtopreventtiming');
      recordFailedAttempt(username, req.ip);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);
    if (!validPassword) {
      recordFailedAttempt(username, req.ip);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    clearFailedAttempts(username);
    securityLogger.info({ event: 'successful_login', username, ip: req.ip, method: 'basic' });

    req.user = { username, role: user.role, authMethod: 'basic' };
    next();
  }

  authenticateApiKey(req, res, next, apiKey) {
    const keyHash = crypto.createHash('sha256').update(apiKey).digest('hex');
    const service = this.apiKeys.get(keyHash);

    if (!service) {
      securityLogger.warn({ event: 'invalid_api_key', ip: req.ip });
      return res.status(401).json({ error: 'Invalid API key' });
    }

    securityLogger.info({ event: 'api_key_auth', service: service.service, ip: req.ip });
    req.user = { service: service.service, role: service.role, authMethod: 'apikey' };
    next();
  }

  authenticateJWT(req, res, next, authHeader) {
    const token = authHeader.split(' ')[1];

    try {
      const decoded = jwt.verify(token, this.jwtSecret, {
        algorithms: ['HS256'],
        maxAge: '1h'
      });

      securityLogger.info({ event: 'jwt_auth', username: decoded.sub, ip: req.ip });
      req.user = { username: decoded.sub, role: decoded.role, authMethod: 'jwt' };
      next();
    } catch (error) {
      securityLogger.warn({ event: 'invalid_jwt', error: error.message, ip: req.ip });
      return res.status(401).json({ error: 'Invalid or expired token' });
    }
  }
}

const authManager = new AuthenticationManager();

// Apply rate limiting to auth endpoints
app.use('/api', authLimiter);

// Protected routes
app.get('/api/data', authManager.middleware(), (req, res) => {
  res.json({
    data: 'sensitive information',
    user: req.user.username || req.user.service,
    authMethod: req.user.authMethod
  });
});

// Token endpoint for JWT issuance
app.post('/api/token', authLimiter, authManager.middleware(), (req, res) => {
  const token = jwt.sign(
    { sub: req.user.username, role: req.user.role },
    process.env.JWT_SECRET,
    { algorithm: 'HS256', expiresIn: '1h' }
  );
  res.json({ token, expiresIn: 3600 });
});

// Health check (no auth required)
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

// HTTPS configuration
const httpsOptions = {
  key: fs.readFileSync(process.env.SSL_KEY_PATH),
  cert: fs.readFileSync(process.env.SSL_CERT_PATH),
  minVersion: 'TLSv1.2',
  ciphers: 'ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256'
};

authManager.initialize().then(() => {
  https.createServer(httpsOptions, app).listen(443, () => {
    securityLogger.info({ event: 'server_started', port: 443 });
  });
});
```

**Defense in Depth Layers**:

1. **Transport Layer Security**:
```javascript
// Force HTTPS and modern TLS
const httpsOptions = {
  minVersion: 'TLSv1.2',
  ciphers: 'ECDHE-ECDSA-AES128-GCM-SHA256:ECDHE-RSA-AES128-GCM-SHA256'
};
app.use(helmet.hsts({ maxAge: 31536000, includeSubDomains: true }));
```

2. **Rate Limiting and Account Lockout**:
```javascript
// Progressive lockout increases attacker cost exponentially
const authLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 5 });
if (failedAttempts >= LOCKOUT_THRESHOLD) {
  return res.status(423).json({ error: 'Account temporarily locked' });
}
```

3. **Security Event Monitoring**:
```javascript
// All auth events logged for SIEM integration
securityLogger.warn({
  event: 'failed_login',
  username,
  ip: req.ip,
  attemptCount: attempts.count,
  timestamp: new Date().toISOString()
});
```

**Additional Protections**:
- **HSTS Preloading**: Browser will never connect over HTTP, preventing SSL stripping attacks
- **API Key Hashing**: Keys stored as SHA-256 hashes, never plaintext, preventing theft from database compromise
- **JWT with Short Expiry**: Tokens expire in 1 hour, limiting exposure window if stolen
- **Constant-Time Operations**: All credential comparisons use timing-safe functions to prevent side-channel attacks
- **Username Enumeration Prevention**: Failed logins for non-existent users have identical timing to real users

Managing PHP dependencies securely is critical because vulnerable packages are a top attack vector. In 2023, attackers continued exploiting CVE-2016-10033 in PHPMailer on legacy Drupal sites, achieving remote code execution on servers that hadn't updated dependencies.

**VULNERABLE CODE**:

```php
<?php
// composer.json with dangerously outdated dependencies
// {
//   "require": {
//     "phpmailer/phpmailer": "5.2.16",
//     "guzzlehttp/guzzle": "6.3.0",
//     "monolog/monolog": "1.22.0"
//   }
// }

require 'vendor/autoload.php';

use PHPMailer\PHPMailer\PHPMailer;

class ContactForm {
    public function sendEmail($fromEmail, $fromName, $message) {
        $mail = new PHPMailer();

        // VULNERABLE: User input directly in setFrom without validation
        // PHPMailer 5.2.16 has CVE-2016-10033 RCE vulnerability
        $mail->setFrom($fromEmail, $fromName);
        $mail->addAddress('admin@example.com');
        $mail->Subject = 'Contact Form Submission';
        $mail->Body = $message;

        // No validation, no version checking
        if (!$mail->send()) {
            return "Message could not be sent";
        }
        return "Message sent successfully";
    }
}

// Usage with user input
$form = new ContactForm();
$result = $form->sendEmail(
    $_POST['email'],  // Attacker-controlled input
    $_POST['name'],
    $_POST['message']
);
echo $result;
```

**Attack Payload**:
```text
POST /contact.php HTTP/1.1
Content-Type: application/x-www-form-urlencoded

email="attacker\" -oQ/tmp/ -X/var/www/html/shell.php some"@email.com&name=Test&message=<?php system($_GET['cmd']); ?>
```

**Why This Is Dangerous**:
- PHPMailer 5.2.16 contains CVE-2016-10033 allowing shell command injection via email parameters
- User input is passed directly to mail functions without sanitization
- No dependency version constraints allow installation of vulnerable versions
- No security auditing process to detect known vulnerabilities
- Attackers can execute arbitrary system commands on the server

**SECURE VERSION**:

```php
<?php
// secure-composer.json with pinned, audited versions
// {
//   "require": {
//     "phpmailer/phpmailer": "^6.8",
//     "guzzlehttp/guzzle": "^7.8",
//     "monolog/monolog": "^3.5"
//   },
//   "config": {
//     "allow-plugins": false,
//     "audit": {
//       "abandoned": "report"
//     }
//   },
//   "scripts": {
//     "post-install-cmd": "@composer audit",
//     "post-update-cmd": "@composer audit"
//   }
// }

require 'vendor/autoload.php';

use PHPMailer\PHPMailer\PHPMailer;
use PHPMailer\PHPMailer\SMTP;
use PHPMailer\PHPMailer\Exception;

class SecureContactForm {
    private PHPMailer $mail;
    private array $allowedDomains = ['gmail.com', 'outlook.com', 'yahoo.com'];

    public function __construct() {
        $this->mail = new PHPMailer(true);
        $this->mail->isSMTP();
        $this->mail->Host = getenv('SMTP_HOST');
        $this->mail->SMTPAuth = true;
        $this->mail->Username = getenv('SMTP_USER');
        $this->mail->Password = getenv('SMTP_PASS');
        $this->mail->SMTPSecure = PHPMailer::ENCRYPTION_STARTTLS;
        $this->mail->Port = 587;
    }

    public function sendEmail(string $fromEmail, string $fromName, string $message): array {
        // Input validation - email format
        if (!filter_var($fromEmail, FILTER_VALIDATE_EMAIL)) {
            error_log("Invalid email format attempted: " . substr($fromEmail, 0, 50));
            return ['success' => false, 'error' => 'Invalid email format'];
        }

        // Sanitize name - remove any shell metacharacters
        $safeName = preg_replace('/[^a-zA-Z0-9\s\-]/', '', $fromName);
        if (strlen($safeName) > 100) {
            $safeName = substr($safeName, 0, 100);
        }

        // Sanitize message
        $safeMessage = htmlspecialchars($message, ENT_QUOTES, 'UTF-8');

        try {
            // Use fixed sender, put user email in Reply-To
            $this->mail->setFrom(getenv('MAIL_FROM'), 'Contact Form');
            $this->mail->addReplyTo($fromEmail, $safeName);
            $this->mail->addAddress(getenv('ADMIN_EMAIL'));
            $this->mail->Subject = 'Contact Form: ' . substr($safeName, 0, 50);
            $this->mail->Body = "From: {$safeName} <{$fromEmail}>\n\n{$safeMessage}";
            $this->mail->isHTML(false);

            $this->mail->send();
            error_log("Contact form sent from: {$fromEmail}");
            return ['success' => true, 'message' => 'Message sent successfully'];

        } catch (Exception $e) {
            error_log("Mail error: " . $this->mail->ErrorInfo);
            return ['success' => false, 'error' => 'Message could not be sent'];
        }
    }
}
```

**Key Security Controls**:
- **Version pinning with caret (^)**: Allows patch updates but prevents major version changes that might introduce breaking changes
- **Composer audit integration**: Automatically checks for known vulnerabilities on install/update
- **Input validation**: Strict email format validation using filter_var() before processing
- **Fixed sender address**: User email goes in Reply-To, not From, preventing injection attacks
- **Character sanitization**: Removes shell metacharacters from user input
- **SMTP mode**: Uses authenticated SMTP instead of PHP mail() function, eliminating the vulnerable code path

Automated dependency scanning is essential because transitive dependencies (dependencies of your dependencies) often contain vulnerabilities that are easy to miss. In 2024, the Guzzle SSRF vulnerability (CVE-2022-29248) continued affecting applications through nested package dependencies.

**PRODUCTION PATTERN**:

```php
<?php
// composer.json - production security configuration
// {
//   "name": "myapp/secure-application",
//   "require": {
//     "php": ">=8.2",
//     "phpmailer/phpmailer": "^6.9.1",
//     "guzzlehttp/guzzle": "^7.8.1",
//     "monolog/monolog": "^3.5.0",
//     "symfony/security-bundle": "^7.0"
//   },
//   "require-dev": {
//     "roave/security-advisories": "dev-latest",
//     "enlightn/security-checker": "^2.0"
//   },
//   "config": {
//     "allow-plugins": {
//       "php-http/discovery": false
//     },
//     "audit": {
//       "abandoned": "fail"
//     },
//     "preferred-install": "dist",
//     "sort-packages": true,
//     "optimize-autoloader": true
//   },
//   "extra": {
//     "composer-exit-on-patch-failure": true
//   }
// }

namespace App\Security;

use Monolog\Logger;
use Monolog\Handler\StreamHandler;
use Monolog\Handler\SlackWebhookHandler;

class DependencySecurityManager {
    private Logger $logger;
    private string $projectRoot;
    private array $config;

    public function __construct(string $projectRoot) {
        $this->projectRoot = $projectRoot;
        $this->logger = new Logger('security');
        $this->logger->pushHandler(new StreamHandler('/var/log/app/security.log', Logger::WARNING));

        // Alert on critical findings
        if (getenv('SLACK_WEBHOOK')) {
            $this->logger->pushHandler(new SlackWebhookHandler(
                getenv('SLACK_WEBHOOK'),
                '#security-alerts',
                'SecurityBot',
                true,
                ':shield:',
                false,
                false,
                Logger::CRITICAL
            ));
        }

        $this->config = [
            'max_age_days' => 90,
            'allowed_severity' => ['low'],
            'block_on' => ['critical', 'high', 'medium']
        ];
    }

    public function runSecurityAudit(): array {
        $results = [
            'timestamp' => date('c'),
            'status' => 'pass',
            'vulnerabilities' => [],
            'outdated' => [],
            'abandoned' => []
        ];

        // Run composer audit
        $auditOutput = $this->runComposerAudit();
        if (!empty($auditOutput['advisories'])) {
            foreach ($auditOutput['advisories'] as $package => $advisories) {
                foreach ($advisories as $advisory) {
                    $vuln = [
                        'package' => $package,
                        'cve' => $advisory['cve'] ?? 'N/A',
                        'title' => $advisory['title'],
                        'severity' => $this->normalizeSeverity($advisory),
                        'affected_versions' => $advisory['affectedVersions'],
                        'link' => $advisory['link'] ?? ''
                    ];

                    $results['vulnerabilities'][] = $vuln;

                    if (in_array($vuln['severity'], $this->config['block_on'])) {
                        $results['status'] = 'fail';
                        $this->logger->critical('Critical vulnerability found', $vuln);
                    }
                }
            }
        }

        // Check for outdated packages
        $outdatedPackages = $this->checkOutdatedPackages();
        foreach ($outdatedPackages as $package) {
            if ($package['age_days'] > $this->config['max_age_days']) {
                $results['outdated'][] = $package;
                $this->logger->warning('Outdated package detected', $package);
            }
        }

        // Check transitive dependencies
        $transitiveVulns = $this->scanTransitiveDependencies();
        $results['transitive_vulnerabilities'] = $transitiveVulns;

        if (!empty($transitiveVulns)) {
            $results['status'] = 'warning';
            $this->logger->warning('Transitive dependency vulnerabilities', [
                'count' => count($transitiveVulns)
            ]);
        }

        return $results;
    }

    private function runComposerAudit(): array {
        $lockFile = $this->projectRoot . '/composer.lock';
        if (!file_exists($lockFile)) {
            throw new \RuntimeException('composer.lock not found');
        }

        $cmd = sprintf(
            'cd %s && composer audit --format=json 2>/dev/null',
            escapeshellarg($this->projectRoot)
        );

        $output = shell_exec($cmd);
        return json_decode($output, true) ?? ['advisories' => []];
    }

    private function checkOutdatedPackages(): array {
        $cmd = sprintf(
            'cd %s && composer outdated --format=json 2>/dev/null',
            escapeshellarg($this->projectRoot)
        );

        $output = shell_exec($cmd);
        $data = json_decode($output, true) ?? ['installed' => []];

        $outdated = [];
        foreach ($data['installed'] ?? [] as $package) {
            $outdated[] = [
                'name' => $package['name'],
                'current' => $package['version'],
                'latest' => $package['latest'],
                'age_days' => $this->calculatePackageAge($package)
            ];
        }

        return $outdated;
    }

    private function scanTransitiveDependencies(): array {
        $lockFile = $this->projectRoot . '/composer.lock';
        $lockData = json_decode(file_get_contents($lockFile), true);

        $directDeps = $this->getDirectDependencies();
        $vulnerabilities = [];

        foreach ($lockData['packages'] ?? [] as $package) {
            // Skip direct dependencies (already scanned)
            if (in_array($package['name'], $directDeps)) {
                continue;
            }

            // Check against local advisories database
            $vulns = $this->checkPackageVulnerabilities(
                $package['name'],
                $package['version']
            );

            if (!empty($vulns)) {
                $vulnerabilities[] = [
                    'package' => $package['name'],
                    'version' => $package['version'],
                    'required_by' => $this->findRequirer($package['name'], $lockData),
                    'vulnerabilities' => $vulns
                ];
            }
        }

        return $vulnerabilities;
    }

    private function getDirectDependencies(): array {
        $composerJson = $this->projectRoot . '/composer.json';
        $data = json_decode(file_get_contents($composerJson), true);
        return array_keys($data['require'] ?? []);
    }

    private function findRequirer(string $packageName, array $lockData): string {
        foreach ($lockData['packages'] ?? [] as $package) {
            $requires = $package['require'] ?? [];
            if (isset($requires[$packageName])) {
                return $package['name'];
            }
        }
        return 'unknown';
    }

    private function checkPackageVulnerabilities(string $name, string $version): array {
        // Integration with security advisories API
        // In production, use Packagist Security API or local database
        $url = "https://packagist.org/api/security-advisories/?packages[]={$name}";

        $context = stream_context_create([
            'http' => [
                'timeout' => 5,
                'user_agent' => 'SecurityScanner/1.0'
            ]
        ]);

        $response = @file_get_contents($url, false, $context);
        if ($response === false) {
            return [];
        }

        $data = json_decode($response, true);
        return $data['advisories'][$name] ?? [];
    }

    private function normalizeSeverity(array $advisory): string {
        $cvss = $advisory['cvss']['score'] ?? 0;
        if ($cvss >= 9.0) return 'critical';
        if ($cvss >= 7.0) return 'high';
        if ($cvss >= 4.0) return 'medium';
        return 'low';
    }

    private function calculatePackageAge(array $package): int {
        // Simplified age calculation
        return 30; // Would calculate from release dates
    }

    public function generateSBOM(): array {
        // Software Bill of Materials for compliance
        $lockFile = $this->projectRoot . '/composer.lock';
        $lockData = json_decode(file_get_contents($lockFile), true);

        $sbom = [
            'bomFormat' => 'CycloneDX',
            'specVersion' => '1.4',
            'version' => 1,
            'metadata' => [
                'timestamp' => date('c'),
                'tools' => [['name' => 'DependencySecurityManager', 'version' => '1.0']]
            ],
            'components' => []
        ];

        foreach ($lockData['packages'] ?? [] as $package) {
            $sbom['components'][] = [
                'type' => 'library',
                'name' => $package['name'],
                'version' => $package['version'],
                'purl' => "pkg:composer/{$package['name']}@{$package['version']}",
                'licenses' => $package['license'] ?? []
            ];
        }

        return $sbom;
    }
}
