```

**Attack Payload**:
```bash
# Attacker enumerates all accounts by incrementing ID
for i in $(seq 1 10000); do
    curl -s "https://api.example.com/get_account.php?account_id=$i" >> stolen_data.json
    sleep 0.1
done
```

**Why This Is Dangerous**:
- No verification that the requesting user owns the account
- Sensitive data (SSN, balance) exposed to any requester
- Sequential IDs make enumeration trivial (IDOR vulnerability)
- This exact pattern caused the Optus breach affecting 9.8M customers

**SECURE VERSION**:

```php
<?php
// api/get_account.php - SECURE: Proper authorization
require_once 'config.php';
require_once 'auth.php';

header('Content-Type: application/json');

// SECURITY CONTROL 1: Require authentication
session_start();
if (!isset($_SESSION['user_id']) || !validateSession($_SESSION)) {
    http_response_code(401);
    echo json_encode(['error' => 'Authentication required']);
    exit;
}

$requestedAccountId = $_GET['account_id'] ?? null;
$currentUserId = $_SESSION['user_id'];

if (!$requestedAccountId || !ctype_digit($requestedAccountId)) {
    http_response_code(400);
    echo json_encode(['error' => 'Valid account ID required']);
    exit;
}

try {
    $pdo = new PDO($dsn, $dbUser, $dbPass);
    $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);

    // SECURITY CONTROL 2: Authorization check - user must own the account
    $stmt = $pdo->prepare("
        SELECT a.id, a.name, a.email, a.address, a.phone, a.balance 
        FROM accounts a 
        WHERE a.id = ? AND a.user_id = ?
    ");
    $stmt->execute([$requestedAccountId, $currentUserId]);
    $account = $stmt->fetch(PDO::FETCH_ASSOC);

    if ($account) {
        // SECURITY CONTROL 3: Audit logging
        logAccess($currentUserId, 'account_view', $requestedAccountId, 'success');
        echo json_encode($account);
    } else {
        // SECURITY CONTROL 4: Log potential IDOR attempt
        logAccess($currentUserId, 'account_view', $requestedAccountId, 'denied');
        http_response_code(404);
        echo json_encode(['error' => 'Account not found']);
    }
} catch (PDOException $e) {
    error_log("Database error: " . $e->getMessage());
    http_response_code(500);
    echo json_encode(['error' => 'Internal server error']);
}
```

**Key Security Controls**:
- **Authentication check**: Verifies user is logged in before processing any request
- **Authorization check**: SQL query includes `user_id = ?` to ensure user can only access their own data
- **Input validation**: `ctype_digit()` ensures account ID is numeric
- **Audit logging**: Records both successful access and denied attempts for monitoring

Excellent question - role-based access control (RBAC) requires careful implementation to avoid privilege escalation vulnerabilities while still allowing legitimate administrative access.

**PRODUCTION PATTERN**:

```php
<?php
// lib/AuthorizationService.php - Production RBAC Implementation

class AuthorizationService {
    private PDO $pdo;
    private ?array $currentUser = null;
    private array $userPermissions = [];

    // Define permission constants
    const PERM_VIEW_OWN_ACCOUNT = 'account:view:own';
    const PERM_VIEW_ANY_ACCOUNT = 'account:view:any';
    const PERM_EDIT_OWN_ACCOUNT = 'account:edit:own';
    const PERM_EDIT_ANY_ACCOUNT = 'account:edit:any';
    const PERM_VIEW_SENSITIVE_DATA = 'account:view:sensitive';

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function loadUser(int $userId): bool {
        $stmt = $this->pdo->prepare("
            SELECT u.id, u.email, u.role, u.is_active, u.mfa_enabled
            FROM users u 
            WHERE u.id = ? AND u.is_active = 1
        ");
        $stmt->execute([$userId]);
        $this->currentUser = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($this->currentUser) {
            $this->loadPermissions();
            return true;
        }
        return false;
    }

    private function loadPermissions(): void {
        $stmt = $this->pdo->prepare("
            SELECT p.permission_name 
            FROM permissions p
            INNER JOIN role_permissions rp ON p.id = rp.permission_id
            INNER JOIN roles r ON rp.role_id = r.id
            WHERE r.name = ?
        ");
        $stmt->execute([$this->currentUser['role']]);
        $this->userPermissions = $stmt->fetchAll(PDO::FETCH_COLUMN);
    }

    public function hasPermission(string $permission): bool {
        return in_array($permission, $this->userPermissions, true);
    }

    public function canAccessAccount(int $accountId): bool {
        // Check if user has permission to view any account
        if ($this->hasPermission(self::PERM_VIEW_ANY_ACCOUNT)) {
            return true;
        }

        // Check if user has permission to view own account
        if ($this->hasPermission(self::PERM_VIEW_OWN_ACCOUNT)) {
            return $this->ownsAccount($accountId);
        }

        return false;
    }

    private function ownsAccount(int $accountId): bool {
        $stmt = $this->pdo->prepare("
            SELECT 1 FROM accounts WHERE id = ? AND user_id = ?
        ");
        $stmt->execute([$accountId, $this->currentUser['id']]);
        return $stmt->fetch() !== false;
    }

    public function getCurrentUserId(): ?int {
        return $this->currentUser['id'] ?? null;
    }

    public function getCurrentUserRole(): ?string {
        return $this->currentUser['role'] ?? null;
    }
}
```

```php
<?php
// api/get_account.php - Production endpoint with RBAC

require_once __DIR__ . '/../vendor/autoload.php';
require_once __DIR__ . '/../lib/AuthorizationService.php';
require_once __DIR__ . '/../lib/AuditLogger.php';
require_once __DIR__ . '/../lib/RateLimiter.php';

