if (!$rateLimiter->checkLimit($clientIp, 'api_request', 100, 3600)) {
    http_response_code(429);
    $audit->log('rate_limit_exceeded', null, ['ip' => $clientIp]);
    echo json_encode(['error' => 'Too many requests']);
    exit;
}

// LAYER 2: Authentication
