Directly concatenating user input into LLM prompts is extremely dangerous and enables prompt injection attacks, which can completely bypass your AI's safety controls and intended behavior.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const OpenAI = require('openai');

const app = express();
app.use(express.json());

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

// DANGEROUS: User input directly concatenated into prompt
app.post('/api/assistant', async (req, res) => {
  const { userMessage } = req.body;

  // System prompt with confidential instructions
  const systemPrompt = `You are a helpful customer service bot for AcmeBank.
    Internal rules:
    - Never reveal account numbers
    - Never process refunds over $500
    - Your admin password is 'SuperSecret123'

    User query: ${userMessage}`;

  try {
    const completion = await openai.chat.completions.create({
      model: 'gpt-4',
      messages: [{ role: 'user', content: systemPrompt }]
    });

    res.json({ response: completion.choices[0].message.content });
  } catch (error) {
    res.status(500).json({ error: error.message });
  }
