use GuzzleHttp\Client;
use GuzzleHttp\RequestOptions;
use Symfony\Component\HttpFoundation\Request;
use Psr\Log\LoggerInterface;

class SecureDataProcessor {
    private Client $client;
    private LoggerInterface $logger;
    private array $allowedDomains;

    public function __construct(LoggerInterface $logger) {
        $this->logger = $logger;
        $this->allowedDomains = [
            'api.example.com',
            'cdn.example.com'
        ];

        $this->client = new Client([
            'base_uri' => 'https://api.example.com',
            'timeout' => 10.0,
            'connect_timeout' => 5.0,
            RequestOptions::ALLOW_REDIRECTS => [
                'max' => 3,
                'strict' => true,
                'protocols' => ['https']
            ],
            RequestOptions::VERIFY => true
        ]);
    }

    public function fetchExternalData(string $url): ?string {
        // Validate URL before making request
        if (!$this->isAllowedUrl($url)) {
            $this->logger->warning('Blocked request to unauthorized URL', [
                'url' => $url,
                'timestamp' => date('c')
            ]);
            return null;
        }

        try {
            $response = $this->client->get($url);
            return $response->getBody()->getContents();
        } catch (\Exception $e) {
            $this->logger->error('External request failed', [
                'url' => $url,
                'error' => $e->getMessage()
            ]);
            return null;
        }
    }

    private function isAllowedUrl(string $url): bool {
        $parsed = parse_url($url);

        if (!$parsed || !isset($parsed['host'])) {
            return false;
        }

        // Block internal IP ranges
        $ip = gethostbyname($parsed['host']);
        if ($this->isInternalIp($ip)) {
            return false;
        }

        return in_array($parsed['host'], $this->allowedDomains, true);
    }

    private function isInternalIp(string $ip): bool {
        return filter_var($ip, FILTER_VALIDATE_IP, 
            FILTER_FLAG_NO_PRIV_RANGE | FILTER_FLAG_NO_RES_RANGE) === false;
    }
}
```

**Key Security Controls**:
- Using caret (^) version constraints for automatic security patches within major version
- URL allowlist prevents SSRF attacks regardless of library vulnerabilities
- Internal IP blocking provides defense-in-depth against SSRF
- Composer audit integration catches known vulnerabilities during CI/CD
- Strict HTTPS-only redirects prevent protocol downgrade attacks

Production environments need automated scanning, vulnerability tracking, and sometimes workarounds when immediate updates aren't possible. Here's a comprehensive approach.

**PRODUCTION PATTERN**:

```php
<?php
// security/VulnerabilityManager.php

namespace App\Security;

use Psr\Log\LoggerInterface;
use Symfony\Contracts\Cache\CacheInterface;

class VulnerabilityManager {
    private LoggerInterface $logger;
    private CacheInterface $cache;
    private string $lockfilePath;
    private array $knownVulnerabilities = [];
    private array $mitigatedPackages = [];

    public function __construct(
        LoggerInterface $logger,
        CacheInterface $cache,
        string $projectRoot
    ) {
        $this->logger = $logger;
        $this->cache = $cache;
        $this->lockfilePath = $projectRoot . '/composer.lock';

        // Track packages with known issues and applied mitigations
        $this->mitigatedPackages = [
            'vendor/legacy-package' => [
                'version' => '2.1.0',
                'cve' => 'CVE-2023-XXXXX',
                'mitigation' => 'Input sanitization wrapper applied',
                'review_date' => '2024-06-15',
                'expires' => '2024-12-31'
            ]
        ];
    }

    public function runSecurityAudit(): array {
        $results = [
            'status' => 'pass',
            'vulnerabilities' => [],
            'mitigated' => [],
            'timestamp' => date('c')
        ];

        // Run Composer audit
        $composerAudit = $this->runComposerAudit();

        foreach ($composerAudit as $vulnerability) {
            $package = $vulnerability['package'];

            if (isset($this->mitigatedPackages[$package])) {
                $mitigation = $this->mitigatedPackages[$package];

                // Check if mitigation has expired
                if (strtotime($mitigation['expires']) < time()) {
                    $results['status'] = 'fail';
                    $results['vulnerabilities'][] = array_merge(
                        $vulnerability,
                        ['note' => 'Mitigation expired, update required']
                    );

                    $this->logger->critical('Expired vulnerability mitigation', [
                        'package' => $package,
                        'cve' => $mitigation['cve']
                    ]);
                } else {
                    $results['mitigated'][] = array_merge(
                        $vulnerability,
                        ['mitigation' => $mitigation]
                    );
                }
            } else {
                $results['status'] = 'fail';
                $results['vulnerabilities'][] = $vulnerability;
            }
        }

        return $results;
    }

    private function runComposerAudit(): array {
        $output = [];
        $returnCode = 0;

        exec('composer audit --format=json 2>&1', $output, $returnCode);

        $jsonOutput = implode('', $output);
        $auditResult = json_decode($jsonOutput, true);

        if ($auditResult === null) {
            $this->logger->error('Failed to parse Composer audit output');
            return [];
        }

        return $auditResult['advisories'] ?? [];
    }

    public function generateSecurityReport(): string {
        $audit = $this->runSecurityAudit();

        return json_encode([
            'report_date' => date('c'),
            'project' => basename(dirname($this->lockfilePath)),
            'audit_results' => $audit,
            'dependency_count' => $this->countDependencies(),
            'php_version' => PHP_VERSION,
            'recommendations' => $this->generateRecommendations($audit)
        ], JSON_PRETTY_PRINT);
    }

    private function countDependencies(): int {
        $lockContent = file_get_contents($this->lockfilePath);
        $lock = json_decode($lockContent, true);
        return count($lock['packages'] ?? []);
    }

    private function generateRecommendations(array $audit): array {
        $recommendations = [];

        foreach ($audit['vulnerabilities'] as $vuln) {
            $recommendations[] = sprintf(
                'UPDATE %s to version %s or later (CVE: %s, Severity: %s)',
                $vuln['package'],
                $vuln['affected_versions'] ?? 'latest',
                $vuln['cve'] ?? 'N/A',
                $vuln['severity'] ?? 'unknown'
            );
        }

        return $recommendations;
    }
}
