<?php
// security/DependencyWrapper.php - Mitigation wrapper for vulnerable packages

namespace App\Security;

use Psr\Log\LoggerInterface;

/**
 * Wrapper to mitigate vulnerabilities in packages that cannot be immediately updated
 * Document all mitigations and set expiration dates for forced review
 */
class DependencyWrapper {
    private LoggerInterface $logger;
    private $wrappedService;

    public function __construct($vulnerableService, LoggerInterface $logger) {
        $this->wrappedService = $vulnerableService;
        $this->logger = $logger;
    }

    /**
     * Wrap vulnerable XML parsing with XXE prevention
     * Mitigates: CVE-2023-3823 and similar XML injection vulnerabilities
     */
    public function safeXmlParse(string $xmlContent): ?\SimpleXMLElement {
        // Disable external entity loading before any XML operation
        $previousValue = libxml_disable_entity_loader(true);
        libxml_use_internal_errors(true);

        // Additional sanitization - remove DOCTYPE declarations
        $xmlContent = preg_replace('/<!DOCTYPE[^>]*>/i', '', $xmlContent);

        // Validate XML structure before parsing
        if (!$this->isValidXmlStructure($xmlContent)) {
            $this->logger->warning('Invalid XML structure rejected', [
                'content_length' => strlen($xmlContent)
            ]);
            return null;
        }

        try {
            $xml = simplexml_load_string(
                $xmlContent,
                'SimpleXMLElement',
                LIBXML_NONET | LIBXML_NOENT | LIBXML_NOCDATA
            );

            if ($xml === false) {
                $errors = libxml_get_errors();
                libxml_clear_errors();
                $this->logger->error('XML parsing failed', ['errors' => $errors]);
                return null;
            }

            return $xml;
        } finally {
            libxml_disable_entity_loader($previousValue);
        }
    }

    private function isValidXmlStructure(string $content): bool {
        // Block potential XXE payloads
        $dangerousPatterns = [
            '/<!ENTITY/i',
            '/SYSTEM\s+["\']/',
            '/PUBLIC\s+["\']/',
            '/file:\/\//i',
            '/expect:\/\//i',
            '/php:\/\//i'
        ];

        foreach ($dangerousPatterns as $pattern) {
            if (preg_match($pattern, $content)) {
                return false;
            }
        }

        return true;
    }

    /**
     * Wrap vulnerable serialization with safe alternatives
     * Mitigates: PHP object injection vulnerabilities
     */
    public function safeUnserialize(string $data): mixed {
        // Never unserialize untrusted data - use JSON instead
        $decoded = json_decode($data, true);

        if (json_last_error() !== JSON_ERROR_NONE) {
            $this->logger->error('Failed to decode data', [
                'error' => json_last_error_msg()
            ]);
            return null;
        }

        return $decoded;
    }
}
