**Key Security Controls**:
- **Pinned versions**: Use caret (`^`) for controlled major version updates
- **Security advisories**: `roave/security-advisories` blocks known vulnerable packages
- **Stable only**: `minimum-stability: stable` prevents dev package installation
- **Environment isolation**: Debug disabled by default, explicitly enabled only in dev

Great questions! Transitive dependencies are often the source of critical vulnerabilities. In 2023, the PHPUnit vulnerability (CVE-2023-32659) affected applications through nested dependencies. Here's a production-ready CI/CD security pipeline:

**PRODUCTION PATTERN**:

```yaml
# .github/workflows/security.yml - GitHub Actions pipeline
name: Dependency Security Scan

on:
  push:
    branches: [main, develop]
  pull_request:
    branches: [main]
  schedule:
    - cron: '0 6 * * *'  # Daily at 6 AM UTC

jobs:
  composer-audit:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Setup PHP
        uses: shivammathur/setup-php@v2
        with:
          php-version: '8.2'
          tools: composer:v2

      - name: Composer Audit
        run: |
          composer audit --format=json > audit-report.json
          if [ $(jq '.advisories | length' audit-report.json) -gt 0 ]; then
            echo "CRITICAL: Vulnerabilities detected!"
            jq '.advisories' audit-report.json
            exit 1
          fi

      - name: Check Outdated Packages
        run: |
          composer outdated --direct --format=json > outdated.json
          CRITICAL=$(jq '[.installed[] | select(."latest-status" == "semver-safe-update")] | length' outdated.json)
          if [ $CRITICAL -gt 0 ]; then
            echo "WARNING: $CRITICAL packages have safe updates available"
          fi

      - name: Upload Security Report
        uses: actions/upload-artifact@v4
        if: always()
        with:
          name: security-reports
          path: |
            audit-report.json
            outdated.json

  snyk-scan:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4

      - name: Snyk Security Scan
        uses: snyk/actions/php@master
        env:
          SNYK_TOKEN: ${{ secrets.SNYK_TOKEN }}
        with:
          args: --severity-threshold=high --all-projects
```

```php
<?php
// scripts/dependency-monitor.php - Custom monitoring script
namespace App\Security;

use GuzzleHttp\Client;
use Illuminate\Support\Facades\Log;
use Illuminate\Support\Facades\Cache;

class DependencyMonitor
{
    private Client $client;
    private string $composerLock;
    private array $allowedPackages = [];

    public function __construct()
    {
        $this->client = new Client(['timeout' => 30]);
        $this->composerLock = base_path('composer.lock');
    }

    public function scanForVulnerabilities(): array
    {
        $lockData = json_decode(file_get_contents($this->composerLock), true);
        $packages = array_merge(
            $lockData['packages'] ?? [],
            $lockData['packages-dev'] ?? []
        );

        $vulnerabilities = [];

        foreach ($packages as $package) {
            $vulns = $this->checkPackage($package['name'], $package['version']);
            if (!empty($vulns)) {
                $vulnerabilities[$package['name']] = [
                    'installed_version' => $package['version'],
                    'vulnerabilities' => $vulns,
                    'is_direct' => $this->isDirectDependency($package['name'])
                ];
            }
        }

        return $vulnerabilities;
    }

    private function checkPackage(string $name, string $version): array
    {
        // Check Packagist security advisories API
        $cacheKey = "security_check:{$name}:{$version}";

        return Cache::remember($cacheKey, 3600, function () use ($name, $version) {
            try {
                $response = $this->client->post(
                    'https://packagist.org/api/security-advisories/',
                    [
                        'json' => [
                            'packages' => [$name => $version]
                        ]
                    ]
                );

                $data = json_decode($response->getBody(), true);
                return $data['advisories'][$name] ?? [];
            } catch (\Exception $e) {
                Log::warning("Security check failed for {$name}: " . $e->getMessage());
                return [];
            }
        });
    }

    private function isDirectDependency(string $name): bool
    {
        $composerJson = json_decode(
            file_get_contents(base_path('composer.json')),
            true
        );

        return isset($composerJson['require'][$name]) || 
               isset($composerJson['require-dev'][$name]);
    }

    public function generateSecurityReport(): void
    {
        $vulnerabilities = $this->scanForVulnerabilities();
        $criticalCount = 0;

        foreach ($vulnerabilities as $package => $data) {
            foreach ($data['vulnerabilities'] as $vuln) {
                if ($vuln['severity'] === 'critical' || $vuln['severity'] === 'high') {
                    $criticalCount++;
                    Log::critical('Security vulnerability detected', [
                        'package' => $package,
                        'version' => $data['installed_version'],
                        'cve' => $vuln['cve'] ?? 'N/A',
                        'advisory' => $vuln['advisoryId'],
                        'is_transitive' => !$data['is_direct']
                    ]);
                }
            }
        }

        if ($criticalCount > 0) {
            $this->sendSecurityAlert($vulnerabilities, $criticalCount);
        }
    }

    private function sendSecurityAlert(array $vulnerabilities, int $critical): void
    {
        // Integrate with Slack, PagerDuty, or email
        $webhook = config('services.slack.security_webhook');

        $this->client->post($webhook, [
            'json' => [
                'text' => ":warning: SECURITY ALERT: {$critical} critical vulnerabilities found",
                'attachments' => [
                    [
                        'color' => 'danger',
                        'fields' => array_map(fn($p, $d) => [
                            'title' => $p,
                            'value' => "Version: {$d['installed_version']}",
                            'short' => true
                        ], array_keys($vulnerabilities), $vulnerabilities)
                    ]
                ]
            ]
        ]);
    }
}
```

```php
<?php
// app/Console/Commands/SecurityScanCommand.php
namespace App\Console\Commands;

use App\Security\DependencyMonitor;
use Illuminate\Console\Command;

class SecurityScanCommand extends Command
{
    protected $signature = 'security:scan 
                            {--fail-on-critical : Exit with error on critical vulnerabilities}
                            {--include-dev : Include dev dependencies in scan}';

    protected $description = 'Scan dependencies for known vulnerabilities';

    public function handle(DependencyMonitor $monitor): int
    {
        $this->info('Scanning dependencies for vulnerabilities...');

        $vulnerabilities = $monitor->scanForVulnerabilities();

        if (empty($vulnerabilities)) {
            $this->info('✅ No known vulnerabilities found!');
            return Command::SUCCESS;
        }

        $criticalFound = false;

        foreach ($vulnerabilities as $package => $data) {
            $type = $data['is_direct'] ? 'DIRECT' : 'TRANSITIVE';
            $this->error("[{$type}] {$package} ({$data['installed_version']})");

            foreach ($data['vulnerabilities'] as $vuln) {
                $severity = strtoupper($vuln['severity'] ?? 'unknown');
                $cve = $vuln['cve'] ?? 'No CVE';

                $this->line("  - [{$severity}] {$cve}: {$vuln['title']}");

                if (in_array($severity, ['CRITICAL', 'HIGH'])) {
                    $criticalFound = true;
                }
            }
        }

        if ($this->option('fail-on-critical') && $criticalFound) {
            $this->error('CRITICAL vulnerabilities found! Failing build.');
            return Command::FAILURE;
        }

        return Command::SUCCESS;
    }
}
```

**Defense in Depth Layers**:

1. **Pre-commit hooks** - Block commits with known vulnerabilities:
