const rateLimit = require('express-rate-limit');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const redis = new Redis(process.env.REDIS_URL);
const LOCK_TTL_MS = 5000; // 5 second lock timeout

// Distributed lock implementation
class DistributedLock {
  constructor(redisClient) {
    this.redis = redisClient;
  }

  async acquire(lockKey, ttlMs = LOCK_TTL_MS) {
    const lockValue = crypto.randomUUID();
    const acquired = await this.redis.set(
      lockKey,
      lockValue,
      'PX', ttlMs,
      'NX' // Only set if not exists
    );
    return acquired === 'OK' ? lockValue : null;
  }

  async release(lockKey, lockValue) {
    // Atomic release - only if we hold the lock
    const script = `
      if redis.call('get', KEYS[1]) == ARGV[1] then
        return redis.call('del', KEYS[1])
      else
        return 0
      end
    `;
    return await this.redis.eval(script, 1, lockKey, lockValue);
  }
}

const lock = new DistributedLock(redis);

// Idempotency key middleware
async function idempotencyMiddleware(req, res, next) {
  const idempotencyKey = req.headers['x-idempotency-key'];

  if (!idempotencyKey) {
    return res.status(400).json({ error: 'X-Idempotency-Key header required' });
  }

  // Check if this request was already processed
  const cachedResponse = await redis.get(`idempotency:${idempotencyKey}`);
  if (cachedResponse) {
    console.log(`[SECURITY] Replayed request detected: ${idempotencyKey}`);
    return res.json(JSON.parse(cachedResponse));
  }

  req.idempotencyKey = idempotencyKey;
  next();
}

