// Middleware to detect extraction patterns
function extractionDetector(req, res, next) {
    const apiKey = req.headers['x-api-key'];
    if (!apiKey) return res.status(401).json({ error: 'API key required' });

    const now = Date.now();
    const windowMs = 3600000; // 1 hour

    if (!queryLog.has(apiKey)) {
        queryLog.set(apiKey, { queries: [], flagged: false });
    }

    const userLog = queryLog.get(apiKey);
    userLog.queries = userLog.queries.filter(q => now - q.time < windowMs);

    // Detect suspicious patterns
    if (userLog.queries.length > 500) {
        console.warn(`Potential extraction attack from API key: ${apiKey.substring(0, 8)}...`);
        userLog.flagged = true;
        return res.status(429).json({ error: 'Unusual query pattern detected' });
    }

    userLog.queries.push({ time: now, input: hashInput(req.body.input) });
    next();
}

function hashInput(input) {
    return crypto.createHash('sha256').update(JSON.stringify(input)).digest('hex');
}

// Add noise to predictions (differential privacy)
function addPredictionNoise(predictions, epsilon = 0.1) {
    return predictions.map(p => {
        const noise = (Math.random() - 0.5) * epsilon;
        return Math.max(0, Math.min(1, p + noise));
    });
}

// Truncate predictions to top-k
function truncateToTopK(predictions, k = 3) {
    const indexed = predictions.map((p, i) => ({ prob: p, index: i }));
    indexed.sort((a, b) => b.prob - a.prob);
    return indexed.slice(0, k).map(item => ({
        class: item.index,
        confidence: Math.round(item.prob * 100) / 100 // Reduce precision
    }));
}

app.post('/api/predict', extractionDetector, async (req, res) => {
    const { input } = req.body;

    // Validate input
    if (!Array.isArray(input) || input.length !== 128) {
        return res.status(400).json({ error: 'Invalid input format' });
    }

    try {
        const tensor = tf.tensor2d([input]);
        const prediction = model.predict(tensor);
        const probabilities = await prediction.array();

        // Apply defensive measures
        const noisyPredictions = addPredictionNoise(probabilities[0]);
        const truncatedResults = truncateToTopK(noisyPredictions);

        res.json({
            results: truncatedResults,
            // No model metadata exposed
        });

        tensor.dispose();
        prediction.dispose();
    } catch (error) {
        console.error('Prediction error:', error.message);
        res.status(500).json({ error: 'Prediction failed' });
    }
});
```

**Key Security Controls**:
- **Rate limiting**: Restricts query volume to prevent mass extraction
- **Prediction truncation**: Only returns top-k classes, not full distribution
- **Differential privacy noise**: Adds calibrated noise to reduce extraction accuracy
- **Query pattern detection**: Identifies systematic extraction attempts
- **Metadata hiding**: No model architecture details exposed

Advanced model extraction attacks often use distributed queries across multiple API keys and time windows to evade simple rate limiting. Here's a production-grade detection system with behavioral analysis and anomaly detection.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const tf = require('@tensorflow/tfjs-node');
const Redis = require('ioredis');
const crypto = require('crypto');
const { IsolationForest } = require('isolation-forest');

const app = express();
app.use(express.json());

const redis = new Redis(process.env.REDIS_URL);

// Behavioral fingerprinting for extraction detection
class ExtractionDetector {
    constructor() {
        this.anomalyDetector = new IsolationForest({
            contamination: 0.05,
            nEstimators: 100
        });
        this.featureWindow = 3600000; // 1 hour
    }

    // Extract behavioral features from query patterns
    async extractFeatures(apiKey, currentInput) {
        const recentQueries = await this.getRecentQueries(apiKey);

        if (recentQueries.length < 10) {
            return null; // Not enough data
        }

        // Calculate statistical features
        const queryIntervals = this.calculateIntervals(recentQueries);
        const inputDiversity = this.calculateInputDiversity(recentQueries);
        const coverageMetric = this.calculateInputSpaceCoverage(recentQueries);
        const similarityToKnownAttacks = await this.compareToAttackPatterns(recentQueries);

        return {
            queryRate: recentQueries.length / (this.featureWindow / 60000),
            intervalVariance: this.variance(queryIntervals),
            intervalMean: this.mean(queryIntervals),
            inputEntropy: inputDiversity.entropy,
            inputDistribution: inputDiversity.uniformity,
            spaceCoverage: coverageMetric,
            systematicScore: this.detectSystematicPatterns(recentQueries),
            attackSimilarity: similarityToKnownAttacks
        };
    }

    async getRecentQueries(apiKey) {
        const key = `queries:${apiKey}`;
        const queries = await redis.lrange(key, 0, -1);
        return queries.map(q => JSON.parse(q));
    }

    calculateIntervals(queries) {
        const intervals = [];
        for (let i = 1; i < queries.length; i++) {
            intervals.push(queries[i].timestamp - queries[i-1].timestamp);
        }
        return intervals;
    }

    calculateInputDiversity(queries) {
        const inputHashes = queries.map(q => q.inputHash);
        const uniqueHashes = new Set(inputHashes);

        // Shannon entropy
        const freq = {};
        inputHashes.forEach(h => freq[h] = (freq[h] || 0) + 1);
        const probs = Object.values(freq).map(f => f / inputHashes.length);
        const entropy = -probs.reduce((sum, p) => sum + p * Math.log2(p), 0);

        // Uniformity of input space coverage
        const uniformity = uniqueHashes.size / inputHashes.length;

        return { entropy, uniformity };
    }

    calculateInputSpaceCoverage(queries) {
        // Use locality-sensitive hashing to estimate coverage
        const buckets = new Set();
        queries.forEach(q => {
            // Simplified LSH bucket assignment
            const bucket = this.lshBucket(q.inputFeatures);
            buckets.add(bucket);
        });
        return buckets.size / 1000; // Normalized by expected max buckets
    }

    lshBucket(features) {
        // Simplified LSH for demonstration
        const projection = features.slice(0, 10).map(f => f > 0 ? 1 : 0);
        return projection.join('');
    }

    detectSystematicPatterns(queries) {
        // Detect grid-like or sequential sampling patterns
        let systematicScore = 0;

        // Check for sequential patterns in inputs
        for (let i = 1; i < Math.min(queries.length, 100); i++) {
            const diff = this.inputDifference(queries[i].inputFeatures, queries[i-1].inputFeatures);
            if (this.isSystematicStep(diff)) {
                systematicScore += 1;
            }
        }

        return systematicScore / Math.min(queries.length - 1, 99);
    }

    inputDifference(input1, input2) {
        return input1.map((v, i) => v - input2[i]);
    }

    isSystematicStep(diff) {
        // Check if difference follows a pattern (e.g., constant step)
        const nonZero = diff.filter(d => Math.abs(d) > 0.001);
        return nonZero.length <= 3; // Only a few dimensions changed
    }

    async compareToAttackPatterns(queries) {
        const knownPatterns = await redis.smembers('attack_patterns');
        if (knownPatterns.length === 0) return 0;

        // Compare query pattern signature to known attacks
        const currentSignature = this.generatePatternSignature(queries);
        let maxSimilarity = 0;

        for (const pattern of knownPatterns) {
            const similarity = this.cosineSimilarity(
                currentSignature,
                JSON.parse(pattern)
            );
            maxSimilarity = Math.max(maxSimilarity, similarity);
        }

        return maxSimilarity;
    }

    generatePatternSignature(queries) {
        return [
            this.mean(this.calculateIntervals(queries)),
            this.calculateInputDiversity(queries).entropy,
            this.calculateInputSpaceCoverage(queries),
            this.detectSystematicPatterns(queries)
        ];
    }

    cosineSimilarity(a, b) {
        const dotProduct = a.reduce((sum, val, i) => sum + val * b[i], 0);
        const magA = Math.sqrt(a.reduce((sum, val) => sum + val * val, 0));
        const magB = Math.sqrt(b.reduce((sum, val) => sum + val * val, 0));
        return dotProduct / (magA * magB);
    }

    mean(arr) {
        return arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0;
    }

    variance(arr) {
        const m = this.mean(arr);
        return arr.length ? arr.reduce((sum, val) => sum + Math.pow(val - m, 2), 0) / arr.length : 0;
    }

    async isAnomaly(features) {
        if (!features) return { isAnomaly: false, score: 0 };

        const featureVector = Object.values(features);
        const score = this.anomalyDetector.predict([featureVector])[0];

        return {
            isAnomaly: score === -1,
            score: Math.abs(score)
        };
    }
}

// Adaptive response system
class AdaptiveDefense {
    constructor() {
        this.noiseLevel = new Map(); // Per-user noise levels
        this.trustScore = new Map();  // User trust scores
    }

    async adjustDefense(apiKey, anomalyResult, features) {
        const currentTrust = this.trustScore.get(apiKey) || 1.0;

        if (anomalyResult.isAnomaly) {
            // Decrease trust, increase defenses
            const newTrust = Math.max(0.1, currentTrust * 0.8);
            this.trustScore.set(apiKey, newTrust);

            // Log for security review
            await redis.lpush('security:alerts', JSON.stringify({
                apiKey: this.hashKey(apiKey),
                timestamp: Date.now(),
                anomalyScore: anomalyResult.score,
                features,
                action: 'trust_reduced'
            }));
        } else {
            // Slowly rebuild trust
            const newTrust = Math.min(1.0, currentTrust * 1.01);
            this.trustScore.set(apiKey, newTrust);
        }

        return this.getDefenseParams(apiKey);
    }

    getDefenseParams(apiKey) {
        const trust = this.trustScore.get(apiKey) || 1.0;

        return {
            noiseEpsilon: 0.05 + (1 - trust) * 0.25, // More noise for less trusted
            topK: trust > 0.8 ? 5 : (trust > 0.5 ? 3 : 1),
            precision: trust > 0.8 ? 3 : (trust > 0.5 ? 2 : 1),
            rateLimit: Math.floor(100 * trust), // Reduced rate for untrusted
            watermark: trust < 0.5 // Add watermarks for suspicious users
        };
    }

    hashKey(key) {
        return crypto.createHash('sha256').update(key).digest('hex').substring(0, 16);
    }
}

const detector = new ExtractionDetector();
const defense = new AdaptiveDefense();

// Cross-key correlation detector
async function detectCoordinatedAttack(currentInput, currentFeatures) {
    // Get recent queries across all keys
    const recentKeys = await redis.smembers('active_keys:last_hour');
    let similarPatterns = 0;

    for (const key of recentKeys) {
        const keyFeatures = await detector.extractFeatures(key, currentInput);
        if (keyFeatures) {
            const similarity = detector.cosineSimilarity(
                Object.values(currentFeatures),
                Object.values(keyFeatures)
            );
            if (similarity > 0.9) similarPatterns++;
        }
    }

    // Multiple keys with similar extraction patterns = coordinated attack
    if (similarPatterns > 5) {
        await redis.lpush('security:alerts', JSON.stringify({
            type: 'coordinated_extraction',
            timestamp: Date.now(),
            affectedKeys: similarPatterns
        }));
        return true;
    }
    return false;
}

// Watermarking for suspicious responses
function addWatermark(predictions, apiKey) {
    // Embed invisible watermark in prediction ordering
    const keyHash = crypto.createHash('md5').update(apiKey).digest('hex');
    const watermarkBits = parseInt(keyHash.substring(0, 4), 16) % 16;

    // Subtly reorder near-equal predictions to embed watermark
    // This allows tracing leaked model outputs back to the API key
    return predictions.map((p, i) => {
        if (i < 4) {
            const bit = (watermarkBits >> i) & 1;
            return p + (bit ? 0.0001 : -0.0001);
        }
        return p;
    });
}

app.post('/api/v2/predict', async (req, res) => {
    const apiKey = req.headers['x-api-key'];
    if (!apiKey) {
