        );

        if (defenseParams.watermark) {
            probabilities = addWatermark(probabilities, apiKey);
        }

        // Truncate and reduce precision
        const results = truncateToTopK(
            probabilities, 
            defenseParams.topK,
            defenseParams.precision
        );

        res.json({ results });

        tensor.dispose();
