// SECURE: Rate-limited password reset request
func requestPasswordReset(w http.ResponseWriter, r *http.Request) {
	clientIP := getClientIP(r)

	// SECURITY: Rate limit by IP to prevent enumeration
	if !checkRateLimit(clientIP, 5, time.Minute) {
		log.Printf("Rate limit exceeded for password reset from IP: %s", clientIP)
		// Return success to prevent enumeration
		respondWithGenericSuccess(w)
		return
	}

	var req PasswordResetRequest
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
