	db.QueryRow(`SELECT COUNT(*) FROM password_reset_tokens 
		WHERE user_id = $1 AND created_at > $2`,
		userID, time.Now().Add(-ResetAttemptWindow)).Scan(&recentAttempts)

	if recentAttempts >= MaxResetAttempts {
		log.Printf("Too many reset attempts for user %d from IP: %s", userID, clientIP)
		// Optionally notify user of suspicious activity
		sendSecurityAlert(userID, "Multiple password reset attempts detected")
		return
	}

	// SECURITY: Invalidate any existing reset tokens
	db.Exec("UPDATE password_reset_tokens SET used = true WHERE user_id = $1 AND used = false", userID)

	// SECURITY: Generate cryptographically secure token
	token, tokenHash, err := generateSecureResetToken()
	if err != nil {
		log.Printf("Failed to generate reset token for user %d: %v", userID, err)
		return
	}

	// Store hashed token (never store plaintext)
	expiresAt := time.Now().Add(ResetTokenExpiration)
	_, err = db.Exec(`INSERT INTO password_reset_tokens 
		(user_id, token_hash, expires_at, ip_address, created_at) 
		VALUES ($1, $2, $3, $4, $5)`,
		userID, tokenHash, expiresAt, clientIP, time.Now())

	if err != nil {
		log.Printf("Failed to store reset token for user %d: %v", userID, err)
		return
	}

	// Send reset email with token
	resetURL := fmt.Sprintf("https://example.com/reset-password?token=%s", token)
	sendPasswordResetEmail(userEmail, resetURL, clientIP)

	log.Printf("Password reset token generated for user %d, expires at %v", userID, expiresAt)
}

func generateSecureResetToken() (plainToken, hashedToken string, err error) {
	// Generate 32 bytes of cryptographically secure random data
	tokenBytes := make([]byte, ResetTokenLength)
	if _, err := rand.Read(tokenBytes); err != nil {
		return "", "", fmt.Errorf("failed to generate random bytes: %w", err)
	}

	// Encode as URL-safe base64 for the link
	plainToken = base64.URLEncoding.EncodeToString(tokenBytes)

	// Store SHA-256 hash of token (never store plaintext)
	hash := sha256.Sum256([]byte(plainToken))
	hashedToken = hex.EncodeToString(hash[:])

	return plainToken, hashedToken, nil
}

// SECURE: Password reset confirmation with token
func confirmPasswordReset(w http.ResponseWriter, r *http.Request) {
	clientIP := getClientIP(r)

	// SECURITY: Rate limit reset confirmations
	if !checkRateLimit(clientIP, 10, time.Minute) {
		log.Printf("Rate limit exceeded for reset confirmation from IP: %s", clientIP)
		http.Error(w, "Too many attempts. Please try again later.", http.StatusTooManyRequests)
		return
	}

	var req PasswordResetConfirm
	if err := json.NewDecoder(r.Body).Decode(&req); err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Validate passwords match
	if req.NewPassword != req.ConfirmPassword {
		http.Error(w, "Passwords do not match", http.StatusBadRequest)
		return
	}

	// Validate password strength
	if err := validatePasswordStrength(req.NewPassword); err != nil {
		http.Error(w, err.Error(), http.StatusBadRequest)
		return
	}

	// Hash the provided token to compare with stored hash
	tokenHash := sha256.Sum256([]byte(req.Token))
	tokenHashString := hex.EncodeToString(tokenHash[:])

	// Begin transaction for atomic operations
	tx, err := db.BeginTx(r.Context(), nil)
	if err != nil {
		log.Printf("Failed to begin transaction: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}
	defer tx.Rollback()

	// SECURITY: Find valid, unused, non-expired token
	var tokenRecord PasswordResetToken
	err = tx.QueryRow(`SELECT id, user_id, expires_at, used FROM password_reset_tokens 
		WHERE token_hash = $1`, tokenHashString).Scan(
		&tokenRecord.ID, &tokenRecord.UserID, &tokenRecord.ExpiresAt, &tokenRecord.Used)

	if err == sql.ErrNoRows {
		log.Printf("Invalid reset token attempted from IP: %s", clientIP)
		http.Error(w, "Invalid or expired reset link", http.StatusBadRequest)
		return
	}
	if err != nil {
		log.Printf("Database error during token lookup: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// SECURITY: Check if token is already used
	if tokenRecord.Used {
		log.Printf("Attempted reuse of reset token for user %d from IP: %s", tokenRecord.UserID, clientIP)
		http.Error(w, "This reset link has already been used", http.StatusBadRequest)
		return
	}

	// SECURITY: Check if token is expired
	if time.Now().After(tokenRecord.ExpiresAt) {
		log.Printf("Expired reset token for user %d from IP: %s", tokenRecord.UserID, clientIP)
		http.Error(w, "Reset link has expired. Please request a new one.", http.StatusBadRequest)
		return
	}

	// SECURITY: Mark token as used immediately (before password update)
	_, err = tx.Exec("UPDATE password_reset_tokens SET used = true, used_at = $1, used_ip = $2 WHERE id = $3",
		time.Now(), clientIP, tokenRecord.ID)
	if err != nil {
		log.Printf("Failed to mark token as used: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// Hash new password
	newPasswordHash, err := bcrypt.GenerateFromPassword([]byte(req.NewPassword), 12)
	if err != nil {
		log.Printf("Failed to hash password: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// Update password
	_, err = tx.Exec(`UPDATE users SET password = $1, password_changed_at = $2, 
		force_password_change = false WHERE id = $3`,
		string(newPasswordHash), time.Now(), tokenRecord.UserID)
	if err != nil {
		log.Printf("Failed to update password for user %d: %v", tokenRecord.UserID, err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// SECURITY: Invalidate all existing sessions
	_, err = tx.Exec("DELETE FROM sessions WHERE user_id = $1", tokenRecord.UserID)
	if err != nil {
		log.Printf("Failed to invalidate sessions for user %d: %v", tokenRecord.UserID, err)
	}

	// Commit transaction
	if err = tx.Commit(); err != nil {
		log.Printf("Failed to commit transaction: %v", err)
		http.Error(w, "Password reset failed", http.StatusInternalServerError)
		return
	}

	// SECURITY: Send notification email about password change
	go sendPasswordChangedNotification(tokenRecord.UserID, clientIP)

	log.Printf("Password successfully reset for user %d from IP: %s", tokenRecord.UserID, clientIP)

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"message": "Password reset successful. Please log in with your new password.",
	})
}

func checkRateLimit(key string, limit int, window time.Duration) bool {
	rateMu.Lock()
	defer rateMu.Unlock()

	limiter, exists := rateLimiter[key]
	if !exists {
		limiter = rate.NewLimiter(rate.Every(window/time.Duration(limit)), limit)
		rateLimiter[key] = limiter
	}
	return limiter.Allow()
}

func respondWithGenericSuccess(w http.ResponseWriter) {
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{
		"message": "If an account exists with this email, you will receive a password reset link.",
	})
}

func getClientIP(r *http.Request) string {
	// Check X-Forwarded-For header (behind proxy)
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		// Take first IP from comma-separated list
		if idx := strings.Index(xff, ","); idx != -1 {
			return strings.TrimSpace(xff[:idx])
		}
		return strings.TrimSpace(xff)
	}
	// Fall back to RemoteAddr
	if idx := strings.LastIndex(r.RemoteAddr, ":"); idx != -1 {
		return r.RemoteAddr[:idx]
	}
	return r.RemoteAddr
}

func maskEmail(email string) string {
	parts := strings.Split(email, "@")
	if len(parts) != 2 {
		return "***"
	}
	if len(parts[0]) <= 2 {
		return "***@" + parts[1]
	}
	return parts[0][:2] + "***@" + parts[1]
}
```

**Defense in Depth Layers**:

1. **Token Security**:
```go
// Layer 1: Cryptographically secure random generation
tokenBytes := make([]byte, 32) // 256 bits of entropy
crypto_rand.Read(tokenBytes)

// Layer 2: Store only hashed tokens in database
hash := sha256.Sum256([]byte(plainToken))
// Attacker with DB access cannot use stolen token hashes
```

2. **Timing Attack Prevention**:
```go
// Layer 3: Constant-time responses prevent email enumeration
// Process request asynchronously, always return same message
go processPasswordResetRequest(email, clientIP)
respondWithGenericSuccess(w) // Same response for existing and non-existing emails
```

3. **Multi-Layer Rate Limiting**:
```go
// Layer 4: IP-based rate limiting
if !checkRateLimit(clientIP, 5, time.Minute) { ... }

// Layer 5: Per-user rate limiting
if recentAttempts >= MaxResetAttempts {
    sendSecurityAlert(userID, "Multiple password reset attempts")
}
```

**Additional Protections**:
- **Short token expiration** (15 minutes): Limits attack window for intercepted emails
- **Single-use tokens**: Tokens are marked used immediately before password update in same transaction
- **Session invalidation**: All sessions terminated after password reset to boot out attackers
- **Notification emails**: User is alerted when password is changed, enabling quick detection of unauthorized changes
- **Audit trail**: Complete logging of all reset attempts with IP addresses for forensic investigation
- **Atomic transactions**: Password update and token invalidation happen atomically to prevent race conditions
- **Breached password check**: Consider integrating HaveIBeenPwned API to reject known compromised passwords

File download endpoints are extremely dangerous if implemented incorrectly. Path traversal vulnerabilities allow attackers to escape intended directories and access any file on the system - this was exploited in CVE-2024-21762 affecting Fortinet devices, compromising 150,000+ systems worldwide.

**VULNERABLE CODE**:

```php
<?php
// DANGEROUS: Never use user input directly in file paths!

class FileDownloadController {
    private $uploadDir = '/var/www/uploads/';

    public function downloadFile() {
        // User-controlled filename with NO validation
        $filename = $_GET['file'];

        // Direct concatenation - PATH TRAVERSAL VULNERABILITY
        $filepath = $this->uploadDir . $filename;

        // No existence or permission check
        if (file_exists($filepath)) {
            header('Content-Type: application/octet-stream');
            header('Content-Disposition: attachment; filename="' . basename($filename) . '"');
            header('Content-Length: ' . filesize($filepath));

            // Reads ANY file the web server can access
            readfile($filepath);
            exit;
        } else {
            http_response_code(404);
            echo "File not found";
        }
    }
}

// Usage
$controller = new FileDownloadController();
$controller->downloadFile();
?>
```

**Attack Payloads**:
```text
# Read system password file
?file=../../../etc/passwd

# Read PHP configuration
?file=../../../etc/php/8.2/apache2/php.ini

# Read application credentials
?file=../../config/database.php

# Read SSL private keys
?file=../../../etc/ssl/private/server.key

# Double encoding bypass
?file=..%252f..%252f..%252fetc/passwd

# Null byte injection (older PHP)
?file=../../../etc/passwd%00.jpg
```

**Why This Is Dangerous**:
- User input directly controls file path with no sanitization
- `../` sequences allow escaping the intended upload directory
- Attackers can read sensitive files: `/etc/passwd`, application configs, database credentials
- Can expose SSL private keys, session files, and source code
- May allow reading files containing database credentials leading to full compromise

**SECURE VERSION**:

```php
<?php
class SecureFileDownloadController {
    private $uploadDir;
    private $allowedExtensions = ['pdf', 'png', 'jpg', 'jpeg', 'gif', 'txt', 'doc', 'docx'];
    private $pdo;

    public function __construct(PDO $pdo) {
        // Use realpath to resolve the actual directory
        $this->uploadDir = realpath(__DIR__ . '/../uploads');
        if ($this->uploadDir === false) {
            throw new RuntimeException('Upload directory does not exist');
        }
        $this->pdo = $pdo;
    }

    public function downloadFile(int $userId, string $fileId): void {
        // DEFENSE 1: Validate file ID format (UUID only)
        if (!preg_match('/^[a-f0-9]{8}-[a-f0-9]{4}-4[a-f0-9]{3}-[89ab][a-f0-9]{3}-[a-f0-9]{12}$/i', $fileId)) {
            $this->logSecurityEvent('invalid_file_id', $userId, $fileId);
            $this->sendError(400, 'Invalid file identifier');
            return;
        }

        // DEFENSE 2: Database lookup - only return files user owns
        $stmt = $this->pdo->prepare(
            'SELECT filename, original_name, mime_type FROM uploads 
             WHERE file_id = :file_id AND user_id = :user_id AND deleted_at IS NULL'
        );
        $stmt->execute(['file_id' => $fileId, 'user_id' => $userId]);
        $fileRecord = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$fileRecord) {
            $this->logSecurityEvent('unauthorized_access_attempt', $userId, $fileId);
            $this->sendError(404, 'File not found');
            return;
        }

        // DEFENSE 3: Construct path and validate with realpath
        $storedFilename = basename($fileRecord['filename']); // Extra safety
        $fullPath = $this->uploadDir . DIRECTORY_SEPARATOR . $storedFilename;
        $realPath = realpath($fullPath);

        // DEFENSE 4: Verify file is within allowed directory
        if ($realPath === false || strpos($realPath, $this->uploadDir) !== 0) {
            $this->logSecurityEvent('path_traversal_blocked', $userId, $fullPath);
            $this->sendError(403, 'Access denied');
            return;
        }

        // DEFENSE 5: Validate file extension
        $extension = strtolower(pathinfo($realPath, PATHINFO_EXTENSION));
        if (!in_array($extension, $this->allowedExtensions, true)) {
            $this->logSecurityEvent('blocked_extension', $userId, $extension);
            $this->sendError(403, 'File type not allowed');
            return;
        }

        // DEFENSE 6: Verify file exists and is readable
        if (!is_file($realPath) || !is_readable($realPath)) {
            $this->sendError(404, 'File not available');
            return;
        }

        // Log successful download
        $this->logDownload($userId, $fileId, $realPath);

        // Send file with secure headers
        $this->sendFile($realPath, $fileRecord['original_name'], $fileRecord['mime_type']);
    }

    private function sendFile(string $path, string $displayName, string $mimeType): void {
        // Sanitize display name for Content-Disposition
        $safeName = preg_replace('/[^a-zA-Z0-9._-]/', '_', $displayName);

        header('Content-Type: ' . $mimeType);
        header('Content-Disposition: attachment; filename="' . $safeName . '"');
        header('Content-Length: ' . filesize($path));
        header('X-Content-Type-Options: nosniff');
        header('Cache-Control: private, no-cache, no-store, must-revalidate');

        readfile($path);
        exit;
    }

    private function sendError(int $code, string $message): void {
        http_response_code($code);
        header('Content-Type: application/json');
        echo json_encode(['error' => $message]);
    }

    private function logSecurityEvent(string $event, int $userId, string $details): void {
        error_log(sprintf(
            '[SECURITY] %s | event=%s | user=%d | details=%s | ip=%s',
            date('Y-m-d H:i:s'),
            $event,
            $userId,
            $details,
            $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ));
    }

    private function logDownload(int $userId, string $fileId, string $path): void {
        $stmt = $this->pdo->prepare(
            'INSERT INTO download_log (user_id, file_id, downloaded_at, ip_address) 
             VALUES (:user_id, :file_id, NOW(), :ip)'
        );
        $stmt->execute([
            'user_id' => $userId,
            'file_id' => $fileId,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]);
    }
}
?>
```

**Key Security Controls**:
- **Database-driven access**: Files are looked up by UUID and user ownership, not user-supplied filenames
- **realpath() validation**: Resolves symbolic links and verifies the actual path stays within upload directory
- **Directory containment check**: Ensures `strpos($realPath, $this->uploadDir) === 0` prevents escaping
- **Extension whitelist**: Only explicitly allowed file types can be downloaded
- **Security logging**: All access attempts and blocked attacks are logged for monitoring

Supporting subdirectories adds complexity but can be done securely. The key is maintaining strict path validation while allowing legitimate hierarchical access. Many breaches like CVE-2024-21762 exploited insufficient validation when directory structures were involved.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

namespace App\Services;

use PDO;
use RuntimeException;
use InvalidArgumentException;
use Psr\Log\LoggerInterface;

class SecureFileService {
    private string $baseUploadDir;
    private PDO $pdo;
    private LoggerInterface $logger;
    private array $allowedExtensions;
    private array $mimeTypeMap;
    private int $maxPathDepth = 5;

    public function __construct(
        PDO $pdo,
        LoggerInterface $logger,
        string $uploadBasePath,
        array $allowedExtensions = ['pdf', 'png', 'jpg', 'jpeg', 'gif', 'txt']
    ) {
        $this->pdo = $pdo;
        $this->logger = $logger;
        $this->allowedExtensions = array_map('strtolower', $allowedExtensions);

        // Resolve and validate base directory at construction
        $realBase = realpath($uploadBasePath);
        if ($realBase === false || !is_dir($realBase)) {
            throw new RuntimeException('Invalid upload base directory');
        }
        $this->baseUploadDir = $realBase;

        $this->mimeTypeMap = [
            'pdf' => 'application/pdf',
            'png' => 'image/png',
            'jpg' => 'image/jpeg',
            'jpeg' => 'image/jpeg',
            'gif' => 'image/gif',
            'txt' => 'text/plain'
        ];
    }

    /**
     * Download a file with full path traversal protection
     */
    public function downloadUserFile(int $userId, string $requestedPath): void {
        $context = [
            'user_id' => $userId,
            'requested_path' => $requestedPath,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown'
        ];

        try {
            // LAYER 1: Sanitize and validate path format
            $sanitizedPath = $this->sanitizePath($requestedPath);

            // LAYER 2: Verify user has access to this path via database
            $fileRecord = $this->verifyUserAccess($userId, $sanitizedPath);
            if (!$fileRecord) {
                $this->logger->warning('Unauthorized file access attempt', $context);
                $this->sendJsonError(403, 'Access denied');
                return;
            }

            // LAYER 3: Resolve and validate actual filesystem path
            $resolvedPath = $this->resolveSecurePath($userId, $sanitizedPath);
            if ($resolvedPath === null) {
                $this->logger->error('Path traversal attack detected', $context);
                $this->sendJsonError(403, 'Invalid path');
                return;
            }

            // LAYER 4: Validate file type and integrity
            if (!$this->validateFile($resolvedPath)) {
                $this->logger->warning('File validation failed', array_merge($context, ['path' => $resolvedPath]));
                $this->sendJsonError(403, 'File type not allowed');
                return;
            }

            // LAYER 5: Rate limiting check
            if (!$this->checkDownloadRateLimit($userId)) {
                $this->logger->warning('Download rate limit exceeded', $context);
                $this->sendJsonError(429, 'Too many download requests');
                return;
            }

            // Log successful download
            $this->auditDownload($userId, $fileRecord['id'], $resolvedPath);

            // Serve the file
            $this->streamFile($resolvedPath, $fileRecord['original_name']);

        } catch (InvalidArgumentException $e) {
            $this->logger->warning('Invalid path format', array_merge($context, ['error' => $e->getMessage()]));
            $this->sendJsonError(400, 'Invalid request');
        } catch (\Throwable $e) {
            $this->logger->error('File download error', array_merge($context, ['error' => $e->getMessage()]));
            $this->sendJsonError(500, 'Internal error');
        }
    }

    /**
     * DEFENSE: Multi-layer path sanitization
     */
    private function sanitizePath(string $path): string {
        // Remove null bytes (CVE-2006-7243 style attacks)
        $path = str_replace("\0", '', $path);

        // Decode URL encoding layers (prevent double-encoding bypass)
        $decoded = $path;
        $maxIterations = 3;
        for ($i = 0; $i < $maxIterations; $i++) {
            $newDecoded = urldecode($decoded);
            if ($newDecoded === $decoded) break;
            $decoded = $newDecoded;
        }
        $path = $decoded;

        // Normalize directory separators
        $path = str_replace(['\\', '/'], DIRECTORY_SEPARATOR, $path);

        // Block dangerous patterns
        $dangerousPatterns = [
            '..',           // Directory traversal
            './',           // Current directory reference
            '/.',           // Hidden files on Unix
            '~',            // Home directory expansion
            ':',            // Windows drive letters / alternate data streams
            '*', '?',       // Wildcards
            '<', '>', '|',  // Shell metacharacters
            '\$',           // Variable expansion
            '`',            // Command substitution
        ];

        foreach ($dangerousPatterns as $pattern) {
            if (strpos($path, $pattern) !== false) {
                throw new InvalidArgumentException('Invalid path characters detected');
            }
        }

        // Validate path depth
        $segments = explode(DIRECTORY_SEPARATOR, trim($path, DIRECTORY_SEPARATOR));
        if (count($segments) > $this->maxPathDepth) {
            throw new InvalidArgumentException('Path too deep');
        }

        // Validate each segment
        foreach ($segments as $segment) {
            if ($segment === '' || $segment === '.' || $segment === '..') {
                throw new InvalidArgumentException('Invalid path segment');
            }
            // Only allow alphanumeric, dash, underscore, dot (not at start)
            if (!preg_match('/^[a-zA-Z0-9][a-zA-Z0-9._-]*$/', $segment)) {
                throw new InvalidArgumentException('Invalid characters in path segment');
            }
        }

        return implode(DIRECTORY_SEPARATOR, $segments);
    }

    /**
     * DEFENSE: Database-driven access control
     */
    private function verifyUserAccess(int $userId, string $relativePath): ?array {
        $stmt = $this->pdo->prepare('
            SELECT f.id, f.filename, f.original_name, f.mime_type, f.folder_id,
                   fo.path as folder_path
            FROM files f
            INNER JOIN folders fo ON f.folder_id = fo.id
            WHERE fo.user_id = :user_id
              AND CONCAT(fo.path, "/", f.filename) = :full_path
              AND f.deleted_at IS NULL
              AND fo.deleted_at IS NULL
        ');

        $stmt->execute([
            'user_id' => $userId,
            'full_path' => $relativePath
        ]);

        return $stmt->fetch(PDO::FETCH_ASSOC) ?: null;
    }

    /**
     * DEFENSE: Secure path resolution with realpath validation
     */
    private function resolveSecurePath(int $userId, string $relativePath): ?string {
        // User's files are stored in: /uploads/{user_id}/{relative_path}
        $userDir = $this->baseUploadDir . DIRECTORY_SEPARATOR . (string)$userId;
        $fullPath = $userDir . DIRECTORY_SEPARATOR . $relativePath;

        // Resolve the real path (follows symlinks, resolves . and ..)
        $realPath = realpath($fullPath);

        // File must exist
        if ($realPath === false) {
            return null;
        }

        // CRITICAL: Verify path is within user's directory
        $realUserDir = realpath($userDir);
        if ($realUserDir === false) {
            return null;
        }

        // Path must start with user's directory (prevent traversal)
        if (strpos($realPath, $realUserDir . DIRECTORY_SEPARATOR) !== 0) {
            return null;
        }

        // Must be a regular file (not directory, symlink outside, device, etc.)
        if (!is_file($realPath)) {
            return null;
        }

        return $realPath;
    }

    /**
     * DEFENSE: File type validation
     */
    private function validateFile(string $path): bool {
        // Check extension
        $extension = strtolower(pathinfo($path, PATHINFO_EXTENSION));
        if (!in_array($extension, $this->allowedExtensions, true)) {
            return false;
        }

        // Verify MIME type matches extension (prevent extension spoofing)
        $finfo = new \finfo(FILEINFO_MIME_TYPE);
        $detectedMime = $finfo->file($path);
        $expectedMime = $this->mimeTypeMap[$extension] ?? null;

        if ($expectedMime === null || $detectedMime !== $expectedMime) {
            // Allow some flexibility for text files
            if ($extension === 'txt' && strpos($detectedMime, 'text/') === 0) {
                return true;
            }
            return false;
        }

        return true;
    }

    /**
     * DEFENSE: Rate limiting for downloads
     */
    private function checkDownloadRateLimit(int $userId): bool {
        $key = "download_rate:{$userId}";
        $limit = 100; // Downloads per hour
        $window = 3600; // 1 hour

        // Using database for rate limiting (could use Redis in production)
        $stmt = $this->pdo->prepare('
            SELECT COUNT(*) as count FROM download_log 
            WHERE user_id = :user_id AND downloaded_at > DATE_SUB(NOW(), INTERVAL 1 HOUR)
        ');
        $stmt->execute(['user_id' => $userId]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);

        return ($result['count'] ?? 0) < $limit;
    }

    /**
     * Audit logging for compliance
     */
    private function auditDownload(int $userId, int $fileId, string $path): void {
        $stmt = $this->pdo->prepare('
            INSERT INTO download_log 
            (user_id, file_id, file_path, downloaded_at, ip_address, user_agent)
            VALUES (:user_id, :file_id, :path, NOW(), :ip, :ua)
        ');

        $stmt->execute([
            'user_id' => $userId,
            'file_id' => $fileId,
            'path' => $path,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'ua' => substr($_SERVER['HTTP_USER_AGENT'] ?? 'unknown', 0, 255)
        ]);

        $this->logger->info('File downloaded', [
            'user_id' => $userId,
            'file_id' => $fileId,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown'
        ]);
    }

    /**
     * Stream file with security headers
     */
    private function streamFile(string $path, string $originalName): void {
        // Sanitize filename for Content-Disposition
        $safeName = preg_replace('/[^a-zA-Z0-9._-]/', '_', $originalName);
        $safeName = substr($safeName, 0, 255);

        $extension = strtolower(pathinfo($path, PATHINFO_EXTENSION));
        $mimeType = $this->mimeTypeMap[$extension] ?? 'application/octet-stream';

        // Security headers
        header('Content-Type: ' . $mimeType);
        header('Content-Disposition: attachment; filename="' . $safeName . '"');
        header('Content-Length: ' . filesize($path));
        header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
        header('Content-Security-Policy: default-src \'none\'');
        header('Cache-Control: private, no-cache, no-store, must-revalidate');
        header('Pragma: no-cache');
        header('Expires: 0');

        // Stream file in chunks to handle large files
        $handle = fopen($path, 'rb');
        if ($handle === false) {
            throw new RuntimeException('Cannot open file');
        }

        while (!feof($handle)) {
            echo fread($handle, 8192);
            flush();
        }

        fclose($handle);
        exit;
    }

    private function sendJsonError(int $code, string $message): void {
        http_response_code($code);
        header('Content-Type: application/json');
        echo json_encode(['error' => $message]);
    }
}
?>
