**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const Ajv = require('ajv');
const addFormats = require('ajv-formats');
const { createHash, timingSafeEqual } = require('crypto');
const pino = require('pino');

const app = express();
const logger = pino({ level: process.env.LOG_LEVEL || 'info' });

// Initialize JSON Schema validator
const ajv = new Ajv({ 
  allErrors: true,
  removeAdditional: 'all',  // Strip unknown properties
  useDefaults: true,
  coerceTypes: false        // Don't auto-convert types
});
addFormats(ajv);

// Define strict schema for external data
const externalDataSchema = {
  type: 'object',
  additionalProperties: false,
  required: ['eventId', 'timestamp', 'payload'],
  properties: {
    eventId: { type: 'string', format: 'uuid' },
    timestamp: { type: 'string', format: 'date-time' },
    signature: { type: 'string', pattern: '^[a-f0-9]{64}$' },
    payload: {
      type: 'object',
      additionalProperties: false,
      properties: {
        userId: { type: 'string', format: 'uuid' },
        action: { type: 'string', enum: ['create', 'update', 'delete'] },
        data: {
          type: 'object',
          additionalProperties: false,
          maxProperties: 50,
          patternProperties: {
            '^[a-zA-Z][a-zA-Z0-9_]{0,63}$': {
              oneOf: [
                { type: 'string', maxLength: 10000 },
                { type: 'number' },
                { type: 'boolean' },
                { type: 'null' }
              ]
            }
          }
        }
      }
    }
  }
};

const validateExternalData = ajv.compile(externalDataSchema);

// Secure JSON parser that prevents prototype pollution
function safeJsonParse(jsonString, maxSize = 1048576) {
  // Size limit to prevent DoS
  if (jsonString.length > maxSize) {
    throw new Error(`Payload exceeds maximum size of ${maxSize} bytes`);
  }

  // Parse with prototype pollution protection
  const parsed = JSON.parse(jsonString, (key, value) => {
    // Block prototype pollution vectors
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') {
      logger.warn({ key }, 'Blocked prototype pollution attempt');
      return undefined;
    }
    return value;
  });

  // Create clean object without prototype chain
  return JSON.parse(JSON.stringify(parsed));
}

// HMAC signature verification for external data
function verifySignature(payload, signature, secret) {
  const expectedSignature = createHash('sha256')
    .update(JSON.stringify(payload))
    .digest('hex');

  const sigBuffer = Buffer.from(signature, 'hex');
  const expectedBuffer = Buffer.from(expectedSignature, 'hex');

  if (sigBuffer.length !== expectedBuffer.length) {
    return false;
  }

  return timingSafeEqual(sigBuffer, expectedBuffer);
}

// Process external webhook/message queue data
app.post('/api/webhook', express.text({ type: '*/*', limit: '1mb' }), async (req, res) => {
  const requestId = req.headers['x-request-id'] || crypto.randomUUID();
  const startTime = Date.now();

  try {
    // Step 1: Safe JSON parsing
    let data;
    try {
      data = safeJsonParse(req.body);
    } catch (parseError) {
      logger.warn({ requestId, error: parseError.message }, 'JSON parse failed');
      return res.status(400).json({ error: 'Invalid JSON' });
    }

    // Step 2: Schema validation
    const isValid = validateExternalData(data);
    if (!isValid) {
      logger.warn({ 
        requestId, 
        errors: validateExternalData.errors 
      }, 'Schema validation failed');
      return res.status(400).json({ 
        error: 'Invalid data structure',
        details: validateExternalData.errors.map(e => e.message)
      });
    }

    // Step 3: Signature verification (defense in depth)
    const webhookSecret = process.env.WEBHOOK_SECRET;
    if (data.signature && webhookSecret) {
      if (!verifySignature(data.payload, data.signature, webhookSecret)) {
        logger.error({ requestId }, 'Signature verification failed');
        return res.status(401).json({ error: 'Invalid signature' });
      }
    }

    // Step 4: Process the validated, verified data
    logger.info({ 
      requestId,
      eventId: data.eventId,
