**Why This Is Dangerous**:
- HTTP headers can be spoofed by any client, including external attackers
- Internal network location is not a valid authentication factor
- No cryptographic verification of service identity
- Compromising ANY internal service grants access to ALL internal services
- Trust boundary between services is implicit, not enforced

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const app = express();

app.use(express.json());

// Service-to-service authentication using mTLS + JWT
const SERVICE_PUBLIC_KEYS = {
  'admin-service': process.env.ADMIN_SERVICE_PUBLIC_KEY,
  'billing-service': process.env.BILLING_SERVICE_PUBLIC_KEY
};

// Allowed service permissions (explicit trust boundaries)
const SERVICE_PERMISSIONS = {
  'admin-service': ['read:user:basic', 'read:user:admin'],
  'billing-service': ['read:user:billing']
};

// Secure middleware: Verify service identity cryptographically
const verifyServiceIdentity = async (req, res, next) => {
  const serviceToken = req.headers['x-service-token'];
  const serviceName = req.headers['x-service-name'];

  if (!serviceToken || !serviceName) {
    req.isVerifiedService = false;
    return next();
  }

  try {
    // Verify JWT signed by the calling service
    const publicKey = SERVICE_PUBLIC_KEYS[serviceName];
    if (!publicKey) {
      throw new Error('Unknown service');
    }

    const decoded = jwt.verify(serviceToken, publicKey, {
      algorithms: ['RS256'],
      issuer: serviceName,
      audience: 'user-service'
    });

    // Verify token is fresh (prevents replay attacks)
    if (Date.now() - decoded.iat * 1000 > 60000) {
      throw new Error('Token expired');
    }

    req.isVerifiedService = true;
    req.callingService = serviceName;
    req.servicePermissions = SERVICE_PERMISSIONS[serviceName] || [];
    req.requestContext = decoded.context; // Verified context from token

  } catch (error) {
    console.error('Service auth failed:', error.message);
    req.isVerifiedService = false;
  }

  next();
};

app.use(verifyServiceIdentity);

// Permission check helper
const requirePermission = (permission) => (req, res, next) => {
  if (!req.servicePermissions.includes(permission)) {
    console.warn(`Service ${req.callingService} denied: lacks ${permission}`);
    return res.status(403).json({ error: 'Insufficient permissions' });
  }
  next();
};

// SECURE: Explicit trust boundaries with cryptographic verification
app.get('/api/users/:id/sensitive-data', 
  requirePermission('read:user:admin'),
  (req, res) => {
    const userId = req.params.id;

    // Even for verified services, validate the request makes sense
    if (!req.requestContext || req.requestContext.targetUserId !== userId) {
      return res.status(400).json({ error: 'Context mismatch' });
    }

    // Audit log all sensitive data access
    console.log(JSON.stringify({
      event: 'sensitive_data_access',
      service: req.callingService,
      targetUser: userId,
      timestamp: new Date().toISOString(),
      correlationId: req.headers['x-correlation-id']
    }));

    const sensitiveData = getSensitiveUserData(userId);
    res.json(sensitiveData);
  }
);

app.listen(3000);
```

**Key Security Controls**:
- **Cryptographic service identity**: JWT tokens signed with service-specific private keys replace spoofable headers
- **Explicit permission model**: Each service has defined capabilities, enforced at the receiving service
- **Request context binding**: The target of the request is embedded in the signed token, preventing parameter manipulation
- **Audit logging**: All cross-service calls logged with correlation IDs for tracing
- **Short-lived tokens**: 60-second token lifetime prevents replay attacks

Complex architectures require explicit trust zone modeling with cryptographic enforcement at each boundary. Here's a production pattern based on zero-trust principles:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const { createClient } = require('redis');

// Trust Zone Definitions
const TRUST_ZONES = {
  PUBLIC: {
    level: 0,
    name: 'public',
    allowedTargetZones: ['public'],
    maxDataClassification: 'public'
  },
  AUTHENTICATED: {
    level: 1,
    name: 'authenticated',
    allowedTargetZones: ['public', 'authenticated'],
    maxDataClassification: 'internal'
  },
  INTERNAL_SERVICE: {
    level: 2,
    name: 'internal-service',
    allowedTargetZones: ['public', 'authenticated', 'internal-service'],
    maxDataClassification: 'confidential'
  },
  PRIVILEGED: {
    level: 3,
    name: 'privileged',
    allowedTargetZones: ['public', 'authenticated', 'internal-service', 'privileged'],
    maxDataClassification: 'restricted',
    requiresMFA: true,
    requiresApproval: true
  }
};

// Data Classification tied to trust zones
const DATA_CLASSIFICATIONS = {
  public: 0,
  internal: 1,
  confidential: 2,
  restricted: 3
};

class TrustBoundaryEnforcer {
  constructor(redisClient, config) {
    this.redis = redisClient;
    this.config = config;
    this.serviceKeys = new Map();
  }

  // Load service public keys from secure key management
  async loadServiceKeys() {
    const keys = await this.redis.hGetAll('service:public_keys');
    for (const [service, key] of Object.entries(keys)) {
      this.serviceKeys.set(service, key);
    }
  }

  // Verify the identity claim cryptographically
  async verifyIdentity(req) {
    const context = {
      verified: false,
      trustZone: TRUST_ZONES.PUBLIC,
      identity: null,
      permissions: [],
      violations: []
    };

    // Check for service-to-service token (mTLS would be verified at ingress)
    const serviceToken = req.headers['x-service-assertion'];
    if (serviceToken) {
      try {
        context.identity = await this.verifyServiceToken(serviceToken);
        context.trustZone = TRUST_ZONES.INTERNAL_SERVICE;
        context.verified = true;
      } catch (e) {
        context.violations.push(`Service token invalid: ${e.message}`);
      }
    }

    // Check for user token
    const userToken = req.headers['authorization']?.replace('Bearer ', '');
    if (userToken) {
      try {
        const user = await this.verifyUserToken(userToken);
        context.identity = { ...context.identity, user };

        // Elevate to privileged if user has admin role AND MFA
        if (user.roles.includes('admin') && user.mfaVerified) {
          context.trustZone = TRUST_ZONES.PRIVILEGED;
        } else {
          context.trustZone = TRUST_ZONES.AUTHENTICATED;
        }
        context.verified = true;
      } catch (e) {
        context.violations.push(`User token invalid: ${e.message}`);
      }
    }

    return context;
  }

  async verifyServiceToken(token) {
    const header = JSON.parse(
      Buffer.from(token.split('.')[0], 'base64url').toString()
    );

    const serviceName = header.iss;
    const publicKey = this.serviceKeys.get(serviceName);

    if (!publicKey) {
      throw new Error(`Unknown service: ${serviceName}`);
    }

    const decoded = jwt.verify(token, publicKey, {
      algorithms: ['RS256', 'ES256'],
      clockTolerance: 30
    });

    // Verify service is calling from expected network segment
    // (This would be validated at ingress/service mesh level)

    return {
      type: 'service',
      serviceName: decoded.iss,
      permissions: decoded.permissions || [],
      requestId: decoded.jti
    };
  }

  async verifyUserToken(token) {
    const decoded = jwt.verify(token, this.config.userTokenSecret, {
      algorithms: ['RS256']
    });

    return {
      type: 'user',
      userId: decoded.sub,
      roles: decoded.roles || [],
      mfaVerified: decoded.amr?.includes('mfa') || false
    };
  }

  // Enforce trust boundary crossing
  canAccessResource(context, resource) {
    const result = {
      allowed: false,
      reason: '',
      requiredElevation: null
    };

    // Check if trust zone can access target zone
    if (!context.trustZone.allowedTargetZones.includes(resource.zone)) {
      result.reason = `Trust zone ${context.trustZone.name} cannot access ${resource.zone}`;
      return result;
    }

    // Check data classification
    const maxAllowed = DATA_CLASSIFICATIONS[context.trustZone.maxDataClassification];
    const resourceLevel = DATA_CLASSIFICATIONS[resource.classification];

    if (resourceLevel > maxAllowed) {
      result.reason = `Data classification ${resource.classification} exceeds allowed ${context.trustZone.maxDataClassification}`;
      result.requiredElevation = 'privileged';
      return result;
    }

    // Check specific permissions
    if (resource.requiredPermission) {
      const hasPermission = context.identity?.permissions?.includes(resource.requiredPermission);
      if (!hasPermission) {
        result.reason = `Missing required permission: ${resource.requiredPermission}`;
        return result;
      }
    }

    result.allowed = true;
    return result;
  }
}

// Express middleware factory
const createTrustBoundaryMiddleware = (enforcer) => {
  return async (req, res, next) => {
    try {
      req.trustContext = await enforcer.verifyIdentity(req);

      // Log all boundary crossings
      console.log(JSON.stringify({
        event: 'trust_boundary_evaluation',
        path: req.path,
        method: req.method,
        sourceZone: req.trustContext.trustZone.name,
        identity: req.trustContext.identity?.type,
        violations: req.trustContext.violations,
        correlationId: req.headers['x-correlation-id'],
        timestamp: new Date().toISOString()
      }));

      if (req.trustContext.violations.length > 0) {
        // Alert on potential attacks
        console.error(JSON.stringify({
          event: 'trust_boundary_violation_attempt',
          violations: req.trustContext.violations,
          ip: req.ip,
          headers: req.headers
        }));
      }

      next();
    } catch (error) {
      console.error('Trust boundary error:', error);
      res.status(500).json({ error: 'Security validation failed' });
    }
  };
};

// Resource access decorator
const protectResource = (resourceConfig) => {
  return (req, res, next) => {
    const resource = {
      zone: resourceConfig.zone || 'internal-service',
      classification: resourceConfig.classification || 'internal',
      requiredPermission: resourceConfig.permission
    };

    const accessResult = req.app.locals.enforcer.canAccessResource(
      req.trustContext,
      resource
    );

    if (!accessResult.allowed) {
      console.warn(JSON.stringify({
        event: 'access_denied',
        reason: accessResult.reason,
        resource: resourceConfig,
        identity: req.trustContext.identity,
        correlationId: req.headers['x-correlation-id']
      }));

      if (accessResult.requiredElevation) {
        return res.status(403).json({
          error: 'Insufficient privileges',
          requiredElevation: accessResult.requiredElevation
        });
      }

      return res.status(403).json({ error: 'Access denied' });
    }

    next();
  };
};

// Application setup
const app = express();

async function initializeApp() {
  const redis = createClient({ url: process.env.REDIS_URL });
  await redis.connect();

  const enforcer = new TrustBoundaryEnforcer(redis, {
    userTokenSecret: process.env.USER_TOKEN_PUBLIC_KEY
  });
  await enforcer.loadServiceKeys();

  app.locals.enforcer = enforcer;
  app.use(express.json());
  app.use(createTrustBoundaryMiddleware(enforcer));

  // Public endpoint - no protection
  app.get('/api/public/status', (req, res) => {
    res.json({ status: 'ok' });
  });

  // Authenticated user data
  app.get('/api/users/:id/profile',
    protectResource({
      zone: 'authenticated',
      classification: 'internal'
    }),
    (req, res) => {
      // Additional check: users can only access their own profile
      if (req.trustContext.identity?.user?.userId !== req.params.id) {
        return res.status(403).json({ error: 'Access denied' });
      }
      res.json({ userId: req.params.id, name: 'Example User' });
    }
  );

  // Internal service endpoint
  app.get('/internal/users/:id/full',
    protectResource({
      zone: 'internal-service',
      classification: 'confidential',
      permission: 'read:user:full'
    }),
    (req, res) => {
      res.json({ userId: req.params.id, sensitive: true });
    }
  );

  // Privileged admin endpoint
  app.post('/admin/users/:id/impersonate',
    protectResource({
      zone: 'privileged',
      classification: 'restricted',
      permission: 'admin:impersonate'
    }),
    async (req, res) => {
      // Require approval for impersonation
      const approval = await checkApprovalStatus(req.body.approvalId);
      if (!approval.valid) {
        return res.status(403).json({ error: 'Approval required' });
