Your login endpoint is vulnerable to credential stuffing attacks, which are different from traditional brute force. In credential stuffing, attackers use lists of breached username/password pairs from other sites to attempt logins at scale. This was exactly what happened in the 2024 23andMe breach affecting 6.9 million users.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const { Pool } = require('pg');

const app = express();
app.use(express.json());

const pool = new Pool({
  connectionString: process.env.DATABASE_URL
});

// VULNERABLE: No rate limiting, no account lockout, no breach detection
app.post('/api/login', async (req, res) => {
  const { email, password } = req.body;

  try {
    const result = await pool.query(
      'SELECT id, password_hash FROM users WHERE email = $1',
      [email]
    );

    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const isValid = await bcrypt.compare(password, user.password_hash);

    if (!isValid) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Login successful - generate session
    req.session.userId = user.id;
    return res.json({ success: true, message: 'Login successful' });
  } catch (error) {
    console.error('Login error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});
```

**Attack Scenario**:
```bash
# Attacker uses automated tool with breached credentials
for cred in breached_credentials.txt; do
  curl -X POST https://target.com/api/login \
    -H "Content-Type: application/json" \
    -d "{\"email\":\"${cred%:*}\",\"password\":\"${cred#*:}\"}"
done
# Attackers can attempt thousands of logins per minute
```

**Why This Is Dangerous**:
- No rate limiting allows unlimited login attempts
- No detection of automated attack patterns (same IP, high velocity)
- No account lockout after failed attempts
- No breach password detection (checking against known compromised passwords)
- No CAPTCHA or proof-of-work challenge for suspicious activity
- No alerting on unusual login patterns

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const rateLimit = require('express-rate-limit');
const { Pool } = require('pg');
const Redis = require('ioredis');
const crypto = require('crypto');

const app = express();
app.use(express.json());

const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const redis = new Redis(process.env.REDIS_URL);

// Global rate limit: 100 requests per 15 minutes per IP
const globalLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: { error: 'Too many requests, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Strict login rate limit: 5 attempts per 15 minutes per IP
const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  message: { error: 'Too many login attempts, please try again later' },
  keyGenerator: (req) => req.ip
});

app.use(globalLimiter);

// Track failed attempts per account
async function trackFailedAttempt(email, ip) {
  const accountKey = `failed:account:${email}`;
  const ipKey = `failed:ip:${ip}`;

  await redis.multi()
    .incr(accountKey)
    .expire(accountKey, 3600) // 1 hour window
    .incr(ipKey)
    .expire(ipKey, 3600)
    .exec();

  const accountFailures = await redis.get(accountKey);
  return parseInt(accountFailures) || 0;
}

// Check if account is locked
async function isAccountLocked(email) {
  const failures = await redis.get(`failed:account:${email}`);
  return parseInt(failures) >= 5; // Lock after 5 failed attempts
}

// Clear failed attempts on successful login
async function clearFailedAttempts(email) {
  await redis.del(`failed:account:${email}`);
}

app.post('/api/login', loginLimiter, async (req, res) => {
  const { email, password } = req.body;
  const clientIp = req.ip;

  // Input validation
  if (!email || !password || typeof email !== 'string') {
    return res.status(400).json({ error: 'Invalid request' });
  }

  try {
    // Check if account is locked
    if (await isAccountLocked(email)) {
      console.warn(`Locked account login attempt: ${email} from ${clientIp}`);
      return res.status(429).json({ 
        error: 'Account temporarily locked. Please try again later or reset password.' 
      });
    }

    const result = await pool.query(
      'SELECT id, password_hash FROM users WHERE email = $1',
      [email]
    );

    // Constant-time response for user enumeration protection
    if (result.rows.length === 0) {
      await trackFailedAttempt(email, clientIp);
      // Simulate bcrypt comparison time to prevent timing attacks
      await bcrypt.compare(password, '$2b$12$InvalidHashToSimulateTime');
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const isValid = await bcrypt.compare(password, user.password_hash);

    if (!isValid) {
      const failures = await trackFailedAttempt(email, clientIp);
      console.warn(`Failed login for ${email} from ${clientIp} (${failures} failures)`);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Success - clear failed attempts
    await clearFailedAttempts(email);

    // Log successful login for monitoring
    console.info(`Successful login: ${email} from ${clientIp}`);

    req.session.userId = user.id;
    return res.json({ success: true });
  } catch (error) {
    console.error('Login error:', error);
    return res.status(500).json({ error: 'Internal server error' });
  }
});
```

**Key Security Controls**:
- **IP-based rate limiting**: Limits login attempts per IP to slow automated attacks
- **Account-based lockout**: Temporarily locks accounts after repeated failures
- **Constant-time responses**: Prevents user enumeration via timing attacks
- **Redis-backed tracking**: Distributed tracking of failed attempts across instances
- **Security logging**: Records failed attempts for SIEM/monitoring integration

