const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const redis = new Redis(process.env.REDIS_URL);

// ===========================================
// BREACH DETECTION: Have I Been Pwned API
// ===========================================
async function checkPasswordBreached(password) {
  // Use k-Anonymity model - only send first 5 chars of SHA-1 hash
  const sha1Hash = crypto.createHash('sha1')
    .update(password)
    .digest('hex')
    .toUpperCase();

  const prefix = sha1Hash.substring(0, 5);
  const suffix = sha1Hash.substring(5);

  try {
    const response = await axios.get(
      `https://api.pwnedpasswords.com/range/${prefix}`,
      {
        headers: { 'Add-Padding': 'true' }, // Prevent response size analysis
        timeout: 5000
      }
    );

    // Check if our suffix appears in the response
    const hashes = response.data.split('\n');
    for (const line of hashes) {
      const [hashSuffix, count] = line.split(':');
      if (hashSuffix.trim() === suffix) {
        return { breached: true, count: parseInt(count) };
      }
    }

    return { breached: false, count: 0 };
  } catch (error) {
    // Fail open but log - don't block login if API is down
    console.error('HIBP API error:', error.message);
    return { breached: false, count: 0, error: true };
  }
}

