function verifyTOTP(secret, token) {
  return speakeasy.totp.verify({
    secret: secret,
    encoding: 'base32',
    token: token,
    window: 1 // Allow 1 step tolerance for clock drift
  });
}

async function verifyBackupCode(userId, code) {
  const hashedCode = crypto.createHash('sha256').update(code).digest('hex');

  const result = await pool.query(
    `UPDATE backup_codes 
     SET used_at = NOW() 
     WHERE user_id = $1 AND code_hash = $2 AND used_at IS NULL
     RETURNING id`,
    [userId, hashedCode]
  );

  return result.rows.length > 0;
}

// ===========================================
// DEVICE FINGERPRINTING & RISK ANALYSIS
// ===========================================
function calculateRiskScore(req, user) {
  let score = 0;

  const clientIp = req.ip;
  const userAgent = req.headers['user-agent'] || '';
  const acceptLanguage = req.headers['accept-language'] || '';

  // New device/location indicators
  if (!user.known_ips?.includes(clientIp)) score += 30;
  if (!user.known_user_agents?.includes(userAgent)) score += 20;

  // Suspicious patterns
  if (userAgent.includes('curl') || userAgent.includes('python')) score += 40;
  if (!acceptLanguage) score += 15; // Bots often omit this

  // Time-based anomalies
  const hour = new Date().getHours();
  if (user.typical_login_hours && !user.typical_login_hours.includes(hour)) {
    score += 10;
  }

  return Math.min(score, 100);
}

