const loginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 5,
  skipSuccessfulRequests: true
});

app.post('/api/login', loginLimiter, async (req, res) => {
  const { email, password, mfaToken, backupCode } = req.body;
  const clientIp = req.ip;
  const requestId = crypto.randomUUID();

  // Structured logging for SIEM
  const logContext = { requestId, email, clientIp, timestamp: new Date().toISOString() };

  try {
    // Input validation
    if (!email || !password) {
      console.warn('Login: missing credentials', logContext);
      return res.status(400).json({ error: 'Email and password required' });
    }

    // Check account lockout
    const lockKey = `lockout:${email}`;
    const isLocked = await redis.get(lockKey);
    if (isLocked) {
      console.warn('Login: account locked', logContext);
      return res.status(429).json({ 
        error: 'Account temporarily locked',
        retryAfter: await redis.ttl(lockKey)
      });
    }

    // Fetch user with MFA settings
    const userResult = await pool.query(
      `SELECT id, password_hash, mfa_enabled, mfa_secret, 
              known_ips, known_user_agents, typical_login_hours,
              password_changed_at, force_password_change
       FROM users WHERE email = $1`,
      [email]
    );

    if (userResult.rows.length === 0) {
      await incrementFailures(email, clientIp);
      await bcrypt.compare(password, '$2b$12$DummyHashForTimingAttackPrevention');
      console.warn('Login: user not found', logContext);
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = userResult.rows[0];

    // Verify password
    const isValidPassword = await bcrypt.compare(password, user.password_hash);
    if (!isValidPassword) {
      const failures = await incrementFailures(email, clientIp);
      console.warn('Login: invalid password', { ...logContext, failures });

      // Progressive lockout
      if (failures >= 5) {
        await redis.setex(lockKey, 900, 'locked'); // 15 min lockout
        console.warn('Login: account locked due to failures', logContext);
      }

      return res.status(401).json({ error: 'Invalid credentials' });
    }

    // Check if password is breached
    const breachCheck = await checkPasswordBreached(password);
    if (breachCheck.breached) {
      console.warn('Login: breached password detected', { 
        ...logContext, 
        breachCount: breachCheck.count 
      });

      // Allow login but force password change
      await pool.query(
        'UPDATE users SET force_password_change = true WHERE id = $1',
        [user.id]
      );
    }

    // Calculate risk score
    const riskScore = calculateRiskScore(req, user);
    console.info('Login: risk assessment', { ...logContext, riskScore });

    // MFA verification
    if (user.mfa_enabled || riskScore >= 50) {
      if (!mfaToken && !backupCode) {
        // Require MFA - return partial success
        const challengeToken = crypto.randomBytes(32).toString('hex');
        await redis.setex(`mfa_challenge:${challengeToken}`, 300, user.id.toString());

        return res.status(200).json({ 
          requiresMfa: true,
          challengeToken,
          reason: user.mfa_enabled ? 'mfa_enabled' : 'high_risk_login'
        });
      }

      // Verify MFA token
      let mfaValid = false;
      if (mfaToken) {
        mfaValid = verifyTOTP(user.mfa_secret, mfaToken);
      } else if (backupCode) {
        mfaValid = await verifyBackupCode(user.id, backupCode);
      }

      if (!mfaValid) {
        console.warn('Login: invalid MFA token', logContext);
        return res.status(401).json({ error: 'Invalid MFA token' });
      }
    }

    // Login successful!
    await clearFailures(email);

    // Update known devices
    await pool.query(
      `UPDATE users SET 
         known_ips = array_append(array_remove(known_ips, $2), $2),
         known_user_agents = array_append(
           array_remove(known_user_agents, $3), $3
         ),
         last_login_at = NOW(),
         last_login_ip = $2
       WHERE id = $1`,
      [user.id, clientIp, req.headers['user-agent']]
    );

    // Generate secure session
    const sessionId = crypto.randomBytes(32).toString('hex');
    await redis.setex(
      `session:${sessionId}`,
      86400, // 24 hour expiry
      JSON.stringify({ userId: user.id, createdAt: Date.now() })
    );

    console.info('Login: successful', { ...logContext, userId: user.id, riskScore });

    // Set secure cookie
    res.cookie('session', sessionId, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 86400000
    });

    return res.json({ 
      success: true,
      forcePasswordChange: user.force_password_change || breachCheck.breached,
      mfaEnabled: user.mfa_enabled
    });

  } catch (error) {
    console.error('Login: internal error', { ...logContext, error: error.message });
    return res.status(500).json({ error: 'Internal server error' });
  }
});

