app.post('/api/mfa/verify-setup', requireAuth, async (req, res) => {
  const userId = req.session.userId;
  const { token } = req.body;

  const secret = await redis.get(`mfa_setup:${userId}`);
  if (!secret) {
    return res.status(400).json({ error: 'No MFA setup in progress' });
  }

  const isValid = verifyTOTP(secret, token);
  if (!isValid) {
    return res.status(400).json({ error: 'Invalid token' });
  }

  // Generate backup codes
  const backupCodes = [];
  for (let i = 0; i < 10; i++) {
    const code = crypto.randomBytes(4).toString('hex').toUpperCase();
    const hash = crypto.createHash('sha256').update(code).digest('hex');
    backupCodes.push({ plain: code, hash });

    await pool.query(
      'INSERT INTO backup_codes (user_id, code_hash) VALUES ($1, $2)',
      [userId, hash]
    );
  }

  // Enable MFA
  await pool.query(
    'UPDATE users SET mfa_enabled = true, mfa_secret = $2 WHERE id = $1',
    [userId, secret]
  );

  await redis.del(`mfa_setup:${userId}`);

  console.info('MFA enabled', { userId });

  return res.json({
    success: true,
    backupCodes: backupCodes.map(c => c.plain)
  });
});

