Production applications need continuous monitoring because new vulnerabilities are discovered daily. The Log4Shell vulnerability (CVE-2021-44228) showed how a zero-day in a transitive dependency can affect millions of applications within hours. Here's a comprehensive production setup.

**PRODUCTION PATTERN**:

```javascript
// security/dependency-scanner.js
const { exec } = require('child_process');
const fs = require('fs').promises;
const https = require('https');
const crypto = require('crypto');

class DependencySecurityMonitor {
  constructor(config) {
    this.config = {
      maxSeverity: config.maxSeverity || 'moderate',
      slackWebhook: config.slackWebhook,
      allowedLicenses: config.allowedLicenses || ['MIT', 'Apache-2.0', 'ISC', 'BSD-3-Clause'],
      lockfileHash: null
    };
  }

  async verifyLockfileIntegrity() {
    try {
      const lockfile = await fs.readFile('package-lock.json', 'utf8');
      const currentHash = crypto.createHash('sha256').update(lockfile).digest('hex');

      const storedHash = await fs.readFile('.lockfile-hash', 'utf8').catch(() => null);

      if (storedHash && storedHash.trim() !== currentHash) {
        await this.sendAlert('CRITICAL', 'Lockfile modified unexpectedly', {
          previousHash: storedHash.trim(),
          currentHash: currentHash
        });
        return false;
      }

      await fs.writeFile('.lockfile-hash', currentHash);
      return true;
    } catch (error) {
      console.error('Lockfile verification failed:', error.message);
      return false;
    }
  }

  async runNpmAudit() {
    return new Promise((resolve, reject) => {
      exec('npm audit --json', { maxBuffer: 10 * 1024 * 1024 }, (error, stdout, stderr) => {
        try {
          const result = JSON.parse(stdout);
          resolve(result);
        } catch (parseError) {
          reject(new Error(`Audit parse failed: ${parseError.message}`));
        }
      });
    });
  }

  async checkOSVDatabase(packageName, version) {
    return new Promise((resolve, reject) => {
      const postData = JSON.stringify({
        package: { name: packageName, ecosystem: 'npm' },
        version: version
      });

      const options = {
        hostname: 'api.osv.dev',
        path: '/v1/query',
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Content-Length': Buffer.byteLength(postData)
        },
        timeout: 10000
      };

      const req = https.request(options, (res) => {
        let data = '';
        res.on('data', chunk => data += chunk);
        res.on('end', () => {
          try {
            resolve(JSON.parse(data));
          } catch (e) {
            resolve({ vulns: [] });
          }
        });
      });

      req.on('error', reject);
      req.on('timeout', () => reject(new Error('OSV API timeout')));
      req.write(postData);
      req.end();
    });
  }

  async analyzeDependencies() {
    const lockfile = JSON.parse(await fs.readFile('package-lock.json', 'utf8'));
    const dependencies = lockfile.packages || {};
    const issues = [];

    for (const [path, pkg] of Object.entries(dependencies)) {
      if (!path || path === '') continue;

      const packageName = path.replace('node_modules/', '').split('/node_modules/').pop();

      // Check OSV database for vulnerabilities
      try {
        const osvResult = await this.checkOSVDatabase(packageName, pkg.version);
        if (osvResult.vulns && osvResult.vulns.length > 0) {
          issues.push({
            package: packageName,
            version: pkg.version,
            vulnerabilities: osvResult.vulns.map(v => ({
              id: v.id,
              severity: v.severity?.[0]?.score || 'unknown',
              summary: v.summary
            }))
          });
        }
      } catch (error) {
        console.warn(`OSV check failed for ${packageName}: ${error.message}`);
      }
    }

    return issues;
  }

  async sendAlert(severity, message, details) {
    if (!this.config.slackWebhook) return;

    const payload = JSON.stringify({
      text: `🚨 *Dependency Security Alert* [${severity}]`,
      attachments: [{
        color: severity === 'CRITICAL' ? '#ff0000' : '#ffaa00',
        fields: [
          { title: 'Message', value: message, short: false },
          { title: 'Details', value: JSON.stringify(details, null, 2), short: false },
          { title: 'Timestamp', value: new Date().toISOString(), short: true }
        ]
      }]
    });

    const url = new URL(this.config.slackWebhook);
    const options = {
      hostname: url.hostname,
      path: url.pathname,
      method: 'POST',
      headers: { 'Content-Type': 'application/json' }
    };

    return new Promise((resolve) => {
      const req = https.request(options, resolve);
      req.on('error', (e) => console.error('Alert failed:', e.message));
      req.write(payload);
      req.end();
    });
  }

  async fullSecurityScan() {
    console.log('[Security] Starting dependency security scan...');
    const results = { passed: true, issues: [] };

    // Layer 1: Lockfile integrity
    const lockfileValid = await this.verifyLockfileIntegrity();
    if (!lockfileValid) {
      results.passed = false;
      results.issues.push({ type: 'lockfile_tampered', severity: 'CRITICAL' });
    }

    // Layer 2: npm audit
    try {
      const auditResult = await this.runNpmAudit();
      if (auditResult.metadata?.vulnerabilities) {
        const vulns = auditResult.metadata.vulnerabilities;
        if (vulns.critical > 0 || vulns.high > 0) {
          results.passed = false;
          results.issues.push({ 
            type: 'npm_audit', 
            severity: vulns.critical > 0 ? 'CRITICAL' : 'HIGH',
            details: vulns
          });
        }
      }
    } catch (error) {
      console.warn('npm audit failed:', error.message);
    }

    // Layer 3: OSV database check
    const osvIssues = await this.analyzeDependencies();
    if (osvIssues.length > 0) {
      results.issues.push(...osvIssues.map(i => ({ type: 'osv_vuln', ...i })));
    }

    // Send alert if issues found
    if (!results.passed) {
      await this.sendAlert('CRITICAL', 'Dependency vulnerabilities detected', results.issues);
    }

    console.log(`[Security] Scan complete. Passed: ${results.passed}`);
    return results;
  }
}

module.exports = { DependencySecurityMonitor };
```

