    @Path("/register")
    @Consumes(MediaType.APPLICATION_JSON)
    @Produces(MediaType.APPLICATION_JSON)
    public Response registerUser(UserDTO user) {
        // NO VALIDATION - accepts any input directly
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String sql = "INSERT INTO users (username, email, password, age, role) VALUES (?, ?, ?, ?, ?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, user.getUsername());  // Could be empty or malicious
            stmt.setString(2, user.getEmail());     // No email format check
            stmt.setString(3, user.getPassword());  // No password strength check
            stmt.setInt(4, user.getAge());          // Could be negative or absurd
            stmt.setString(5, user.getRole());      // Attacker can set "ADMIN"
            stmt.executeUpdate();
            return Response.ok("{\"status\": \"registered\"}").build();
        } catch (SQLException e) {
            return Response.serverError().entity(e.getMessage()).build();
        }
