    @Pattern(regexp = "^[a-f0-9\\-]{36}$")
    private String userId;

    @NotNull
    @Size(min = 1, max = 100)
    @Valid
    private List<OrderItemDTO> items;

    @DecimalMin("0.01")
    @DecimalMax("100000.00")
    private BigDecimal clientTotal;

    // getters and setters
}

class OrderItemDTO {
    @NotNull
    @Pattern(regexp = "^PROD-[A-Z0-9]{8}$")
    private String productId;

    @NotNull
    @Min(1)
    @Max(9999)
    private Integer quantity;

    @Size(max = 10)
    @Valid
    private List<CustomOptionDTO> customOptions;

    // getters and setters
}

class CustomOptionDTO {
