**Attack Methods to Discover Hidden Endpoints**:
```bash
# 1. Directory/path fuzzing with common wordlists
ffuf -u http://target.com/FUZZ -w /usr/share/seclists/Discovery/Web-Content/api-endpoints.txt

# 2. JavaScript source code analysis
grep -r "api/" bundle.js | grep -E '"/[a-z0-9]+/'

# 3. Mobile app reverse engineering
apktool d app.apk && grep -r "http" ./app/

# 4. Traffic interception
mitmproxy -s analyze_endpoints.py

# 5. Timing attacks - hidden endpoints often have different response times
for path in $(cat paths.txt); do
  curl -s -o /dev/null -w "%{time_total}\n" "http://target.com/$path"
done
```

**Why This Is Dangerous**:
- Hidden URLs can be discovered through fuzzing, traffic analysis, or code inspection
- Mobile apps and JavaScript bundles often expose "hidden" paths in plain text
- No actual authentication means anyone who finds the path has full access
- Secrets in responses (passwords, API keys) compound the damage
- Attackers specifically look for these patterns in security assessments

**SECURE VERSION**:

```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"strings"
	"time"

	"github.com/golang-jwt/jwt/v5"
)

type contextKey string

const userContextKey contextKey = "user"

var jwtSecret = []byte(getEnvOrPanic("JWT_SECRET"))

type Claims struct {
	UserID   int    `json:"user_id"`
	Username string `json:"username"`
	Role     string `json:"role"`
	jwt.RegisteredClaims
}

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Role     string `json:"role"`
}

func main() {
	mux := http.NewServeMux()

	// Public endpoints
	mux.HandleFunc("/api/public/info", publicInfoHandler)
	mux.HandleFunc("/api/auth/login", loginHandler)

	// Protected admin endpoints - clear paths, strong authentication
	mux.Handle("/api/admin/users", requireAuth(requireRole("admin", listAllUsersHandler)))
	mux.Handle("/api/admin/users/delete", requireAuth(requireRole("admin", deleteUserHandler)))
	mux.Handle("/api/admin/config", requireAuth(requireRole("superadmin", getSystemConfigHandler)))

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", mux))
}

// Authentication middleware - validates JWT token
func requireAuth(next http.HandlerFunc) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		authHeader := r.Header.Get("Authorization")
		if authHeader == "" || !strings.HasPrefix(authHeader, "Bearer ") {
			http.Error(w, `{"error": "unauthorized"}`, http.StatusUnauthorized)
			return
		}

		tokenString := strings.TrimPrefix(authHeader, "Bearer ")
		claims := &Claims{}

		token, err := jwt.ParseWithClaims(tokenString, claims, func(token *jwt.Token) (interface{}, error) {
			return jwtSecret, nil
		})

		if err != nil || !token.Valid {
			log.Printf("Invalid token attempt from %s", r.RemoteAddr)
			http.Error(w, `{"error": "invalid token"}`, http.StatusUnauthorized)
			return
		}

		// Add user to context
		ctx := context.WithValue(r.Context(), userContextKey, claims)
		next.ServeHTTP(w, r.WithContext(ctx))
	})
}

// Authorization middleware - checks role
func requireRole(requiredRole string, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		claims, ok := r.Context().Value(userContextKey).(*Claims)
		if !ok {
			http.Error(w, `{"error": "unauthorized"}`, http.StatusUnauthorized)
			return
		}

		if !hasRole(claims.Role, requiredRole) {
			log.Printf("Access denied: user %s (role: %s) attempted to access %s requiring %s",
				claims.Username, claims.Role, r.URL.Path, requiredRole)
			http.Error(w, `{"error": "forbidden"}`, http.StatusForbidden)
			return
		}

		next.ServeHTTP(w, r)
	}
}

func hasRole(userRole, requiredRole string) bool {
	roleHierarchy := map[string]int{
		"user":       1,
		"admin":      2,
		"superadmin": 3,
	}
	return roleHierarchy[userRole] >= roleHierarchy[requiredRole]
}

func getEnvOrPanic(key string) string {
	// In production, load from secure config
	return "your-256-bit-secret-key-here"
}
```

**Key Security Controls**:
- **Proper Authentication**: JWT tokens validate user identity, not URL knowledge
- **Role-Based Access Control (RBAC)**: Users must have appropriate roles to access endpoints
- **Clear API Design**: Predictable paths are fine when properly protected
- **Audit Logging**: Failed access attempts are logged for security monitoring
- **Context-Based User Data**: User claims passed securely through request context

Absolutely problematic! Custom encoding (Base64, ROT13, XOR with static keys, custom alphabets) is **not encryption** and provides zero real security. Attackers routinely identify and reverse these schemes in minutes. This was a key factor in several major breaches where companies thought their data was "encrypted" but it was merely obfuscated.

