	Ciphertext   string `json:"ciphertext"`    // AES-256-GCM encrypted data
	Nonce        string `json:"nonce"`         // Unique per encryption
	EncryptedDEK string `json:"encrypted_dek"` // Data key encrypted by KMS
	KeyVersion   int    `json:"key_version"`   // For key rotation
}

