// NewEncryptionService creates a properly configured encryption service
func NewEncryptionService(ctx context.Context, masterKeyID string, db *sql.DB) (*EncryptionService, error) {
	cfg, err := config.LoadDefaultConfig(ctx)
	if err != nil {
		return nil, fmt.Errorf("failed to load AWS config: %w", err)
	}

	return &EncryptionService{
		kmsClient:   kms.NewFromConfig(cfg),
		masterKeyID: masterKeyID,
		auditLogger: &AuditLogger{db: db},
	}, nil
}

// Encrypt uses envelope encryption: AES-256-GCM with KMS-managed data keys
func (es *EncryptionService) Encrypt(ctx context.Context, plaintext []byte, userID int, fieldName string) (*EncryptedField, error) {
	// Generate a unique data encryption key (DEK) from KMS
	dataKey, err := es.kmsClient.GenerateDataKey(ctx, &kms.GenerateDataKeyInput{
		KeyId:   &es.masterKeyID,
		KeySpec: "AES_256",
	})
	if err != nil {
		return nil, fmt.Errorf("failed to generate data key: %w", err)
	}

	// Create AES-256-GCM cipher
	block, err := aes.NewCipher(dataKey.Plaintext)
	if err != nil {
		return nil, fmt.Errorf("failed to create cipher: %w", err)
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, fmt.Errorf("failed to create GCM: %w", err)
	}

	// Generate random nonce - CRITICAL: must be unique per encryption
	nonce := make([]byte, gcm.NonceSize())
	if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
		return nil, fmt.Errorf("failed to generate nonce: %w", err)
	}

	// Encrypt with authenticated encryption (GCM provides integrity)
	ciphertext := gcm.Seal(nil, nonce, plaintext, nil)

	// Securely wipe plaintext key from memory
	for i := range dataKey.Plaintext {
		dataKey.Plaintext[i] = 0
	}

	// Audit log the encryption operation
	es.auditLogger.LogEncryption(ctx, userID, fieldName, "ENCRYPT")

	return &EncryptedField{
		Ciphertext:   base64.StdEncoding.EncodeToString(ciphertext),
		Nonce:        base64.StdEncoding.EncodeToString(nonce),
		EncryptedDEK: base64.StdEncoding.EncodeToString(dataKey.CiphertextBlob),
		KeyVersion:   1,
	}, nil
}

// Decrypt decrypts an envelope-encrypted field
func (es *EncryptionService) Decrypt(ctx context.Context, ef *EncryptedField, userID int, fieldName string, accessReason string) ([]byte, error) {
	// Validate access reason is provided
	if accessReason == "" {
		return nil, errors.New("access reason required for decryption audit")
	}

	// Decode the encrypted data key
	encryptedDEK, err := base64.StdEncoding.DecodeString(ef.EncryptedDEK)
	if err != nil {
		return nil, fmt.Errorf("failed to decode encrypted DEK: %w", err)
	}

	// Decrypt the data key using KMS
	decryptedKey, err := es.kmsClient.Decrypt(ctx, &kms.DecryptInput{
		CiphertextBlob: encryptedDEK,
		KeyId:          &es.masterKeyID,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to decrypt data key: %w", err)
	}

	// Decode ciphertext and nonce
	ciphertext, err := base64.StdEncoding.DecodeString(ef.Ciphertext)
	if err != nil {
		return nil, fmt.Errorf("failed to decode ciphertext: %w", err)
	}

	nonce, err := base64.StdEncoding.DecodeString(ef.Nonce)
	if err != nil {
		return nil, fmt.Errorf("failed to decode nonce: %w", err)
	}

	// Create cipher and decrypt
	block, err := aes.NewCipher(decryptedKey.Plaintext)
	if err != nil {
		return nil, fmt.Errorf("failed to create cipher: %w", err)
	}

	gcm, err := cipher.NewGCM(block)
	if err != nil {
		return nil, fmt.Errorf("failed to create GCM: %w", err)
	}

	plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
	if err != nil {
		// GCM authentication failed - data may have been tampered with
		es.auditLogger.LogTamperingAttempt(ctx, userID, fieldName)
		return nil, fmt.Errorf("decryption failed: data integrity check failed")
	}

	// Securely wipe decryption key from memory
	for i := range decryptedKey.Plaintext {
		decryptedKey.Plaintext[i] = 0
	}

	// Audit log the decryption with access reason
	es.auditLogger.LogDecryption(ctx, userID, fieldName, accessReason)

	return plaintext, nil
}

